INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VMT_2024_consolidated', 'VMT', 2024, 'consolidated', 'Doanh nghiệp có giao dịch đáng kể với công ty mẹ Công ty Cổ phần Transimex, bao gồm khoản vay ngắn hạn 29 tỷ VND và lãi vay phải trả 5,595 tỷ VND (lũy kế). Giao dịch mua bán dịch vụ với Transimex đạt ~4 tỷ VND trong năm. Ngoài ra, Công ty còn giao dịch với nhiều công ty con/cùng Tập đoàn Transimex khác. Mặc dù các giao dịch được thực hiện theo thỏa thuận hợp đồng, tỷ trọng giao dịch với bên liên quan chiếm khoảng 10.5% doanh thu thuần và nợ vay từ Transimex chiếm 33% tổng nợ vay, cho thấy mức độ phụ thuộc đáng kể vào công ty mẹ.', 'Tổng nợ vay là 87.5 tỷ VND, trong đó nợ ngắn hạn 43.6 tỷ và nợ dài hạn 43.9 tỷ. Chi phí lãi vay năm 2024 là 6.68 tỷ VND, gần bằng lợi nhuận hoạt động kinh doanh (836 triệu VND), cho thấy áp lực trả nợ rất lớn. Công ty đã trả nợ gốc 14.63 tỷ VND trong năm. Tài sản đảm bảo là quyền sử dụng đất trị giá 8.678 tỷ VND tại các vị trí đắc địa ở Đà Nẵng. Công ty có 4.46 tỷ VND chi phí lãi vay chưa được trừ thuế chuyển sang các năm sau.', 'Công ty không có hàng tồn kho truyền thống (nguyên vật liệu, thành phẩm). Chỉ có chi phí xây dựng cơ bản dở dang 396.6 triệu VND liên quan đến tài sản đang xây dựng. Giá trị này không đáng kể so với tổng tài sản (160.4 tỷ VND) và không có dự phòng giảm giá. Rủi ro tồn kho thấp.', 6, 'Công ty Cổ phần Giao nhận Vận tải Miền Trung hoạt động trong lĩnh vực vận tải, kho vận và cho thuê văn phòng tại Đà Nẵng. Doanh thu thuần năm 2024 đạt 41.6 tỷ VND, giảm 30% so với năm trước (59.1 tỷ). Biên lợi nhuận gộp cải thiện nhẹ lên 22.7% (năm trước 20.7%). Tuy nhiên, chi phí lãi vay 6.68 tỷ VND chiếm tỷ trọng lớn, khiến lợi nhuận sau thuế chỉ đạt 306 triệu VND. Dòng tiền hoạt động kinh doanh dương 14.9 tỷ VND cho thấy khả năng tạo tiền tốt. Công ty có tài sản cố định lớn (126.5 tỷ VND) và bất động sản đầu tư. Các rủi ro chính bao gồm: (1) Phụ thuộc lớn vào công ty mẹ Transimex về vốn vay và giao dịch; (2) Chi phí lãi vay áp đảo lợi nhuận; (3) Biến động nhân sự cấp cao liên tục trong năm 2024. Công ty đang trong quá trình tăng vốn 29.9 tỷ VND vào năm 2025, nếu thành công sẽ cải thiện đáng kể cơ cấu vốn.'),
('VMT_2022_consolidated', 'VMT', 2022, 'consolidated', 'Doanh nghiệp có giao dịch đáng kể với công ty mẹ (Công ty Cổ phần Transimex) và các công ty trong cùng tập đoàn. Các giao dịch bao gồm cho vay tín chấp, mua bán dịch vụ và tài sản. Điều này tạo ra rủi ro về tính độc lập và có thể có xung đột lợi ích, đặc biệt là khoản vay ngắn hạn tín chấp lớn.', 'Tổng nợ vay chiếm tỷ trọng lớn trong cơ cấu vốn. Nợ ngắn hạn 29 tỷ VND từ công ty mẹ và nợ dài hạn ~80,5 tỷ VND từ ngân hàng Shinhan Bank để đầu tư xây dựng tài sản cố định. Áp lực trả nợ lãi vay trong năm là đáng kể (chi phí lãi vay hơn 5,5 tỷ VND). Tuy nhiên, nợ dài hạn có thời hạn đến 2028 và được đảm bảo bằng tài sản đất đai, giảm bớt áp lực thanh khoản ngắn hạn.', 'Báo cáo không trình bày chi tiết về hàng tồn kho (nguyên liệu, thành phẩm) hay các dự án bất động sản cụ thể. Rủi ro tồn kho dở dang không được đánh giá do thiếu thông tin. Các tài sản dở dang (chi phí xây dựng cơ bản dở dang) đã được chuyển giao vào tài sản cố định hữu hình trong năm.', 4, 'Sức khỏe tài chính của doanh nghiệp đang trong giai đoạn tái cơ cấu và đầu tư mạnh. Lợi nhuận sau thuế giảm mạnh 85% do bắt đầu khấu hao và gánh chịu chi phí lãi vay từ dự án Trung tâm Logistics mới. Công ty phụ thuộc vào nguồn vốn vay, đặc biệt từ công ty mẹ. Triển vọng đầu tư trung và dài hạn phụ thuộc vào hiệu quả hoạt động của Trung tâm Logistics Vinatrans Danang khi đi vào vận hành hoàn toàn.'),
('VMK_2025_consolidated', 'VMK', 2025, 'consolidated', 'Công ty có một số giao dịch với các bên liên quan (chủ yếu là mua bán hàng hóa, trả trước) với giá trị lớn, chiếm tỷ trọng đáng kể trong công nợ phải thu và phải trả. Tuy nhiên, chưa phát hiện giao dịch bất thường như cho vay không lãi suất hay chênh lệch giá lớn.', 'Áp lực nợ vay ở mức trung bình. Tổng nợ vay (ngắn và dài hạn) xấp xỉ 19.900 tỷ VNĐ. Công ty sử dụng tài sản cố định và bất động sản đầu tư làm tài sản đảm bảo cho các khoản vay. Lợi nhuận trước thuế (5.000 tỷ) cao hơn chi phí lãi vay (1.187 tỷ), cho thấy khả năng thanh toán lãi vay vẫn đảm bảo.', 'Hàng tồn kho chủ yếu là thành phẩm, không có dự phòng giảm giá. Dự án xây dựng dở dang (Biệt thự, dự án dược liệu) có giá trị lớn (~28.600 tỷ) nhưng đang trong quá trình triển khai, chưa ghi nhận lỗ. Rủi ro nằm ở tiến độ và khả năng thu hồi vốn của các dự án này.', 5, 'Công ty có sức khỏe tài chính tương đối ổn định với biên lợi nhuận gộp dương (~13.3%). Tuy nhiên, lợi nhuận sau thuế năm 2025 giảm 24.6% so với năm 2024 do giá vốn hàng bán tăng. Công ty vừa tăng vốn mạnh (gấp đôi) để đầu tư vào dự án bất động sản và dược liệu. Triển vọng phụ thuộc vào khả năng triển khai và thu hồi lợi nhuận từ các dự án đầu tư lớn này.'),
('VMT_2021_consolidated', 'VMT', 2021, 'consolidated', 'Doanh nghiệp có nhiều giao dịch với bên liên quan, đặc biệt vay vốn từ công ty mẹ với lãi suất 7%/năm. Các giao dịch mua bán dịch vụ có thể không phản ánh giá thị trường, tiềm ẩn rủi ro về xung đột lợi ích.', 'Áp lực nợ vay tăng cao với tổng nợ 50.89 tỷ VND, chủ yếu để tài trợ dự án. Nợ dài hạn được đảm bảo bằng quyền sử dụng đất, nhưng khả năng thanh toán phụ thuộc vào dòng tiền từ hoạt động kinh doanh.', 'Dự án xây dựng Trung tâm logistics Vinatrans Đà Nẵng đang dở dang với chi phí 85.19 tỷ VND. Rủi ro về tiến độ và chi phí phát sinh có thể ảnh hưởng đến tài sản.', 5, 'Tăng trưởng doanh thu và lợi nhuận mạnh trong năm 2021, nhưng nợ vay tăng đáng kể để đầu tư dự án. Sức khỏe tài chính ổn định nhưng cần theo dõi áp lực nợ và tiến độ dự án.'),
('VMK_2023_consolidated', 'VMK', 2023, 'consolidated', 'Không phát hiện giao dịch bất thường với bên liên quan. Các giao dịch chủ yếu là lương thưởng cho Ban Tổng Giám đốc, không có giao dịch mua bán, vay mượn đáng ngờ với các bên liên quan.', 'Tổng nợ vay (ngắn và dài hạn) là 33.657 tỷ VND, chiếm tỷ trọng cao trong cơ cấu vốn. Áp lực trả nợ tập trung vào các khoản vay dài hạn từ ngân hàng và cá nhân. Công ty có tài sản đảm bảo là hệ thống điện mặt trời và bất động sản đầu tư.', 'Công ty không có hàng tồn kho thông thường (nguyên vật liệu, thành phẩm). Khoản mục lớn là chi phí xây dựng dở dang cho dự án Biệt thự A4-06A, rủi ro phụ thuộc vào tiến độ hoàn thiện và chuyển nhượng của dự án.', 3, 'Công ty có kết quả kinh doanh tăng trưởng tốt, dòng tiền từ hoạt động kinh doanh dương mạnh. Tuy nhiên, cơ cấu vốn vay nợ cao tạo áp lực tài chính. Dự án bất động sản đầu tư là tài sản có giá trị nhưng tính thanh khoản không cao. Công ty được hưởng ưu đãi thuế TNDN. Triển vọng phụ thuộc vào việc hoàn thiện dự án và quản lý nợ.'),
('VMK_2022_consolidated', 'VMK', 2022, 'consolidated', 'Công ty không phát sinh giao dịch với các bên liên quan trong năm, rủi ro liên quan thấp.', 'Công ty có mức nợ vay cao với lãi suất thả nổi, nhưng có tài sản đảm bảo và dòng tiền từ hoạt động kinh doanh khả quan.', 'Hàng tồn kho thấp, dự án xây dựng dở dang có thể có rủi ro chậm tiến độ hoặc giá trị giảm.', 4, 'Công ty có lợi nhuận tăng trưởng, biên lợi nhuận gộp khoảng 20.5%, nhưng lưu chuyển tiền thuần âm do đầu tư lớn vào tài sản cố định và dự án. Công ty được ưu đãi thuế và có khả năng thanh toán nợ, nhưng cần quản lý rủi ro lãi suất và tiến độ dự án.'),
('VNA_2023_consolidated', 'VNA', 2023, 'consolidated', 'Công ty có nhiều giao dịch với các bên liên quan trong cùng tập đoàn Hàng hải Việt Nam, bao gồm doanh thu cung cấp dịch vụ (2,15 tỷ VNĐ) và mua hàng hóa dịch vụ (1,78 tỷ VNĐ). Khoản phải trả cho công ty mẹ (Tổng Công ty Hàng hải Việt Nam) lên đến 6,6 tỷ VNĐ. Các giao dịch này chủ yếu là nghiệp vụ kinh doanh thông thường trong ngành hàng hải, chưa phát hiện giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn bất thường. Tuy nhiên, cần theo dõi khoản nợ với công ty mẹ.', 'Tại ngày 31/12/2023, công ty đã trả hết nợ gốc vay ngân hàng (cả ngắn hạn và dài hạn). Tuy nhiên, vẫn còn khoản phải trả lãi vay 18,4 tỷ VNĐ đối với Ngân hàng Phát triển Việt Nam - Chi nhánh Đông Bắc, trong đó bao gồm nợ lãi chậm trả 4,5 tỷ VNĐ. Công ty đang thuộc diện được xóa nợ lãi chậm trả theo Nghị định 78/2023/NĐ-CP nhưng chưa ghi nhận thu nhập do chưa có thông báo chính thức. Lãi suất vay cũ là 7,8%/năm cố định. Tài sản thế chấp là tàu Vinaship Gold.', 'Hàng tồn kho giảm từ 58,2 tỷ xuống 32,1 tỷ VNĐ, chủ yếu là nguyên liệu vật liệu phục vụ vận tải biển, không có dự phòng giảm giá. Dự án xây dựng dở dang tăng mạnh từ 3,4 tỷ lên 49,7 tỷ VNĐ do dự án trụ sở văn phòng mới tại lô đất TM8 (tổng mức đầu tư dự kiến 96 tỷ đồng) đang trong giai đoạn xây dựng tích cực. Dự án dự kiến hoàn thành năm 2024, cần theo dõi tiến độ và khả năng hoàn thành đúng kế hoạch.', 5, 'Công ty Vận tải biển Vinaship đang trong giai đoạn khó khăn khi doanh thu giảm mạnh 43,5% (từ 1.051 tỷ xuống 593,8 tỷ VNĐ) và tỷ suất lợi nhuận gộp giảm sâu từ 26,6% xuống chỉ còn 2,11%. Công ty đã trả hết nợ gốc ngân hàng và phát sinh thu nhập lớn từ xử lý tái cơ cấu nợ (58,6 tỷ VNĐ). Dòng tiền hoạt động kinh doanh dương 5,35 tỷ VNĐ. Công ty đang đầu tư mạnh vào dự án bất động sản (trụ sở văn phòng mới). Điểm tích cực là đã trả hết nợ gốc ngân hàng, có dòng tiền kinh doanh dương. Điểm rủi ro bao gồm: tỷ suất lợi nhuận gộp thấp, giao dịch với bên liên quan trong tập đoàn, nợ lãi vay cũ chưa xử lý triệt để.'),
('VOS_2025_consolidated', 'VOS', 2025, 'consolidated', 'Công ty có giao dịch đáng kể với các bên liên quan, đặc biệt là công ty mẹ VIMC và các công ty con/liên kết, với tổng doanh thu và mua hàng hóa dịch vụ khoảng 318 tỷ VNĐ. Các giao dịch này có thể tạo ra xung đột lợi ích, mặc dù giá trị dường như dựa trên thị trường. Rủi ro ở mức trung bình.', 'Công ty tăng mạnh nợ vay, chủ yếu là dài hạn để mua tàu, với tổng nợ khoảng 7.59 nghìn tỷ VNĐ. Tài sản thế chấp là các tàu biển. Áp lực trả nợ cao do thời hạn vay dài và lãi suất thả nổi, nhưng dòng tiền từ hoạt động kinh doanh ổn định. Rủi ro nợ ở mức trung bình.', 'Hàng tồn kho chủ yếu là nguyên liệu, vật liệu với giá trị tương đối thấp và không có dự phòng giảm giá. Không có dự án xây dựng dở dang. Rủi ro tồn kho thấp.', 5, 'Công ty Cổ phần Vận tải biển Việt Nam (VOSCO) ghi nhận doanh thu giảm trong năm 2025 nhưng lợi nhuận tăng nhờ thanh lý tài sản cố định. Công ty đang mở rộng đội tàu thông qua vay nợ dài hạn, làm tăng đòn bẩy tài chính. Dù vậy, công ty có vốn chủ sở hữu mạnh và quản trị công ty tương đối tốt với cổ đông lớn là VIMC. Triển vọng phụ thuộc vào ngành vận tải biển và khả năng quản lý nợ.'),
('VOS_2024_consolidated', 'VOS', 2024, 'consolidated', 'Doanh nghiệp có mạng lưới giao dịch phức tạp với các bên liên quan trong hệ sinh thái Tổng Công ty Hàng hải Việt Nam (VIMC). Tổng mua hàng hóa, dịch vụ từ bên liên quan đạt 278.285 tỷ đồng, chiếm tỷ trọng lớn trong chi phí. Các khoản phải trả cổ tức 67.2 tỷ cho Công ty mẹ và khoản nợ phải thu 86 tỷ từ Công ty TNHH MTV Vận tải viễn dương Vinashin (công ty cùng Công ty mẹ) đang trong quá trình phá sản cho thấy rủi ro tín dụng đáng kể. Công ty đang thực hiện cấn trừ công nợ phức tạp giữa các khoản phải thu sửa chữa tàu Vinashin Atlantic với khoản phải trả cổ tức cho Công ty mẹ.', 'Tổng nợ phải trả chiếm 31.2% tổng tài sản (902.267 tỷ/2.891.192 tỷ), mức độ đòn bẩy trung bình. Công ty không có nợ vay ngân hàng cuối kỳ (đã trả 70 tỷ trong năm), chi phí lãi vay giảm mạnh từ 25.9 tỷ xuống 64.8 triệu đồng. Tuy nhiên, khoản nợ lớn nhất là tạm tăng nguyên giá tàu 487.1 tỷ và nợ Ngân hàng Phát triển Việt Nam 126.6 tỷ tiền lãi vay tàu Vosco Sunrise. Tài sản thế chấp là TSCĐ hữu hình trị giá 254.2 tỷ. Tiền mặt và đầu tư ngắn hạn đạt 1.219 tỷ, đảm bảo khả năng thanh toán tốt cho nợ ngắn hạn 409.5 tỷ.', 'Hàng tồn kho giảm từ 123.2 tỷ xuống 105.2 tỷ, chủ yếu do giảm nguyên liệu vật liệu, không có dự phòng giảm giá. Các dự án đóng tàu mới (Lucky Star, Blue Star, Vosco Sunrise) có tổng khoản trả trước 276.7 tỷ và tạm tăng nguyên giá 487.2 tỷ vẫn đang trong quá trình quyết toán, cho thấy tiến độ đóng tàu có thể chậm hơn dự kiến.', 6, 'VOSCO có sức khỏe tài chính ổn định với thanh khoản tốt (tiền mặt + đầu tư ngắn hạn 1.219 tỷ), tăng trưởng lợi nhuận sau thuế 115.8% (từ 155.3 tỷ lên 335.2 tỷ). Doanh thu tăng 74.8% nhờ hoạt động vận tải và thương mại. Tuy nhiên, doanh nghiệp đối mặt với: (1) khoản phải thu 86 tỷ từ Vinashin đang phá sản có nguy cơ mất trắng; (2) các dự án đóng tàu mới với tổng vốn cam kết lớn nhưng tiến độ quyết toán chậm; (3) chiến lược bán tài sản (thu 393.4 tỷ từ thanh lý tàu) làm giảm đội tàu, có thể ảnh hưởng năng lực vận tải dài hạn; (4) biên lợi nhuận gộp mỏng 2.28% đặc thù ngành vận tải biển.'),
('VOS_2023_consolidated', 'VOS', 2023, 'consolidated', 'Doanh nghiệp có nhiều giao dịch lớn với các bên liên quan, đặc biệt là công ty mẹ (Tổng Công ty Hàng hải Việt Nam) và các công ty cùng công ty mẹ. Khoản phải trả cổ tức cho công ty mẹ lên đến 67,2 tỷ đồng và khoản phải thu từ Công ty TNHH MTV Vận tải viễn dương Vinashin (đang trong quá trình phá sản) là 74 tỷ đồng, tiềm ẩn rủi ro về khả năng thu hồi nợ.', 'Doanh nghiệp không có nợ vay ngân hàng (vay và nợ thuê tài chính ngắn hạn và dài hạn đều bằng 0). Tuy nhiên, nợ phải trả khác ngắn hạn là 124,9 tỷ đồng và nợ phải trả khác dài hạn là 518,7 tỷ đồng (chủ yếu là khoản tạm tăng nguyên giá tàu 516,7 tỷ đồng). Áp lực nợ vay không cao nhưng nợ phải trả lớn, cần theo dõi.', 'Hàng tồn kho giảm so với đầu năm, chủ yếu là nguyên liệu, vật liệu và công cụ, dụng cụ, không có dự phòng giảm giá. Rủi ro tồn kho thấp.', 5, 'Năm 2023, doanh thu thuần của VOS tăng 31,7% so với năm trước, nhưng lợi nhuận sau thuế giảm 68,2% do giá cước vận tải giảm mạnh và chi phí giá vốn tăng. Công ty đã thực hiện tái cơ cấu tài sản (bán tàu Neptune Star) và xóa nợ lãi trên lãi chậm trả với Ngân hàng Phát triển Việt Nam, mang lại thu nhập khác lớn. Cơ cấu tài sản lành mạnh, không có nợ vay ngân hàng, nhưng nợ phải trả khác chiếm tỷ trọng cao. Giao dịch với bên liên quan đáng chú ý, đặc biệt là khoản phải thu từ công ty đang phá sản và khoản phải trả cổ tức cho công ty mẹ. Tổng quan, doanh nghiệp đang trong giai đoạn tái cơ cấu và đối mặt với thách thức từ thị trường vận tải biển suy giảm.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VOS_2022_consolidated', 'VOS', 2022, 'consolidated', 'Công ty có mạng lưới giao dịch phức tạp với nhiều bên liên quan trong hệ sinh thái VIMC/Tổng Công ty Hàng Hải Việt Nam (công ty mẹ sở hữu 51%). Các giao dịch đáng chú ý bao gồm: (1) Phải trả cổ tức 67,2 tỷ VNĐ cho Tổng Công ty Hàng Hải Việt Nam đang chờ bù trừ với khoản phải thu sửa chữa tàu Vinashins Atlantic; (2) Khoản phải thu lớn 74 tỷ VNĐ từ Công ty TNHH MTV Vận tải viễn dương Vinashin (cùng công ty mẹ) về tiền sửa chữa tàu Vinashins Atlantic; (3) Tạm tăng nguyên giá tàu 516,7 tỷ VNĐ chưa quyết toán với các công ty đóng tàu; (4) Mua hàng hóa/dịch vụ lớn từ Công ty Vận tải Biển VIMC (110,8 tỷ) và Công ty Cổ phần Cảng Sài Gòn (15,5 tỷ). Các khoản phải thu lớn với bên liên quan có nguy cơ khó thu hồi và cần theo dõi.', 'Áp lực nợ vay đã giảm đáng kể trong năm 2022. Công ty không còn dư nợ vay ngân hàng ngắn hạn và dài hạn trên Bảng cân đối kế toán (so với 145,2 tỷ nợ ngắn hạn và 491,8 tỷ nợ dài hạn đầu năm). Công ty đã trả nợ gốc vay 638,2 tỷ VNĐ trong năm và hoàn tất nghĩa vụ thanh toán nợ với DATC/VCB. Tuy nhiên, nợ phải trả khác ngắn hạn vẫn ở mức 129 tỷ VNĐ và nợ dài hạn phải trả khác 518,8 tỷ VNĐ (chủ yếu là nguyên giá tàu chưa quyết toán). Chi phí lãi vay trong năm là 59,6 tỷ VNĐ (giảm so với 101,6 tỷ năm trước). Dòng tiền từ hoạt động kinh doanh mạnh (562,6 tỷ) giúp Công ty có khả năng thanh toán tốt.', 'Hàng tồn kho tăng 57,7% so với đầu năm (từ 90,1 tỷ lên 142,1 tỷ VNĐ), chủ yếu do tăng nguyên liệu nhiên liệu phục vụ hoạt động vận tải biển. Không có dự phòng giảm giá hàng tồn kho. Rủi ro tồn kho ở mức thấp do nhiên liệu là hàng hóa có tính thanh khoản cao. Tuy nhiên, các khoản trả trước cho đóng tàu (Lucky Star, Blue Star, Vosco Sunrise) với tổng giá trị 278 tỷ VNĐ đang trong quá trình quyết toán, cần được theo dõi tiến độ bàn giao và quyết toán giá trị tàu.', 5, 'Công ty Cổ phần Vận tải Biển Việt Nam (VOSCO) đạt kết quả kinh doanh tích cực năm 2022 với lợi nhuận trước thuế 605,6 tỷ VNĐ (tăng 67,6 tỷ so với năm 2021), doanh thu tăng 70% nhờ đội tàu hoạt động ổn định và tận dụng tốt cơ hội thị trường. Công ty đã cơ cấu nợ thành công khi trả hết nợ vay ngân hàng và hoàn tất nghĩa vụ với DATC/VCB, ghi nhận thu nhập từ cơ cấu nợ 89,5 tỷ VNĐ. Dòng tiền từ hoạt động kinh doanh đạt 562,6 tỷ VNĐ. Tuy nhiên, vẫn còn một số rủi ro: (1) Nhiều giao dịch lớn với bên liên quan trong hệ sinh thái VIMC; (2) Khoản phải thu 74 tỷ VNĐ từ Vinashin và 25,9 tỷ VNĐ từ tàu Đông Thanh (đang tranh chấp); (3) Nguyên giá tàu chưa quyết toán 516,7 tỷ VNĐ; (4) Chi phí quản lý nợ DATC 15,7 tỷ VNĐ. Công ty có vị thế tài chính cải thiện đáng kể với tỷ lệ nợ giảm mạnh, nhưng cần tiếp tục theo dõi tiến độ quyết toán các khoản đầu tư tàu và khả năng thu hồi các khoản phải thu lớn với bên liên quan.'),
('VOS_2021_consolidated', 'VOS', 2021, 'consolidated', 'Doanh nghiệp có phát sinh giao dịch đáng kể với các bên liên quan, đặc biệt là công ty mẹ (Tổng Công ty Hàng Hải Việt Nam) và các công ty con, công ty liên kết trong cùng tập đoàn. Các giao dịch này bao gồm doanh thu bán hàng, mua hàng, cho vay và phải trả cổ tức. Giá trị giao dịch lớn, tập trung ở một số đối tượng, tạo rủi ro về tính độc lập và công bằng trong giao dịch. Tuy nhiên, không có bằng chứng rõ ràng về giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch giá lớn.', 'Doanh nghiệp có gánh nặng nợ vay lớn với tổng nợ vay khoảng 637 tỷ VNĐ. Công ty đang trong quá trình tái cơ cấu nợ, đặc biệt với Ngân hàng TMCP Ngoại thương Việt Nam. Một phần nợ đã quá hạn thanh toán. Tài sản thế chấp chủ yếu là tài sản hình thành từ vốn vay (tàu biển). Áp lực trả nợ ngắn hạn là đáng kể, cần theo dõi chặt chẽ khả năng thanh toán.', 'Hàng tồn kho chủ yếu là nguyên liệu, vật liệu và chi phí sửa chữa tàu trả trước, không có dự án bất động sản dở dang. Giá trị tồn kho tăng so với đầu năm nhưng không có trích lập dự phòng, cho thấy hàng hóa vẫn có khả năng tiêu thụ. Rủi ro tồn kho ở mức trung bình thấp.', 6, 'Công ty VOSCO đã có sự phục hồi mạnh mẽ trong năm 2021, chuyển từ lỗ nặng năm 2020 sang lợi nhuận trước thuế 505 tỷ VNĐ nhờ hoạt động vận tải biển hiệu quả, cơ cấu nợ thành công và thanh lý tài sản. Tuy nhiên, công ty vẫn đối mặt với rủi ro tài chính từ nợ vay lớn và đang tái cơ cấu. Quản trị doanh nghiệp có những điểm cần lưu ý do giao dịch lớn với các bên liên quan trong tập đoàn. Triển vọng phụ thuộc vào sự ổn định của ngành vận tải biển và tiến trình xử lý nợ.'),
('VOS_2019_consolidated', 'VOS', 2019, 'consolidated', 'Giao dịch với công ty liên kết dựa trên điều kiện thương mại bình thường, không có dấu hiệu bất thường về giá hay điều kiện thanh toán. Giá trị giao dịch không đáng kể so với tổng quy mô hoạt động.', 'Áp lực nợ vay cao với nợ ngắn hạn vượt tài sản ngắn hạn, gây rủi ro thanh khoản. Công ty có tài sản thế chấp (tàu biển) nhưng khả năng thanh toán phụ thuộc vào dòng tiền từ hoạt động kinh doanh và cơ cấu nợ.', 'Tồn kho chủ yếu là nguyên vật liệu và công cụ, không có hàng tồn kho dở dang hay dự án bất động sản. Rủi ro tồn kho thấp nhưng cần theo dõi biến động giá nguyên liệu.', 3, 'Công ty hoạt động trong ngành vận tải biển với doanh thu ổn định nhưng lợi nhuận gộp âm trong năm 2019. Nợ vay lớn và áp lực thanh khoản là mối lo ngại chính, dù có tài sản thế chấp. Triển vọng đầu tư thận trọng do rủi ro thanh khoản và lợi nhuận mỏng.'),
('VOS_2018_consolidated', 'VOS', 2018, 'consolidated', 'Giao dịch với bên liên quan chủ yếu là mua bán hàng hóa dịch vụ và nhận/chia cổ tức với công ty liên kết (Công ty Cổ phần Thương mại và Dịch vụ Vosco) và công ty mẹ (Tổng Công ty Hàng hải Việt Nam). Không phát hiện giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn. Tuy nhiên, khoản phải trả cổ tức cho công ty mẹ 67,2 tỷ VND là khoản nợ cũ từ cổ phần hóa, cần theo dõi.', 'Tổng nợ vay rất lớn (gần 1.941 tỷ VND), trong đó nợ ngắn hạn 700,4 tỷ VND, nợ dài hạn 1.240,9 tỷ VND. Tài sản thế chấp chủ yếu là tàu biển. Công ty đối mặt rủi ro tỷ giá USD và lãi suất thả nổi. Nợ ngắn hạn vượt tài sản ngắn hạn 171,9 tỷ VND cho thấy áp lực thanh khoản ngắn hạn.', 'Hàng tồn kho tăng mạnh từ 85,9 tỷ lên 135,9 tỷ VND, chủ yếu là nguyên liệu vật liệu. Không có dự án xây dựng dở dang hay bất động sản đầu tư. Rủi ro tồn kho không quá cao nhưng cần kiểm soát lượng tồn kho tăng.', 4, 'Công ty có doanh thu tăng nhẹ, lợi nhuận gộp chuyển sang dương (52,4 tỷ VND) sau năm trước lỗ gộp. Tuy nhiên, lợi nhuận thuần từ hoạt động kinh doanh vẫn âm, nhưng nhờ thu nhập khác lớn (209,4 tỷ VND) từ thanh lý tài sản và cơ cấu nợ, Công ty đạt lợi nhuận trước thuế 51,3 tỷ VND. Nợ vay cao, rủi ro tỷ giá và lãi suất là thách thức lớn. Triển vọng phụ thuộc vào ngành vận tải biển và khả năng quản lý dòng tiền.'),
('VOS_2017_consolidated', 'VOS', 2017, 'consolidated', 'Công ty có giao dịch với các công ty liên kết (mua bán hàng hóa, dịch vụ, nhận cổ tức) và có khoản phải trả, phải thu lớn với công ty mẹ và bên liên quan đang chờ bù trừ. Không phát hiện giao dịch bất thường lớn như cho vay không lãi suất, nhưng việc chờ bù trừ công nợ lớn (khoảng 151,6 tỷ VND) có thể ảnh hưởng đến dòng tiền và cần được giám sát.', 'Áp lực nợ vay cao với tổng nợ vay hơn 2.297 tỷ VND, trong đó nợ ngắn hạn đáo hạn trong năm 607 tỷ VND. Nhiều khoản vay lãi suất thả nổi (USD và VND) gây rủi ro lãi suất và tỷ giá. Công ty thế chấp hầu hết tàu biển cho các khoản vay, khả năng thanh toán phụ thuộc vào dòng tiền từ hoạt động kinh doanh. Nợ ngắn hạn lớn hơn tài sản ngắn hạn, cho thấy áp lực thanh khoản.', 'Hàng tồn kho chủ yếu là nguyên liệu vật liệu và công cụ dụng cụ, không có dự phòng giảm giá. Không có dự án xây dựng dở dang hay bất động sản đầu tư. Rủi ro tồn kho thấp, tuy nhiên tồn kho giảm nhẹ so với đầu năm.', 5, 'Công ty vận tải biển Việt Nam (VOSCO) năm 2017 có lợi nhuận sau thuế 10,7 tỷ VND, chấm dứt chuỗi lỗ lớn, chủ yếu nhờ khoản thu nhập khác 274 tỷ VND từ xóa nợ lãi vay của Ngân hàng Phát triển Việt Nam. Tuy nhiên, hoạt động kinh doanh cốt lõi vẫn lỗ gộp 122 tỷ VND do chi phí vận hành cao. Nợ vay lớn, áp lực trả nợ và rủi ro tỷ giá, lãi suất là mối lo ngại chính. Công ty có lỗ lũy kế 791 tỷ VND. Triển vọng phụ thuộc vào khả năng cải thiện biên lợi nhuận gộp, quản lý nợ và tình hình thị trường vận tải biển. Điểm rủi ro quản trị trung bình do có giao dịch với bên liên quan và cơ cấu nợ phức tạp.'),
('VOS_2016_consolidated', 'VOS', 2016, 'consolidated', 'Giao dịch với bên liên quan chủ yếu là mua bán hàng hóa dịch vụ với công ty liên kết, giá trị không đáng kể so với tổng doanh thu, rủi ro thấp.', 'Nợ vay lớn, tổng nợ phải trả cao, áp lực thanh toán nợ lớn, đặc biệt với các khoản vay dài hạn, tài sản thế chấp chủ yếu là tàu biển.', 'Hàng tồn kho giảm mạnh so với năm trước, chủ yếu là nguyên liệu, không có dự án xây dựng dở dang, rủi ro tồn kho thấp.', 7, 'Công ty đang gặp khó khăn tài chính với lỗ lũy kế lớn và nợ vay cao. Dòng tiền từ hoạt động kinh doanh dương nhưng不足以覆盖 nợ, triển vọng đầu tư phụ thuộc vào khả năng tái cơ cấu nợ và cải thiện hoạt động kinh doanh.'),
('VOS_2025_parent', 'VOS', 2025, 'parent', 'Công ty có nhiều giao dịch với các bên liên quan, bao gồm công ty mẹ Tổng Công ty Hàng hải Việt Nam (VIMC) và các công ty con, công ty liên kết, công ty cùng công ty mẹ. Tổng doanh thu từ các bên liên quan năm 2025 là 31.8 tỷ VND và mua hàng hóa, dịch vụ là 231.4 tỷ VND. Các giao dịch này có vẻ không bất thường nhưng cần được giám sát để đảm bảo tính công bằng và minh bạch.', 'Nợ vay tăng mạnh từ 0 lên 758.9 tỷ VND tính đến 31/12/2025, chủ yếu để tài trợ mua tàu mới. Các khoản vay có tài sản thế chấp là tàu biển và tiền gửi, giảm rủi ro tín dụng. Tuy nhiên, chi phí lãi vay tăng đáng kể (31.7 tỷ VND trong năm 2025), tạo áp lực lên dòng tiền.', 'Hàng tồn kho giảm từ 105.2 tỷ VND xuống 97.2 tỷ VND, chủ yếu là nguyên liệu, vật liệu và công cụ dụng cụ. Không có dự phòng giảm giá, cho thấy rủi ro tồn kho thấp. Tuy nhiên, cần theo dõi nhu cầu vận tải biển để tránh tồn kho quá mức.', 5, 'Công ty Cổ phần Vận tải biển Việt Nam (VOS) ghi nhận doanh thu thuần giảm 44% so với năm trước, nhưng lợi nhuận gộp tăng 59%. Công ty đang đầu tư mạnh vào mua tàu mới thông qua vay nợ dài hạn, làm tăng tổng tài sản và nợ phải trả. Dòng tiền từ hoạt động kinh doanh âm (-127.8 tỷ VND) do tăng phải thu và trả nợ, nhưng dòng tiền từ hoạt động tài chính dương (606.3 tỷ VND). Công ty có liên kết chặt chẽ với Tập đoàn VIMC, điều này mang lại lợi ích nhưng cũng tiềm ẩn rủi ro quản trị. Tổng thể, công ty đang trong giai đoạn mở rộng, cần quản lý hiệu quả nợ và dòng tiền để duy trì ổn định tài chính.'),
('VOS_2023_parent', 'VOS', 2023, 'parent', 'Công ty có nhiều giao dịch với các bên liên quan, đặc biệt với công ty mẹ và các công ty liên kết, nhưng giá trị không lớn và không có dấu hiệu bất thường rõ ràng.', 'Công ty không có nợ vay tài chính, áp lực nợ thấp.', 'Hàng tồn kho chủ yếu là nguyên liệu, vật liệu và hàng hóa, không có dự án xây dựng dở dang, rủi ro tồn kho thấp.', 3, 'Tổng quan, công ty có tình hình tài chính ổn định, không có nợ vay, dòng tiền hoạt động kinh doanh dương, nhưng biên lợi nhuận gộp thấp do chi phí giá vốn cao.'),
('VOS_2021_parent', 'VOS', 2021, 'parent', 'Doanh nghiệp có giao dịch bên liên quan đáng chú ý: (1) Trả trước cho các công ty đóng tàu liên quan đến nhà nước (Bạch Đằng, Nam Triệu) lên tới hơn 276 tỷ VND cho việc đóng tàu Lucky Star, Blue Star, Vosco Sunrise nhưng chưa quyết toán xong, tiềm ẩn rủi ro chậm trễ bàn giao và quyết toán giá trị tàu. (2) Phải thu Công ty TNHH MTV Vận tải Viễn dương Vinashin khoảng 88,6 tỷ VND (bao gồm nợ sửa chữa tàu Vinashins Atlantic), trong đó đã trích lập dự phòng toàn bộ 2,5 tỷ VND nợ đầu nhòn. (3) Chưa đối trừ được khoản phải trả cổ tức 67,2 tỷ VND cho Tổng Công ty Hàng Hải Việt Nam với khoản phải thu sửa chữa tàu Vinashins Atlantic. (4) Các giao dịch với công ty con (VOSCO 100%) và công ty liên kết (Thương mại Dịch vụ Vosco, Đại lý Tàu biển Logistics Vosco) ở mức hợp lý nhưng cần theo dõi hiệu quả đầu tư.', 'Tổng nợ vay khoảng 637 tỷ VND, giảm mạnh so với đầu năm (1.327 tỷ VND) nhờ tích cực trả nợ gốc 685,9 tỷ VND trong năm. Tuy nhiên vẫn còn nợ quá hạn gốc 30,99 tỷ VND và lãi tích lũy 216,37 tỷ VND (giảm so với năm trước). Công ty đang trong quá trình tái cơ cấu nợ với Ngân hàng TMCP Ngoại thương Việt Nam (bán nợ sang Công ty TNHH Mua bán nợ Việt Nam). Phần lớn tài sản cố định (1.473 tỷ VND giá trị còn lại) đã dùng thế chấp đảm bảo khoản vay. Áp lực nợ vay đã giảm đáng kể nhờ cơ cấu lại, nhưng nợ quá hạn lãi vẫn là rủi ro lớn.', 'Hàng tồn kho 90,1 tỷ VND, chủ yếu là nguyên liệu vật liệu (89,7 tỷ VND) phục vụ hoạt động vận tải biển, không có dự phòng giảm giá. Giá trị tồn kho tăng 20% so với đầu năm, phù hợp với hoạt động kinh doanh tăng trưởng. Rủi ro tồn kho ở mức thấp do chủ yếu là nhiên liệu, vật tư tiêu hao có tính thanh khoản cao.', 6, 'Năm 2021 đánh dấu sự phục hồi mạnh mẽ của VOSCO với lợi nhuận trước thuế đạt 503,4 tỷ VND (so với lỗ 187,3 tỷ VND năm 2020). Kết quả tích cực đến từ: (1) Hoạt động vận tải biển hiệu quả với lợi nhuận gộp 453,1 tỷ VND; (2) Lãi bán khoản đầu tư MSB 137,9 tỷ VND; (3) Miễn giảm lãi vay từ cơ cấu nợ 55,7 tỷ VND; (4) Thanh lý tàu Đại Nam lãi 93,8 tỷ VND. Tuy nhiên, tính bền vững của lợi nhuận cần đánh giá do phụ thuộc lớn vào thu nhập bất thường (bán đầu tư, thanh lý tài sản, miễn giảm lãi vay chiếm hơn 60% lợi nhuận trước thuế). Nợ vay đã giảm mạnh nhưng vẫn còn nợ quá hạn lãi lớn 216 tỷ VND và đang tái cơ cấu nợ với VCB. Vốn chủ sở hữu vẫn âm do lỗ lũy kế 432,7 tỷ VND. Triển vọng trung hạn phụ thuộc vào khả năng hoàn tất tái cơ cấu nợ và duy trì hiệu quả vận tải biển.'),
('VOS_2018_parent', 'VOS', 2018, 'parent', 'Giao dịch với các bên liên quan (công ty con, công ty liên kết, công ty mẹ) là phổ biến và có giá trị lớn (mua/bán hàng hóa dịch vụ hàng chục tỷ VNĐ). Không có bằng chứng rõ ràng về giao dịch bất thường như cho vay không lãi suất hay chênh lệch giá lớn bất thường trong các giao dịch này. Tuy nhiên, khoản phải thu của Công ty TNHH Một thành viên Vận tải Viễn dương Vinashin (công ty liên kết cũ) 12.028.393.238 VND đã quá hạn trên 3 năm đang chờ bù trừ với nợ phải trả Tổng Công ty Hàng hải Việt Nam, cho thấy rủi ro thu hồi.', 'Áp lực nợ vay rất lớn. Tổng nợ vay và nợ thuê tài chính cuối năm là 1.941.382.082.955 VND, trong đó nợ ngắn hạn chiếm 700.402.379.315 VND. Nợ ngắn hạn vượt quá tài sản ngắn hạn 275.765.792.159 VND, tạo áp lực thanh khoản nghiêm trọng. Phần lớn nợ vay dài hạn được đảm bảo bằng tài sản hình thành từ vốn vay (tàu biển) với giá trị ghi sổ lớn. Công ty đã thực hiện cơ cấu nợ và chuyển đổi từ USD sang VND để quản lý rủi ro tỷ giá.', 'Hàng tồn kho chủ yếu là nguyên liệu, vật liệu (nhiên liệu cho tàu) và công cụ dụng cụ, không có hàng tồn kho dở dang hay dự án xây dựng dở dang. Giá trị tồn kho tăng từ 85.982.191.926 VND lên 135.975.346.672 VND. Rủi ro tồn kho ở mức trung bình, tập trung vào biến động giá nhiên liệu và khả năng tiêu hao trên tàu.', 4, 'Công ty hoạt động trong ngành vận tải biển đầy biến động. Năm 2018, Công ty đã có lãi sau thuế 14.580.546.988 VND, cải thiện so với năm trước, nhờ vào thu nhập từ cơ cấu nợ và thanh lý tài sản. Tuy nhiên, sức khỏe tài chính yếu kém với nợ ngắn hạn vượt quá tài sản ngắn hạn, vốn chủ sở hữu âm lũy kế (-786.347.626.962 VND). Dòng tiền hoạt động kinh doanh dương nhưng không đủ để bù đắp dòng tiền trả nợ vay lớn. Triển vọng phụ thuộc vào khả năng quản lý dòng tiền, cơ cấu nợ và biến động của thị trường vận tải biển. Rủi ro về khả năng hoạt động liên tục là đáng kể.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VOS_2022_parent', 'VOS', 2022, 'parent', 'Công ty có các giao dịch đáng kể với các bên liên quan như Tổng Công ty Hàng Hải Việt Nam (cổ đông lớn 51%) và các công ty con, liên kết. Khoản phải trả cổ tức 67,2 tỷ đồng cho Tổng Công ty Hàng Hải Việt Nam đang được bù trừ với khoản phải thu từ Công ty TNHH MTV Vận tải viễn dương Vinashin, cho thấy sự phức tạp trong quản lý công nợ nội bộ. Giao dịch với Công ty Cổ phần Thương mại và Dịch vụ Vosco (công ty liên kết) phát sinh khoản phải trả 4,77 tỷ đồng. Nhìn chung, các giao dịch này tiềm ẩn rủi ro về tính minh bạch và giá trị giao dịch.', 'Tại thời điểm cuối năm 2022, Công ty đã không còn dư nợ vay ngân hàng (vay ngắn hạn và dài hạn đều bằng 0), cho thấy áp lực nợ vay đã được giải quyết triệt để. Công ty đã hoàn tất thanh toán nợ cho Ngân hàng TMCP Ngoại thương Việt Nam (VCB) thông qua DATC, giúp ghi nhận khoản lợi nhuận khác lớn. Tuy nhiên, Công ty vẫn còn khoản phải trả lớn cho Ngân hàng Phát triển Việt Nam (249 tỷ đồng) và các khoản phải trả khác. Rủi ro nợ vay ở mức thấp.', 'Hàng tồn kho chủ yếu là nguyên liệu, vật liệu (141,7 tỷ đồng) phục vụ hoạt động vận tải biển, không có dự phòng giảm giá. Công ty không có các dự án bất động sản hay xây dựng cơ bản dở dang. Rủi ro tồn kho ở mức thấp.', 4, 'Công ty Cổ phần Vận tải Biển Việt Nam (VOS) có một năm tài chính 2022 rất tích cực. Lợi nhuận sau thuế đạt 483 tỷ đồng, tăng trưởng mạnh nhờ doanh thu vận tải tăng và đặc biệt là khoản lợi nhuận khác từ việc xử lý nợ thành công với VCB. Công ty đã trả hết nợ vay ngân hàng, cải thiện đáng kể cấu trúc tài chính và không còn áp lực nợ. Tuy nhiên, cần lưu ý đến các khoản phải thu và phải trả nội bộ phức tạp với các bên liên quan, cũng như các khoản tạm ứng lớn cho việc đóng tàu chưa được quyết toán. Nhìn chung, sức khỏe tài chính của VOS đã được phục hồi mạnh mẽ và triển vọng khả quan.'),
('VOS_2019_parent', 'VOS', 2019, 'parent', 'Công ty có nhiều giao dịch với bên liên quan bao gồm: (1) Công ty con 100% (Đại lý Tàu biển và Logistics Vosco) với tổng giao dịch mua bán khoảng 18,8 tỷ VND; (2) Công ty liên kết 46,45% (Thương mại và Dịch vụ Vosco) với tổng giao dịch mua bán khoảng 27 tỷ VND và nhận cổ tức 1,4 tỷ VND; (3) Khoản phải thu lớn từ Công ty TNHH MTV Vận tải viễn dương Vinashin (liên quan đến công ty mẹ Tổng Công ty Hàng hải Việt Nam) tổng cộng khoảng 86 tỷ VND đang chờ bù trừ với nợ phải trả công ty mẹ 67,2 tỷ VND. Các giao dịch này có tính chất thương mại thông thường nhưng mối quan hệ phức tạp giữa các bên liên quan, đặc biệt khoản phải thu chờ bù trừ lớn từ bên liên quan, cần được theo dõi chặt chẽ.', 'Tổng nợ vay phải trả là 1.449 tỷ VND (bao gồm 731,6 tỷ VND nợ ngắn hạn và 717,4 tỷ VND nợ dài hạn). Nợ ngắn hạn vượt quá tài sản ngắn hạn 348,2 tỷ VND, gây áp lực thanh khoản nghiêm trọng. Tài sản cố định hữu hình trị giá sổ sách 2.083 tỷ VND đã được thế chấp cho các khoản vay. Công ty còn lỗ lũy kế lớn (-733,9 tỷ VND) và đã chuyển lỗ thuế từ năm 2015-2016 với tổng số lỗ còn được chuyển 610 tỷ VND. Tuy nhiên, công ty đã giảm đáng kể nợ dài hạn từ 1.241 tỷ xuống 717 tỷ VND trong năm, có thu nhập lớn từ cơ cấu nợ (244,9 tỷ VND) và đang tích cực tái cơ cấu.', 'Hàng tồn kho cuối năm 2019 trị giá 90,9 tỷ VND (giảm từ 136 tỷ VND đầu năm), chủ yếu là nguyên liệu, vật liệu (90,9 tỷ VND). Không có dự phòng giảm giá hàng tồn kho. Không có bất động sản đầu tư hay dự án xây dựng dở dang. Rủi ro tồn kho ở mức thấp do đây là công ty vận tải biển, hàng tồn kho chủ yếu là nhiên liệu và vật tư tiêu hao.', 5, 'Công ty Cổ phần Vận tải Biển Việt Nam (VOSCO) đang trong giai đoạn tái cơ cấu tài chính với nhiều thách thức. Lợi nhuận gộp từ hoạt động kinh doanh chính bị âm (-12,9 tỷ VND), hoạt động kinh doanh thua lỗ (-186 tỷ VND). Lợi nhuận sau thuế 48,7 tỷ VND chủ yếu nhờ thu nhập từ cơ cấu nợ (244,9 tỷ VND) và lãi thanh lý tài sản (2,2 tỷ VND). Công ty có lỗ lũy kế lớn (-733,9 tỷ VND), nợ ngắn hạn vượt tài sản ngắn hạn, và phụ thuộc vào hoạt động cơ cấu nợ để duy trì hoạt động. Cổ đông Nhà nước chiếm 51% vốn (Tổng Công ty Hàng hải Việt Nam). Triển vọng đầu tư kém hấp dẫn do rủi ro thanh khoản cao, hoạt động kinh doanh chính thua lỗ, và sự phụ thuộc vào cơ cấu nợ.'),
('VOS_2017_parent', 'VOS', 2017, 'parent', 'Công ty có các giao dịch mua bán hàng hóa, dịch vụ đáng kể với các công ty con và công ty liên kết (Vosco Logistics, Vosco Maritime Services, Vosco Trade & Service). Các giao dịch này diễn ra trong hoạt động kinh doanh thông thường. Tuy nhiên, cần lưu ý khoản phải thu lớn từ Công ty TNHH Một thành viên Vận tải Viễn dương Vinashin (12 tỷ đồng) và khoản phải trả cho Tổng Công ty Hàng hải Việt Nam (77.6 tỷ đồng) đang chờ bù trừ, tiềm ẩn rủi ro về khả năng thu hồi và thanh toán. Ngoài ra, khoản cổ tức phải trả lớn (67.2 tỷ đồng) cũng là một nghĩa vụ tài chính cần lưu ý.', 'Công ty có tổng nợ vay rất lớn (hơn 2.297 tỷ đồng), chủ yếu là vay dài hạn bằng USD và VND từ các ngân hàng để đầu tư tàu biển. Áp lực trả nợ ngắn hạn rất cao (607.8 tỷ đồng), vượt xa tài sản ngắn hạn, dẫn đến vấn đề hoạt động liên tục được kiểm toán viên nhấn mạnh. Tài sản cố định (tàu biển) có giá trị còn lại lớn (2.807 tỷ đồng) được dùng làm tài sản thế chấp. Rủi ro tỷ giá USD/VND tác động mạnh đến chi phí tài chính và nghĩa vụ nợ.', 'Hàng tồn kho chủ yếu là nguyên liệu, vật liệu (dầu nhớt, phụ tùng) phục vụ hoạt động vận tải biển, giá trị ổn định và không có dự phòng giảm giá. Rủi ro tồn kho thấp.', 7, 'Công ty Cổ phần Vận tải Biển Việt Nam (Vosco) là doanh nghiệp vận tải biển lâu đời, có quy mô tài sản lớn. Năm 2017, công ty ghi nhận lợi nhuận sau thuế dương nhờ khoản thu nhập khác đột biến từ việc Ngân hàng Phát triển Việt Nam xóa nợ lãi (274 tỷ đồng) và lãi thanh lý tài sản cố định. Hoạt động kinh doanh cốt lõi vẫn lỗ (lợi nhuận gộp âm 118 tỷ đồng). Điểm yếu tài chính trọng yếu là cấu trúc vốn mất cân đối nghiêm trọng: nợ vay quá lớn, vốn chủ sở hữu thấp (lợi nhuận chưa phân phối âm 800 tỷ), và nợ ngắn hạn vượt quá tài sản ngắn hạn, đe dọa khả năng hoạt động liên tục. Công ty phụ thuộc nhiều vào các bên liên quan và có rủi ro quản trị cao. Triển vọng đầu tư rất rủi ro.'),
('VOS_2016_parent', 'VOS', 2016, 'parent', 'Công ty có các giao dịch đáng kể với các công ty con và công ty liên kết, bao gồm mua bán hàng hóa và nhận cổ tức. Đặc biệt, có khoản phải thu lớn (74 tỷ) từ Công ty TNHH Một thành viên Vận tải Viễn dương Vinashin và khoản phải trả cho Tổng Công ty Hàng hải Việt Nam (77 tỷ) đang chờ bù trừ, tiềm ẩn rủi ro về công nợ nội bộ. Việc chuyển đổi công ty con thành công ty liên kết và giải thể công ty con cũng cho thấy sự phức tạp trong quản lý các bên liên quan.', 'Công ty có tổng nợ vay rất lớn (hơn 2.534 tỷ đồng), trong đó vay dài hạn chiếm chủ yếu. Chi phí lãi vay năm 2016 là 134,8 tỷ đồng, tạo áp lực lớn lên dòng tiền. Tài sản đảm bảo chủ yếu là các tàu biển, nhiều khoản vay có lãi suất thả nổi gắn với Libor. Rủi ro thanh khoản cao do tài sản ngắn hạn thấp hơn nợ ngắn hạn (chênh lệch âm). Công ty đã được cấp hạn mức tín dụng ngắn hạn 110 tỷ để bù đắp, nhưng áp lực trả nợ vẫn rất lớn.', 'Hàng tồn kho chủ yếu là nguyên liệu, vật liệu và công cụ dụng cụ với tổng giá trị 86 tỷ đồng, không có dự phòng giảm giá. Rủi ro tồn kho thấp do đây là các vật tư phục vụ hoạt động vận tải, không có dấu hiệu ứ đọng.', 7, 'Công ty Cổ phần Vận tải Biển Việt Nam (VOSCO) năm 2016 ghi nhận lỗ thuần lớn (364 tỷ đồng), doanh thu giảm mạnh, giá vốn cao dẫn đến lợi nhuận gộp âm. Vốn chủ sở hữu giảm do lỗ lũy kế, đạt 619 tỷ đồng, trong đó lợi nhuận chưa phân phối âm 810 tỷ. Nợ vay lớn, cơ cấu tài chính mất cân đối với nợ phải trả chiếm 85% tổng nguồn vốn. Kiểm toán viên đưa ra ý kiến chấp nhận toàn phần, nhưng tình hình tài chính rất khó khăn, tiềm ẩn rủi ro về khả năng thanh toán và hoạt động liên tục. Các giao dịch bên liên quan phức tạp cần được giám sát chặt chẽ.'),
('VOS_2024_parent', 'VOS', 2024, 'parent', 'Doanh nghiệp có giao dịch với các bên liên quan như công ty mẹ, công ty con và công ty liên kết. Các giao dịch chủ yếu là doanh thu và mua hàng hóa dịch vụ, không có dấu hiệu bất thường rõ ràng. Tuy nhiên, có khoản phải thu từ Công ty TNHH MTV Vận tải viễn dương Vinashin đang trong quá trình phá sản, có thể gây rủi ro tín dụng.', 'Doanh nghiệp không có nợ vay ngân hàng, nợ phải trả chủ yếu là phải trả người bán và phải trả khác. Áp lực nợ vay thấp, khả năng thanh toán tốt với tài sản lưu động dồi dào.', 'Hàng tồn kho chủ yếu là nguyên liệu, vật liệu và công cụ dụng cụ, không có dự án xây dựng dở dang. Rủi ro tồn kho thấp do không có dấu hiệu ứ đọng.', 4, 'Doanh nghiệp có sự tăng trưởng lợi nhuận trong năm 2024, với tỷ suất lợi nhuận gộp thấp nhưng bù đắp bằng thu nhập từ thanh lý tài sản. Cơ cấu tài chính lành mạnh với nợ vay thấp và thanh khoản tốt. Tuy nhiên, cần theo dõi các khoản phải thu từ bên liên quan đang gặp khó khăn.'),
('VOS_2015_parent', 'VOS', 2015, 'parent', 'Công ty có nhiều giao dịch đáng kể với các công ty con (mua bán, nhận lợi nhuận, cổ tức). Đặc biệt, khoản phải thu từ Công ty TNHH Vận tải Viễn dương Vinashin lên tới 74 tỷ đồng đang chờ bù trừ với nợ phải trả Tổng Công ty Hàng hải Việt Nam, tiềm ẩn rủi ro thu hồi. Bên cạnh đó, các khoản trả trước cho người bán (như Đóng tàu Nam Triệu 256 tỷ) có giá trị lớn, có thể gây áp lực thanh khoản.', 'Tổng nợ vay cuối kỳ là 2.602 tỷ đồng, trong đó chủ yếu là nợ dài hạn. Chi phí lãi vay năm nay là 141,5 tỷ đồng, chiếm tỷ trọng lớn trong chi phí tài chính. Tài sản thế chấp chủ yếu là tàu biển, giá trị còn lại 3.375 tỷ. Công ty cho rằng có khả năng trả nợ nhờ dòng tiền từ hoạt động kinh doanh, tuy nhiên áp lực nợ vay là đáng kể.', 'Hàng tồn kho chủ yếu là nguyên liệu, vật liệu (84,2 tỷ), không có dự phòng giảm giá. Chi phí xây dựng cơ bản dở dang nhỏ (0,1 tỷ) không đáng kể. Rủi ro tồn kho thấp.', 6, 'Công ty CP Vận tải biển Việt Nam (Vosco) là doanh nghiệp vận tải biển có vốn nhà nước chi phối. Kết quả kinh doanh năm 2015 lỗ nặng 296,5 tỷ đồng, do doanh thu giảm và chi phí tài chính cao. Công ty có cấu trúc vốn với tỷ lệ nợ cao (3.582 tỷ nợ phải trả so với 983 tỷ vốn chủ sở hữu). Mặc dù dòng tiền từ hoạt động kinh doanh dương, nhưng dòng tiền đầu tư và tài chính âm nặng. Rủi ro thanh khoản và rủi ro tỷ giá (nợ vay USD lớn) cần theo dõi. Nhà đầu tư nên thận trọng.'),
('VOS_2015_consolidated', 'VOS', 2015, 'consolidated', 'Giao dịch với các bên liên quan chủ yếu là nội bộ với công ty mẹ và công ty liên doanh, không có dấu hiệu bất thường. Công nợ phải thu với Công ty TNHH MTV Vận tải Viễn dương Vinashin đang chờ bù trừ với nợ phải trả Tổng Công ty Hàng hải Việt Nam.', 'Tập đoàn có nợ vay lớn với tổng nợ vay và nợ thuê tài chính là hơn 2.600 tỷ VNĐ, trong đó nợ dài hạn chiếm phần lớn. Công ty có khả năng thanh toán các khoản vay từ dòng tiền kinh doanh và tài sản thế chấp (tàu biển). Tuy nhiên, áp lực trả nợ là đáng kể do chi phí lãi vay cao.', 'Hàng tồn kho giảm so với năm trước và có dự phòng giảm giá, chủ yếu là hàng hóa. Không có dấu hiệu ứ đọng lớn, nhưng cần theo dõi sát tình hình tiêu thụ.', 4, 'Tập đoàn vận tải biển Việt Nam đang trong giai đoạn khó khăn với lợi nhuận sau thuế âm trong năm 2015. Nợ vay cao, chi phí tài chính lớn, và doanh thu giảm. Tuy nhiên, công ty có tài sản thế chấp mạnh (tàu biển) và dòng tiền từ hoạt động kinh doanh vẫn dương. Triển vọng phụ thuộc vào sự phục hồi của ngành vận tải biển và khả năng quản lý nợ.'),
('VCB_2025_parent', 'VCB', 2025, 'parent', 'Ngân hàng có nhiều giao dịch với các bên liên quan như NHNN, Bộ Tài chính, các công ty con, cổ đông chiến lược và ban lãnh đạo. Các giao dịch được thuyết minh đầy đủ, lãi suất thị trường, không phát hiện bất thường lớn. Rủi ro thấp.', 'Nợ vay tăng mạnh chủ yếu từ vay Ngân hàng Nhà nước qua cầm cố giấy tờ có giá (23,7 nghìn tỷ), phản ánh nhu cầu thanh khoản ngắn hạn. Tuy nhiên, ngân hàng có thanh khoản tốt và tài sản đảm bảo chất lượng. Áp lực nợ thấp.', 'Ngân hàng không có hàng tồn kho thương mại. Các dự án xây dựng cơ bản dở dang (chủ yếu trụ sở) có giá trị nhỏ so với tổng tài sản, không có rủi ro ứ đọng đáng kể.', 2, 'Vietcombank là ngân hàng thương mại hàng đầu Việt Nam với quy mô tài sản lớn, chất lượng tín dụng tốt (NPL chỉ 0.58%). Lợi nhuận tăng trưởng ổn định, thu nhập lãi thuần đạt 57,6 nghìn tỷ. Các giao dịch bên liên quan được kiểm soát chặt chẽ. Sức khỏe tài chính mạnh, triển vọng đầu tư tích cực.'),
('VCB_2022_consolidated', 'VCB', 2022, 'consolidated', 'Các giao dịch với bên liên quan chủ yếu là quan hệ tiền gửi/vay thông thường với các cơ quan Nhà nước (NHNN, Bộ Tài chính) và cổ đông chiến lược (Mizuho). Không phát hiện giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn. Rủi ro thấp.', 'Nợ vay chủ yếu đến từ tiền gửi của khách hàng và tổ chức tín dụng, đây là nguồn vốn ổn định và chi phí tương đối. Tuy nhiên, Ngân hàng có tỷ lệ đòn bẩy cao (nợ phải trả chiếm hơn 90% tổng nguồn vốn), cần theo dõi chặt chẽ rủi ro thanh khoản và lãi suất. Tài sản thế chấp lớn (hơn 2,1 triệu tỷ VNĐ) hỗ trợ giảm rủi ro tín dụng.', 'Ngân hàng không có hàng tồn kho truyền thống. Các dự án xây dựng dở dang (trụ sở chi nhánh) có giá trị không đáng kể so với quy mô tài sản và không có dấu hiệu ứ đọng lớn. Rủi ro thấp.', 5, 'Vietcombank là ngân hàng lớn, có sức khỏe tài chính tốt với lợi nhuận tăng trưởng mạnh (~36%), hệ số an toàn cao. Tuy nhiên, tăng trưởng tín dụng nhanh (~20%) đi kèm với dự phòng tăng, cần giám sát chất lượng tài sản. Khả năng sinh lời tốt, được hỗ trợ bởi thu nhập lãi thuần và dịch vụ. Triển vọng ổn định, phụ thuộc vào môi trường kinh tế vĩ mô và mặt bằng lãi suất.'),
('VCB_2025_consolidated', 'VCB', 2025, 'consolidated', 'Giao dịch với bên liên quan chủ yếu là tiền gửi và vay vốn giữa Vietcombank với NHNNVN và Bộ Tài chính (Kho bạc Nhà nước) – đây là giao dịch mang tính hệ thống, không có biểu hiện bất thường. Cổ đông chiến lược Mizuho Bank (15%) có tiền gửi qua lại với quy mô nhỏ. Các giao dịch với công ty liên doanh, liên kết và người quản lý có giá trị không đáng kể so với tổng tài sản 2.44 triệu tỷ VNĐ. Không phát hiện dấu hiệu giao dịch bất thường, cho vay không lãi suất hay mua bán chênh lệch lớn với bên liên quan.', 'Tổng nợ phải trả đạt 2.22 triệu tỷ VNĐ (tỷ lệ nợ/tổng tài sản ~90.8%), phản ánh bản chất kinh doanh ngân hàng huy động tiền gửi. Nợ xấu (Nhóm 3-5) chiếm tỷ lệ thấp 0.58% tổng dư nợ cho vay, giảm so với 0.71% năm 2024. Dự phòng cụ thể cho vay đạt 12,552,995 triệu VNĐ, tỷ lệ bao phủ nợ xấu ~130%. Tuy nhiên, có 1 khoản trái phiếu doanh nghiệp chưa niêm yết trị giá 3,306,873 triệu VNĐ được phân loại là nợ nghi ngờ. Tiền gửi của khách hàng chiếm 75.4% tổng nợ, tạo áp lực duy trì chi phí huy động. Tỷ lệ tiền gửi không kỳ hạn (CASA) đạt ~33.7% giúp giảm chi phí vốn.', 'Chi phí xây dựng cơ bản dở dang đạt 410,794 triệu VNĐ với nhiều dự án xây dựng trụ sở chi nhánh đang triển khai. Giá trị này không lớn so với tổng tài sản nhưng cần theo dõi tiến độ hoàn thành và khả năng chuyển giao vào tài sản cố định. Các dự án đầu tư dài hạn vào đơn vị khác có dự phòng giảm giá 75,000 triệu VNĐ, cho thấy một số khoản đầu tư có dấu hiệu suy giảm giá trị.', 3, 'Vietcombank là ngân hàng thương mại nhà nước lớn nhất Việt Nam với tổng tài sản 2.44 triệu tỷ VNĐ, cổ đông Nhà nước chiếm 74.8% và cổ đông chiến lược Mizuho Bank (Nhật Bản) 15%. Năm 2025, lợi nhuận sau thuế đạt 35,198 tỷ VNĐ, tăng 4% so với năm trước. NIM đạt ~2.65%, nợ xấu chỉ 0.58% – mức thấp nhất trong hệ thống ngân hàng. Tuy nhiên, nợ xấu đã giảm nhờ trích lập và hoàn nhập dự phòng lớn (dự phòng cụ thể giảm từ 20,495,176 xuống 12,552,995 triệu). Vốn điều lệ đã tăng mạnh lên 83,557 tỷ VNĐ thông qua phát hành cổ phiếu thưởng tỷ lệ 49.5%. Điểm đáng lưu ý: (1) chi phí dự phòng rủi ro tín dụng trong năm 2025 vẫn dương 3,192,186 triệu VNĐ (có trích lập mới cho trái phiếu doanh nghiệp 3,128,122 triệu); (2) giao dịch với bên liên quan minh bạch, không có dấu hiệu bất thường; (3) ngân hàng đã tiếp nhận CGBB Ngân hàng Xây dựng nhưng không hợp nhất BCTC. Sức khỏe tài chính ở mức tốt, triển vọng đầu tư tích cực nhờ vị thế dẫn đầu, lợi nhuận ổn định và quản trị rủi ro tốt.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VCB_2023_consolidated', 'VCB', 2023, 'consolidated', 'Giao dịch với các bên liên quan chủ yếu là Ngân hàng Nhà nước và Bộ Tài chính, phát sinh từ hoạt động huy động vốn và cho vay thông thường với lãi suất thị trường. Không phát hiện giao dịch bất thường hoặc chuyển giá. Rủi ro thấp.', 'Tổng nợ vay (NHNN và TCTD) chiếm tỷ trọng nhỏ trong tổng nguồn vốn (khoảng 12% tổng nợ phải trả). Ngân hàng có thanh khoản dồi dào với tiền gửi khách hàng lớn. Áp lực nợ vay thấp, rủi ro thanh khoản được quản lý tốt.', 'Hàng tồn kho không đáng kể, chỉ có các dự án xây dựng cơ bản dở dang (tổng giá trị 305 tỷ VND), chủ yếu là xây dựng trụ sở chi nhánh. Không có rủi ro tồn kho ứ đọng lớn.', 2, 'Vietcombank là ngân hàng thương mại hàng đầu, có nền tảng tài chính vững mạnh với tổng tài sản hơn 1.800 nghìn tỷ đồng, lợi nhuận trước thuế đạt 41.243 tỷ đồng tăng trưởng 10.4% so với năm trước. Chất lượng tài sản tốt, nợ xấu ở mức 1% (Nợ xấu khoảng 12.455 tỷ trên dư nợ cho vay 1.270 nghìn tỷ). Tỷ lệ dự phòng bao phủ nợ xấu ở mức 155% cho thấy trích lập đầy đủ. Ngân hàng có vị thế thanh khoản mạnh với tiền gửi không kỳ hạn chiếm 33% tổng tiền gửi. Nhìn chung, Vietcombank có sức khỏe tài chính lành mạnh, quản trị rủi ro tốt và là kênh đầu tư an toàn.'),
('VCB_2020_consolidated', 'VCB', 2020, 'consolidated', 'Các giao dịch với Ngân hàng Nhà nước Việt Nam và Bộ Tài chính là các giao dịch thông thường trong hoạt động ngân hàng, không phát hiện dấu hiệu bất thường. Quan hệ với cổ đông chiến lược Mizuho Bank chỉ bao gồm tiền gửi và cho vay thông thường, không có giao dịch đáng ngờ. Rủi ro từ giao dịch bên liên quan ở mức thấp.', 'Ngân hàng có các khoản nợ vay Ngân hàng Nhà nước và phát hành trái phiếu, nhưng tỷ lệ nợ trên vốn chủ sở hữu thấp (khoảng 13 lần nợ/vốn nhưng đặc thù ngân hàng). Khả năng thanh toán tốt nhờ nguồn tiền gửi khách hàng lớn và thanh khoản dồi dào. Tài sản đảm bảo chủ yếu là các khoản cho vay có tài sản thế chấp, không có dấu hiệu rủi ro đặc biệt.', 'Tài sản dở dang chủ yếu là chi phí xây dựng cơ bản các trụ sở chi nhánh, không phải hàng tồn kho kinh doanh. Rủi ro ứ đọng thấp vì các dự án đang triển khai và có giá trị nhỏ so với tổng tài sản.', 3, 'Vietcombank là ngân hàng thương mại hàng đầu Việt Nam với tình hình tài chính lành mạnh. Lợi nhuận sau thuế đạt 18.472 tỷ đồng, tăng trưởng tín dụng ổn định. Tỷ lệ nợ xấu thấp (0,62%), dự phòng bao phủ tốt. Cơ cấu vốn an toàn, thanh khoản dồi dào. Các giao dịch bên liên quan minh bạch. Triển vọng đầu tư tích cực.'),
('VCB_2022_parent', 'VCB', 2022, 'parent', 'Rủi ro giao dịch bên liên quan ở mức trung bình. Ngân hàng có giao dịch lớn với Bộ Tài chính (chi phí lãi tiền gửi và tiền vay khoảng 1.491 tỷ VNĐ năm 2022), Ngân hàng Nhà nước Việt Nam (đại diện chủ sở hữu), và nhiều công ty con. Các giao dịch chủ yếu là tiền gửi, cho vay, thuê văn phòng và dịch vụ giữa ngân hàng mẹ với các công ty con - đây là giao dịch nội bộ thông thường trong hệ thống ngân hàng có công ty con. Không phát hiện giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn bất hợp lý. Tuy nhiên, số dư phải trả nội bộ tăng mạnh từ 3.681 tỷ lên 24.303 tỷ VNĐ cần được theo dõi thêm.', 'Rủi ro nợ vay ở mức thấp. Nguồn vốn của Ngân hàng chủ yếu từ tiền gửi khách hàng (1.244.501 tỷ VNĐ, chiếm 74.3% tổng nợ phải trả), tạo nền tảng vốn ổn định. Vốn chủ sở hữu đạt 133.459 tỷ VNĐ, tỷ lệ an toàn vốn cao. Nợ vay từ Chính phủ/NHNN ở mức 67.315 tỷ VNĐ (giảm so với mức tăng trưởng tín dụng). Dư nợ cho vay khách hàng tăng 20.4% (từ 952.019 tỷ lên 1.136.204 tỷ VNĐ), tốc độ tăng trưởng tín dụng nhanh hơn tốc độ tăng tiền gửi (9.5%) cần được giám sát chặt. Tổng tài sản đảm bảo đạt 2.108.376 tỷ VNĐ, bao gồm bất động sản 1.559.579 tỷ VNĐ.', 'Rủi ro tồn kho/dự án ở mức thấp. Là ngân hàng thương mại, không có hàng tồn kho truyền thống. Chi phí xây dựng cơ bản dở dang chỉ đạt 241.567 triệu VNĐ (0.01% tổng tài sản), giảm so với năm trước (302.160 triệu VNĐ). Các dự án xây dựng trụ sở chi nhánh đều có quy mô nhỏ, tập trung tại các tỉnh thành, không có dấu hiệu ứ đọng đáng kể.', 3, 'Ngân hàng TMCP Ngoại thương Việt Nam (Vietcombank) có tình hình tài chính vững mạnh năm 2022. Tổng tài sản đạt 1.808.208 tỷ VNĐ, tăng 28.5% so với năm trước. Lợi nhuận sau thuế đạt 29.387 tỷ VNĐ, tăng trưởng 38.2% so với năm 2021. Tỷ lệ nợ xấu (nhóm 3-5/cho vay khách hàng) ở mức 0.68%, tương đối thấp so với mặt bằng ngành. Tuy nhiên, nợ xấu tuyệt đối tăng từ 4.396 tỷ lên 6.597 tỷ VNĐ, chi phí dự phòng rủi ro tín dụng giảm từ 11.448 tỷ xuống 9.446 tỷ VNĐ cho thấy chất lượng tài sản có dấu hiệu suy giảm nhẹ. Ngân hàng có cổ đông Nhà nước (74.8%) và cổ đông chiến lược Mizuho Bank (15.0%), tạo nền tảng quản trị ổn định. Kiểm toán Ernst & Young Việt Nam đưa ra ý kiến chấp nhận toàn phần. Điểm đáng lưu ý là tăng trưởng tín dụng 20.4% vượt xa tăng trưởng tiền gửi 9.5%, cho thấy ngân hàng đang đẩy mạnh hoạt động cho vay, cần giám sát rủi ro tín dụng trong dài hạn. Đơn vị kiểm toán là công ty Big Four, đảm bảo độ tin cậy cao.'),
('VCB_2019_consolidated', 'VCB', 2019, 'consolidated', 'Các giao dịch với bên liên quan chủ yếu diễn ra với Ngân hàng Nhà nước (đại diện chủ sở hữu) và Bộ Tài chính (bên liên quan của chủ sở hữu), cùng với cổ đông chiến lược Mizuho Bank. Các giao dịch này bao gồm thu nhập lãi tiền gửi và chi phí lãi vay, được thực hiện theo lãi suất thị trường. Không phát hiện giao dịch bất thường nào như cho vay không lãi suất hoặc mua bán chênh lệch lớn. Rủi ro từ giao dịch bên liên quan ở mức thấp.', 'Ngân hàng có cấu trúc nợ phải trả chủ yếu từ tiền gửi khách hàng (928.450 tỷ đồng), chiếm tỷ trọng lớn. Nợ vay từ Chính phủ, NHNN và các TCTD khác ở mức thấp (khoảng 165.983 tỷ đồng). Khả năng thanh toán tốt, không có áp lực nợ vay đáng kể. Tài sản thế chấp chủ yếu là bất động sản và giấy tờ có giá, đảm bảo an toàn.', 'Vietcombank là ngân hàng thương mại, không có hàng tồn kho sản xuất. Các khoản mục tương tự hàng tồn kho là chi phí xây dựng cơ bản dở dang (các dự án xây trụ sở chi nhánh) với tổng giá trị khoảng 794 tỷ đồng. Các dự án này đang triển khai, không có dấu hiệu ứ đọng. Rủi ro thấp.', 2, 'Vietcombank là ngân hàng thương mại hàng đầu Việt Nam với tình hình tài chính lành mạnh. Báo cáo kiểm toán nhận ý kiến chấp nhận toàn phần từ KPMG, không có vấn đề hoạt động liên tục. Lợi nhuận sau thuế năm 2019 đạt 18.526 tỷ đồng, tăng 26,7% so với năm trước. Tỷ lệ nợ xấu thấp (0,79%), dự phòng bao phủ nợ xấu tốt (179,5%). Thanh khoản dồi dào với tiền gửi khách hàng tăng trưởng mạnh. Nhìn chung, sức khỏe tài chính rất tốt, triển vọng đầu tư tích cực.'),
('VCB_2024_parent', 'VCB', 2024, 'parent', 'Giao dịch với các bên liên quan chủ yếu là các công ty con và các tổ chức nhà nước (NHNN, Bộ Tài chính), phục vụ hoạt động kinh doanh thông thường. Không phát hiện dấu hiệu bất thường như cho vay không lãi suất hay chiếm dụng vốn kéo dài.', 'Nợ vay ở mức cao (tổng nợ phải trả gấp 9.76 lần vốn chủ sở hữu) nhưng phù hợp với đặc thù ngân hàng thương mại. Thanh khoản tốt, không có dấu hiệu áp lực trả nợ đáng kể. Các khoản vay chủ yếu từ NHNN và các TCTD khác, lãi suất thị trường.', 'Ngân hàng không có hàng tồn kho sản xuất. Chi phí xây dựng cơ bản dở dang chiếm tỷ trọng rất nhỏ (0.016% tổng tài sản), không có rủi ro đọng vốn đáng kể.', 2, 'Ngân hàng TMCP Ngoại thương Việt Nam (Vietcombank) là một trong những ngân hàng thương mại hàng đầu Việt Nam, có nền tảng tài chính vững mạnh, tỷ lệ an toàn vốn tốt, quản trị rủi ro chặt chẽ. Kết quả kinh doanh ổn định với lợi nhuận sau thuế tăng trưởng nhẹ. Cơ cấu cổ đông rõ ràng với Nhà nước chi phối. Triển vọng đầu tư tích cực.'),
('VCB_2024_consolidated', 'VCB', 2024, 'consolidated', 'Giao dịch với Ngân hàng Nhà nước và Bộ Tài chính chủ yếu là giao dịch lãi suất tiền gửi và vay, phản ánh hoạt động kinh doanh cốt lõi của ngân hàng. Không có dấu hiệu bất thường lớn.', 'Nợ vay và tiền gửi chiếm tỷ trọng lớn nhưng được quản lý theo quy định ngân hàng. Tỷ lệ nợ xấu ở mức kiểm soát, với dự phòng đầy đủ.', 'Không có hàng tồn kho truyền thống. Các dự án xây dựng dở dang có giá trị nhỏ và không đáng kể trong tổng tài sản.', 3, 'Ngân hàng có tình hình tài chính vững mạnh, tăng trưởng ổn định, với hệ thống quản trị rủi ro tốt. Triển vọng tích cực.'),
('VCB_2021_consolidated', 'VCB', 2021, 'consolidated', 'Các giao dịch với bên liên quan chủ yếu là giao dịch huy động vốn và đầu tư truyền thống của ngân hàng thương mại. Giao dịch với NHNN (dự trữ bắt buộc, tiền gửi thanh toán) và Bộ Tài chính (tiền gửi Kho bạc, vay hỗ trợ) là hoạt động nghiệp vụ đặc thù, không có dấu hiệu bất thường. Giao dịch với Mizuho Bank Ltd. (cổ đông chiến lược 15%) là quan hệ tiền gửi qua lại giữa hai ngân hàng, giá trị hợp lý. Các công ty con và liên doanh chủ yếu hoạt động trong lĩnh vực tài chính ngân hàng truyền thống. Chưa phát hiện dấu hiệu chuyển giá, tuồn vốn hay giao dịch bất thường với bên liên quan.', 'Tổng nợ phải trả 1.305.555 tỷ VND, tỷ lệ nợ/Vốn chủ sở hữu khoảng 11,97 lần - đặc thù hoạt động ngân hàng. Nợ lớn nhất là tiền gửi của khách hàng 1.135.324 tỷ VND (huy động ngắn hạn và dài hạn),其次是 tiền gửi TCTD khác 104.044 tỷ VND. Phát hành giấy tờ có giá 17.388 tỷ VND. Nợ xấu nội bảng (nhóm 3,4,5) chiếm 9,6% dư nợ cho vay (tăng so với 8% năm 2020), trong đó nợ có khả năng mất vốn chiếm 4,6%. Tuy nhiên, tỷ lệ dự phòng/nợ xấu đạt 270%, mức trích lập dự phòng rất thận trọng. Áp lực thanh toán ngắn hạn lớn nhưng được bù đắp bởi tiền gửi thanh toán dồi dào.', 'Vietcombank không có hàng tồn kho theo nghĩa thông thường. Các khoản chi phí xây dựng cơ bản dở dang trị giá 314.690 triệu VND (chiếm tỷ trọng rất nhỏ trên tổng tài sản 1,4 triệu tỷ) chủ yếu là các dự án xây dựng trụ sở chi nhánh. Đây là đầu tư hạ tầng mạng lưới phục vụ kinh doanh, không phải hàng tồn kho thương mại. Rủi ro đọng vốn thấp do quy mô nhỏ so với tổng tài sản.', 3, 'Vietcombank là ngân hàng thương mại lớn nhất Việt Nam với tổng tài sản 1,41 triệu tỷ VND, thuộc sở hữu Nhà nước (74,8%) và Mizuho Bank (15%). Năm 2021, ngân hàng đạt lợi nhuận sau thuế 21.939 tỷ VND (tăng 18,8%), lãi cơ bản trên cổ phiếu 4.195 đồng/cổ phiếu. Thu nhập lãi thuần đạt 42.400 tỷ VND (tăng 16,9%), chứng tỏ hoạt động kinh doanh cốt lõi vững mạnh. Nợ xấu tăng nhẹ lên 9,6% nhưng tỷ lệ dự phòng 270% cho thấy quản trị rủi ro thận trọng. Cơ chế quản trị tốt với Hội đồng Quản trị chuyên nghiệp, Ban Kiểm soát độc lập, kiểm toán bởi KPMG. Ngân hàng duy trì vị thế dẫn đầu thị trường với mạng lưới rộng khắp và sản phẩm đa dạng.'),
('VCB_2021_parent', 'VCB', 2021, 'parent', 'Giao dịch với các bên liên quan chủ yếu là với các công ty con và các cơ quan nhà nước (NHNN, Bộ Tài chính). Các giao dịch bao gồm cho vay, nhận tiền gửi, thuê văn phòng. Không phát hiện giao dịch bất thường. Tuy nhiên, có khoản cho vay lớn đối với công ty con (Công ty Cho thuê Tài chính) với giá trị 3.365.930 triệu VND, cần theo dõi.', 'Nợ vay chủ yếu từ Ngân hàng Nhà nước và phát hành trái phiếu. Tổng nợ phải trả 1.300.310.335 triệu VND, vốn chủ sở hữu 106.523.279 triệu VND, tỷ lệ nợ/vốn chủ sở hữu ở mức cao 12,2 lần, nhưng đây là đặc thù của ngân hàng. Thanh khoản tốt với tiền và tương đương tiền 232.843.012 triệu VND. Rủi ro thanh khoản thấp.', 'Ngân hàng không có hàng tồn kho, chỉ có các dự án xây dựng cơ bản dở dang trị giá 302.160 triệu VND, chiếm tỷ trọng nhỏ. Các dự án đều là xây trụ sở, tiến độ bình thường, không có rủi ro đáng kể.', 3, 'Vietcombank là ngân hàng thương mại cổ phần có vốn nhà nước chi phối, hoạt động ổn định, lợi nhuận tăng trưởng. Tỷ lệ nợ xấu thấp (0,64%), dự phòng bao phủ tốt (308%). CASA ratio cao (32,36%) cho thấy chi phí vốn thấp. Nhìn chung, tình hình tài chính lành mạnh, rủi ro thấp.'),
('VCB_2020_parent', 'VCB', 2020, 'parent', 'Giao dịch với các bên liên quan chủ yếu là nghiệp vụ huy động và cho vay giữa Ngân hàng với các công ty con và cổ đông lớn (NHNN, Bộ Tài chính, Mizuho). Các giao dịch này là hoạt động kinh doanh cốt lõi, quy mô lớn nhưng phù hợp với mô hình ngân hàng. Chưa thấy dấu hiệu chuyển giá hay rút vốn bất thường qua các giao dịch này.', 'Nợ phải trả tập trung chủ yếu vào tiền gửi khách hàng (hơn 84% tổng nợ), với cơ cấu kỳ hạn đa dạng, bao gồm cả không kỳ hạn và có kỳ hạn. Nợ phát hành giấy tờ có giá chủ yếu là trung và dài hạn. Áp lực thanh toán nợ ngắn hạn được kiểm soát tốt nhờ tiền và tương đương tiền lớn (291.166 tỷ VNĐ). Tỷ lệ nợ/VCSH khoảng 13,3 lần, phản ánh đặc thù hoạt động ngân hàng.', 'Hàng tồn kho và dự án chủ yếu là chi phí xây dựng cơ bản dở dang cho các trụ sở chi nhánh. Các dự án này đang trong quá trình triển khai, chưa có dấu hiệu đình trệ hay tồn đọng lớn. Tổng giá trị xây dựng dở dang (449 tỷ VNĐ) là không đáng kể so với quy mô tài sản của Ngân hàng.', 3, 'Ngân hàng TMCP Ngoại thương Việt Nam (Vietcombank) có sức khỏe tài chính vững mạnh. Các chỉ tiêu an toàn hoạt động được đảm bảo, thanh khoản dồi dào. Công tác quản trị rủi ro tín dụng, lãi suất, tỷ giá được thực hiện chặt chẽ. Ý kiến kiểm toán chấp nhận toàn phần là minh chứng cho tính minh bạch và tuân thủ pháp lý. Triển vọng kinh doanh tích cực trong dài hạn.'),
('VCB_2019_parent', 'VCB', 2019, 'parent', 'Các giao dịch bên liên quan chủ yếu với Ngân hàng Nhà nước, Bộ Tài chính và các công ty con trong hệ thống. Các giao dịch này bao gồm tiền gửi, cho vay, và dịch vụ, với quy mô phù hợp hoạt động kinh doanh thông thường. Không phát hiện dấu hiệu bất thường hay rủi ro chuyển giá.', 'Nợ vay chủ yếu từ Ngân hàng Nhà nước và các tổ chức tín dụng khác, với lãi suất thị trường. Tỷ lệ nợ phải trả trên vốn chủ sở hữu ở mức cao (14.4 lần) nhưng phù hợp với đặc thù ngân hàng. Áp lực thanh toán được quản lý tốt thông qua chính sách quản lý thanh khoản chặt chẽ.', 'Ngân hàng không có hàng tồn kho thương mại. Các dự án xây dựng cơ bản dở dang là đầu tư vào trụ sở chi nhánh, không có rủi ro đọng vốn hay mất thanh khoản.', 2, 'Vietcombank là ngân hàng thương mại cổ phần hàng đầu Việt Nam, với quy mô tài sản lớn, chất lượng tài sản tốt (tỷ lệ nợ xấu 0.79%), khả năng sinh lời ổn định và tăng trưởng. Công tác quản trị rủi ro được thực hiện bài bản, kiểm toán độc lập bởi KPMG với ý kiến chấp nhận toàn phần. Cơ cấu cổ đông minh bạch với Nhà nước nắm giữ 74.8%. Hoạt động kinh doanh cốt lõi ổn định, triển vọng tăng trưởng tích cực nhờ nền kinh tế vĩ mô ổn định và nhu cầu tín dụng tăng.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VCB_2018_parent', 'VCB', 2018, 'parent', 'Các giao dịch với bên liên quan chủ yếu là tiền gửi, cho vay và dịch vụ giữa Ngân hàng với NHNN, Bộ Tài chính, các công ty con và cổ đông chiến lược. Các giao dịch này được thực hiện theo điều kiện thị trường, không phát hiện dấu hiệu bất thường. Rủi ro thấp.', 'Nợ phải trả chủ yếu là tiền gửi khách hàng (802.115 tỷ) và phát hành giấy tờ có giá (21.419 tỷ). Tỷ lệ nợ/vốn chủ sở hữu cao (~16,6 lần) là đặc thù của ngân hàng thương mại. Khả năng thanh khoản tốt, lợi nhuận ổn định. Rủi ro nợ ở mức trung bình.', 'Ngân hàng không có hàng tồn kho sản xuất. Tài sản dở dang chỉ bao gồm chi phí xây dựng cơ bản các trụ sở chi nhánh, giá trị nhỏ so với tổng tài sản. Rủi ro đọng vốn thấp.', 3, 'Vietcombank là ngân hàng thương mại hàng đầu Việt Nam với quy mô tài sản lớn, chất lượng tài sản tốt (tỷ lệ nợ xấu 0,99%), lợi nhuận tăng trưởng mạnh (LNST tăng 63% so với 2017). Kiểm toán độc lập bởi KPMG với ý kiến chấp nhận toàn phần. Cơ cấu cổ đông ổn định với Nhà nước nắm 77%. Triển vọng kinh doanh tích cực, phù hợp cho đầu tư dài hạn.'),
('VCB_2018_consolidated', 'VCB', 2018, 'consolidated', 'Giao dịch với các bên liên quan chủ yếu là với Ngân hàng Nhà nước và Bộ Tài chính - các đại diện chủ sở hữu. Các giao dịch này thuộc hoạt động bình thường trong nghiệp vụ ngân hàng (tiền gửi, vay), không có dấu hiệu bất thường hay chuyển giá.', 'Nợ vay bao gồm tiền gửi khách hàng chiếm tỷ trọng lớn (hơn 78% tổng nợ), tạo áp lực thanh khoản. Tuy nhiên, ngân hàng có hệ số an toàn vốn tốt và đa dạng hóa nguồn vốn. Nợ xấu ở mức thấp 0.99% với tỷ lệ dự phòng trên nợ xấu đạt 90%, cho thấy kiểm soát rủi ro tín dụng hiệu quả.', 'Không có hàng tồn kho vật lý. Các dự án xây dựng dở dang chủ yếu là xây dựng trụ sở chi nhánh, tiến triển bình thường, rủi ro đọng vốn thấp.', 2, 'Vietcombank có nền tảng tài chính vững mạnh, hoạt động kinh doanh hiệu quả với lợi nhuận trước thuế tăng trưởng 61%. Tỷ lệ nợ xấu được kiểm soát tốt, dự phòng đầy đủ. Quản trị rủi ro chuyên nghiệp với hệ thống kiểm soát nội bộ và kiểm toán uy tín. Cơ cấu cổ đông minh bạch, ban lãnh đạo nhất quán. Triển vọng phát triển tích cực.'),
('VCB_2017_parent', 'VCB', 2017, 'parent', 'Các giao dịch với bên liên quan chủ yếu là các giao dịch tài chính thông thường với Ngân hàng Nhà nước, Bộ Tài chính và các công ty con. Các khoản thu nhập/chi phí phát sinh từ hoạt động huy động vốn và cho vay. Không phát hiện giao dịch bất thường hoặc có dấu hiệu chuyển giá. Rủi ro thấp.', 'Nợ vay chủ yếu là vay ngắn hạn từ Ngân hàng Nhà nước và các tổ chức tín dụng khác, cùng với phát hành giấy tờ có giá dài hạn. Tổng nợ vay chiếm tỷ trọng nhỏ trên tổng nguồn vốn. Tỷ lệ nợ xấu ở mức thấp 1,145%, khả năng trích lập dự phòng tốt. Áp lực thanh toán nợ thấp.', 'Ngân hàng không có hàng tồn kho sản xuất. Tài sản dở dang duy nhất là chi phí xây dựng cơ bản các trụ sở chi nhánh với tổng giá trị nhỏ, không có dấu hiệu đình trệ. Rủi ro thấp.', 3, 'Vietcombank là ngân hàng thương mại cổ phần lớn, có cơ cấu sở hữu nhà nước chi phối (77,1%), hoạt động kinh doanh ổn định với lợi nhuận tăng trưởng 33% so với năm trước. Chất lượng tài sản tốt, nợ xấu thấp, dự phòng đầy đủ. Công tác quản trị rủi ro chặt chẽ, được kiểm toán bởi KPMG với ý kiến chấp nhận toàn phần. Triển vọng đầu tư tích cực.'),
('VCB_2017_consolidated', 'VCB', 2017, 'consolidated', 'Các giao dịch với các bên liên quan chủ yếu là giao dịch tiền gửi/cho vay giữa Vietcombank với NHNNVN (đại diện chủ sở hữu), Bộ Tài chính và Mizuho Bank Ltd. (cổ đông chiến lược nước ngoài 15%). Các giao dịch này thuộc hoạt động kinh doanh ngân hàng bình thường, không có dấu hiệu bất thường hay chuyển giá. Lợi ích của Ban Điều hành, Hội đồng Quản trị và Ban Kiểm soát được khống chế theo quy chế và Nghị quyết Đại hội đồng Cổ đông. Cổ đông Nhà nước sở hữu 77,10% vốn điều lệ.', 'Huy động vốn chủ yếu từ tiền gửi khách hàng (708.520 tỷ VND), tăng mạnh từ 590.451 tỷ VND năm trước. Nợ Chính phủ và NHNNVN tăng đột biến từ 54.151 tỷ lên 171.385 tỷ VND, chủ yếu do tiền gửi thanh toán của Kho bạc Nhà nước tăng từ 42.752 tỷ lên 165.082 tỷ VND. Tỷ lệ nợ xấu (nhóm 3-5) chỉ chiếm 1,14% dư nợ cho vay. Dự phòng rủi ro tín dụng đạt 8.113 tỷ VND, tỷ lệ bao phủ nợ xấu đạt khoảng 131%. Nợ vay phát hành giấy tờ có giá tăng từ 10.286 tỷ lên 18.215 tỷ VND, trong đó trái phiếu dài hạn bằng VND tăng từ 6.000 tỷ lên 11.000 tỷ VND. Cơ cấu nợ lành mạnh với nguồn vốn ngắn hạn chiếm đa số, phù hợp với tính chất kinh doanh ngân hàng.', 'Vietcombank là tổ chức tín dụng, không có hàng tồn kho truyền thống. Rủi ro tài sản tập trung vào chất lượng danh mục cho vay khách hàng với dư nợ 543.434 tỷ VND. Nợ cần chú ý giảm từ 7.420 tỷ xuống 4.783 tỷ VND, nợ có khả năng mất vốn giảm mạnh từ 4.216 tỷ xuống 1.940 tỷ VND. Dự phòng rủi ro tín dụng cụ thể giảm từ 4.712 tỷ xuống 3.996 tỷ VND nhờ xử lý nợ xấu hiệu quả (sử dụng 6.213 tỷ VND từ nguồn dự phòng). Chất lượng tài sản cải thiện rõ rệt so với năm trước.', 3, 'Vietcombank là ngân hàng TMCP lớn nhất Việt Nam do Nhà nước chi phối (77,10% vốn), được KPMG kiểm toán với ý kiến chấp nhận toàn phần. Năm 2017, ngân hàng đạt lợi nhuận trước thuế 11.341 tỷ VND, tăng 32,2% so với năm 2016. Thu nhập lãi thuần tăng mạnh từ 18.533 tỷ lên 21.938 tỷ VND. Tỷ lệ nợ xấu giảm xuống 1,14% với mức dự phòng bao phủ tốt. NIM đạt 2,63%, CASA đạt 28,4%. Cơ cấu cổ đông minh bạch với sự tham gia của Mizuho Bank Ltd. (Nhật Bản) 15%. Vốn chủ sở hữu đạt 52.558 tỷ VND, tăng từ 48.146 tỷ VND. Lãi cơ bản trên cổ phiếu tăng từ 1.517 VND lên 2.103 VND. Sức khỏe tài chính vững mạnh, triển vọng đầu tư tích cực trong dài hạn.'),
('VCB_2016_parent', 'VCB', 2016, 'parent', 'Giao dịch với các bên liên quan chủ yếu là giao dịch tài chính thông thường với Ngân hàng Nhà nước, Bộ Tài chính và các công ty con, quy mô hợp lý, không phát hiện dấu hiệu bất thường.', 'Nợ vay chủ yếu từ Ngân hàng Nhà nước và Bộ Tài chính, không có áp lực trả nợ ngắn hạn lớn. Tỷ lệ nợ trên vốn chủ sở hữu ở mức cao (khoảng 15.7 lần) nhưng đặc thù ngân hàng. Không có dấu hiệu rủi ro thanh khoản.', 'Ngân hàng không có hàng tồn kho sản xuất, chỉ có tài sản xây dựng cơ bản dở dang với giá trị nhỏ so với tổng tài sản, rủi ro thấp.', 3, 'Vietcombank là ngân hàng thương mại cổ phần lớn, có cơ cấu sở hữu Nhà nước chi phối, hoạt động kinh doanh ổn định và tăng trưởng tốt. Ý kiến kiểm toán chấp nhận toàn phần, không có vấn đề về hoạt động liên tục. Quản trị rủi ro tốt, tình hình tài chính lành mạnh.'),
('VCB_2016_consolidated', 'VCB', 2016, 'consolidated', 'Giao dịch với các bên liên quan chủ yếu là với cơ quan quản lý nhà nước (Ngân hàng Nhà nước, Bộ Tài chính), phục vụ hoạt động huy động vốn và thanh toán đặc thù của ngân hàng. Các giao dịch này thuộc nghiệp vụ bình thường, không có dấu hiệu bất thường hay chiếm dụng vốn.', 'Nợ vay bao gồm tiền gửi khách hàng lớn (590.451 tỷ VND) và nợ Chính phủ/NHNN (54.151 tỷ VND), tạo đòn bẩy tài chính cao nhưng đặc thù cho ngành ngân hàng. Áp lực thanh toán ngắn hạn cao do tiền gửi có kỳ hạn ngắn, nhưng được hỗ trợ bởi tài sản thanh khoản tốt. Lãi suất vay không được chi tiết hóa, song với vị thế ngân hàng lớn, chi phí vốn có thể ở mức hợp lý.', 'Hàng tồn kho không tồn tại; thay vào đó là chi phí xây dựng cơ bản dở dang (404 tỷ VND) cho các dự án trụ sở chi nhánh. Không có thông tin về trích lập dự phòng hay tiến độ dự án, nhưng quy mô nhỏ so với tổng tài sản nên rủi ro đọng vốn thấp.', 2, 'Vietcombank là ngân hàng thương mại nhà nước lớn, có cấu trúc tài chính lành mạnh với tỷ lệ nợ xấu thấp (1.5%), dự phòng bao phủ khá (68.4%). Ý kiến kiểm toán chấp nhận toàn phần, không có vấn đề về hoạt động liên tục. Ban điều hành ổn định, quản trị minh bạch. Tuy nhiên, phụ thuộc nhiều vào vốn huy động ngắn hạn và giao dịch với cơ quan nhà nước. Triển vọng kinh doanh tích cực nhờ mạng lưới rộng và thương hiệu mạnh.'),
('VCB_2015_consolidated', 'VCB', 2015, 'consolidated', 'Giao dịch với các bên liên quan chủ yếu là Ngân hàng Nhà nước và Bộ Tài chính với vai trò cơ quan quản lý. Các giao dịch mang tính chất nghiệp vụ ngân hàng thông thường (tiền gửi, cho vay, phát hành giấy tờ có giá). Không phát hiện giao dịch bất thường hay chuyển giá với bên liên quan. Rủi ro bên liên quan ở mức thấp.', 'Tổng nợ phải trả 629.222 tỷ VND, trong đó tiền gửi khách hàng chiếm phần lớn (500.528 tỷ VND). Tỷ lệ nợ/Vốn chủ sở hữu khoảng 13,9 lần, đặc thù của ngành ngân hàng. Nợ ngắn hạn chiếm phần lớn, phù hợp với tính chất huy động ngắn hạn. Dư nợ cho vay khách hàng 387.152 tỷ VND với tỷ lệ nợ xấu (Nhóm 3-5) chỉ 1,84%, cho thấy chất lượng tín dụng tốt. Tỷ lệ dự phòng/NPL đạt 121%, bao phủ đầy đủ rủi ro.', 'Là ngân hàng thương mại, Vietcombank không có hàng tồn kho sản xuất. Chi phí xây dựng cơ bản dở dang 767 tỷ VND tập trung vào các dự án xây dựng trụ sở chi nhánh tại nhiều tỉnh thành. Các dự án này mang tính chất đầu tư hạ tầng nội bộ, không tạo ra rủi ro đọng vốn đáng kể.', 2, 'Vietcombank là ngân hàng thương mại lớn nhất Việt Nam với tổng tài sản 674.395 tỷ VND, có sự tham gia chi phối của Nhà nước (77,1% vốn) và cổ đông chiến lược Mizuho Bank (15%). Báo cáo kiểm toán được phát hành với ý kiến chấp nhận toàn phần, không có vấn đề nghi ngờ về hoạt động liên tục. Chất lượng tín dụng tốt với tỷ lệ nợ xấu chỉ 1,84% và tỷ lệ dự phòng bao phủ 121%. Tỷ lệ an toàn vốn đạt chuẩn Basel. Hoạt động kinh doanh tăng trưởng mạnh với lợi nhuận sau thuế tăng 16,3% so với năm trước. Cơ cấu quản trị minh bạch, hoạt động dưới sự giám sát chặt chẽ của NHNN. Triển vọng đầu tư tích cực.'),
('VCB_2015_parent', 'VCB', 2015, 'parent', 'Các giao dịch với bên liên quan chủ yếu là hoạt động kinh doanh thông thường giữa ngân hàng với các công ty con và cơ quan quản lý, không phát hiện dấu hiệu bất thường hay rủi ro chuyển giá.', 'Nợ vay chủ yếu từ tiền gửi khách hàng, vay từ NHNN và TCTD khác ở mức vừa phải. Tỷ lệ nợ/vốn chủ sở hữu cao do đặc thù ngành, nhưng khả năng thanh khoản được duy trì tốt với tỷ lệ CASA cao.', 'Ngân hàng không có hàng tồn kho, chỉ có chi phí xây dựng cơ bản dở dang cho các trụ sở chi nhánh, tiến độ triển khai bình thường, rủi ro thấp.', 3, 'Vietcombank có tình hình tài chính lành mạnh, lợi nhuận tăng trưởng ổn định, chất lượng tài sản tốt với tỷ lệ nợ xấu thấp, kiểm toán chấp nhận toàn phần và quản trị rủi ro hiệu quả. Đây là ngân hàng thương mại hàng đầu với triển vọng đầu tư tích cực.'),
('TCB_2025_consolidated', 'TCB', 2025, 'consolidated', 'Techcombank có mối quan hệ mật thiết với Tập đoàn Masan và các công ty liên kết. Giao dịch trái phiếu và cho vay với nhóm Masan có giá trị lớn (hàng nghìn tỷ đồng). Các giao dịch này nằm trong hoạt động kinh doanh thông thường nhưng cần được giám sát chặt chẽ để tránh xung đột lợi ích. Tiền gửi từ ban lãnh đạo và cổ đông lớn cũng đáng lưu ý.', 'Cơ cấu nợ chủ yếu từ tiền gửi khách hàng (618,911 tỷ VNĐ) và phát hành giấy tờ có giá (215,330 tỷ VNĐ). Tỷ lệ nợ/vốn chủ sở hữu là 5.64 lần (1,012,842,695/179,501,442), áp lực trả nợ lớn. Lãi suất tiền gửi kỳ hạn VND lên đến 7.70%/năm, tạo áp lực chi phí vốn. Tuy nhiên, ngân hàng có thanh khoản tốt với tiền và tương đương tiền đạt 191,827 tỷ VNĐ.', 'Là ngân hàng thương mại, Techcombank không có hàng tồn kho vật chất. Rủi ro chủ yếu đến từ chất lượng danh mục cho vay (cho vay khách hàng 767,617 tỷ VNĐ) và chứng khoán đầu tư (145,526 tỷ VNĐ). Tỷ lệ nợ xấu (nhóm 3-5) là 1.07% trên tổng dư nợ cho vay, mức kiểm soát được.', 3, 'Techcombank là ngân hàng lớn với tổng tài sản hơn 1.19 triệu tỷ VNĐ. Kết quả kinh doanh tăng trưởng tốt (lợi nhuận sau thuế tăng 19.28%). Cơ cấu tài sản lành mạnh, thanh khoản dồi dào. Tuy nhiên, nợ vay lớn với lãi suất cao tạo áp lực chi phí vốn. Giao dịch với bên liên quan (Masan Group) cần được giám sát. Ý kiến kiểm toán là chấp nhận toàn phần, không có vấn đề về hoạt động liên tục. Triển vọng tích cực trong trung hạn.'),
('TCB_2025_parent', 'TCB', 2025, 'parent', 'Ngân hàng có các giao dịch lớn với bên liên quan, đặc biệt là nhóm Masan (tiền gửi, cho vay, phái sinh) và các công ty con. Các giao dịch này nằm trong hoạt động kinh doanh thông thường và được thuyết minh đầy đủ, nhưng mức độ tập trung có thể tạo rủi ro nếu đối tác gặp khó khăn.', 'Tỷ lệ nợ/vốn chủ sở hữu ở mức cao (6.76 lần) nhưng phù hợp với ngành ngân hàng. Nguồn vốn huy động chủ yếu từ tiền gửi khách hàng (623,8 nghìn tỷ), chi phí lãi 27.87 nghìn tỷ, khả năng sinh lời tốt. Rủi ro thanh khoản được quản lý chặt chẽ.', NULL, 4, 'Techcombank là ngân hàng thương mại hàng đầu với kết quả kinh doanh ổn định, lợi nhuận sau thuế tăng 3.28% lên 20.305 tỷ đồng. Chất lượng tài sản tốt với tỷ lệ nợ xấu 1.13%, dự phòng đầy đủ. Hệ thống quản trị rủi ro chặt chẽ, được kiểm toán bởi EY với ý kiến chấp nhận toàn phần. Triển vọng tích cực.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('TCB_2022_parent', 'TCB', 2022, 'parent', 'Các giao dịch với bên liên quan chủ yếu là cho vay và nhận tiền gửi từ các công ty con, cổ đông lớn (Tập đoàn Masan) và các bên liên quan khác. Quy mô giao dịch lớn nhưng nằm trong hoạt động kinh doanh thông thường của ngân hàng. Chưa phát hiện dấu hiệu bất thường. Tuy nhiên, cần giám sát chặt các khoản cho vay với công ty con và các bên liên quan để đảm bảo tính độc lập.', 'Ngân hàng có tổng nợ phải trả cao hơn nhiều lần vốn chủ sở hữu (tỷ lệ 5.6 lần), đặc trưng của ngân hàng thương mại. Cơ cấu nợ chủ yếu là tiền gửi khách hàng (63% tổng nợ) và vay các tổ chức tín dụng. Chi phí lãi vay tăng mạnh so với năm trước nhưng vẫn trong tầm kiểm soát do tăng trưởng tín dụng. Rủi ro thanh khoản thấp nhờ lượng tiền gửi ổn định.', 'Ngân hàng thương mại không có hàng tồn kho, do đó rủi ro hàng tồn kho là không đáng kể.', 3, 'Techcombank duy trì vị thế là ngân hàng thương mại cổ phần hàng đầu với tăng trưởng tín dụng ổn định, chất lượng tài sản được kiểm soát (tỷ lệ nợ xấu thấp 0.74%). Ý kiến kiểm toán chấp nhận toàn phần. Hoạt động kinh doanh cốt lõi hiệu quả với NIM ~4.7%. Rủi ro từ các bên liên quan ở mức trung bình. Nhìn chung, sức khỏe tài chính tốt, triển vọng khả quan trong trung hạn.'),
('TCB_2022_consolidated', 'TCB', 2022, 'consolidated', 'Giao dịch với các bên liên quan, đặc biệt nhóm Công ty Cổ phần Tập đoàn Masan, có quy mô lớn (cho vay, mua bán trái phiếu, tiền gửi). Tuy nhiên, các giao dịch này thuộc hoạt động kinh doanh thông thường và được thực hiện theo điều kiện thị trường. Ngân hàng đã công bố chi tiết theo quy định.', 'Nợ vay tập trung vào tiền gửi của khách hàng (chiếm tỷ trọng lớn) và vay từ các tổ chức tín dụng khác. Ngân hàng có tỷ lệ nợ trên vốn chủ sở hữu (585.607.578 / 113.424.966 ≈ 5.16 lần) cao đặc thù ngành ngân hàng. Áp lực thanh toán ngắn hạn được quản lý qua bảng khe hở lãi suất.', 'Ngân hàng không có hàng tồn kho vật lý. Tài sản cố định và bất động sản đầu tư chiếm tỷ trọng nhỏ trong tổng tài sản, rủi ro thấp.', 4, 'Techcombank là ngân hàng thương mại cổ phần lớn, có kết quả kinh doanh tích cực với lợi nhuận sau thuế tăng 10.97% so với năm trước. Cơ cấu tài sản lành mạnh, tỷ lệ nợ xấu được kiểm soát ở mức thấp (0.72%), tỷ lệ dự phòng bao phủ nợ xấu cao (157.3%). Ban lãnh đạo ổn định và có kinh nghiệm. Tuy nhiên, cần theo dõi rủi ro từ tập trung tín dụng vào một số nhóm khách hàng liên quan.'),
('TCB_2021_parent', 'TCB', 2021, 'parent', 'Ngân hàng có nhiều giao dịch với các bên liên quan như công ty con và nhóm Masan. Các giao dịch cho vay và tiền gửi được thực hiện theo điều kiện thị trường, nhưng quy mô lớn cần được giám sát chặt chẽ. Rủi ro ở mức trung bình.', 'Nợ vay chủ yếu từ các tổ chức tín dụng và phát hành trái phiếu với lãi suất cạnh tranh. Tỷ lệ nợ trên vốn chủ sở hữu khoảng 5,5 lần, phù hợp với đặc thù ngân hàng. Áp lực thanh khoản ngắn hạn được kiểm soát tốt.', 'Ngân hàng không có hàng tồn kho sản xuất, do đó rủi ro hàng tồn kho không đáng kể.', 3, 'Techcombank là ngân hàng thương mại hàng đầu với kết quả kinh doanh ấn tượng năm 2021: thu nhập lãi thuần tăng 41%, lợi nhuận sau thuế tăng 47%. Chất lượng tài sản tốt với tỷ lệ nợ xấu chỉ 0,69%. Ngân hàng có nền tảng vốn vững chắc, quản trị rủi ro chuyên nghiệp. Triển vọng tích cực nhờ chiến lược số hóa và nền kinh tế phục hồi.'),
('TCB_2021_consolidated', 'TCB', 2021, 'consolidated', 'Ngân hàng có mối quan hệ mật thiết với Masan Group - cổ đông lớn có thành viên HĐQT trong Hội đồng Quản trị Ngân hàng. Tổng dư nợ cho vay và trái phiếu với Masan và các công ty liên quan lên tới hàng nghìn tỷ đồng. Ngoài ra còn có tiền gửi lớn từ nhóm công ty liên quan Masan (4,209 tỷ đồng), Công ty Dịch vụ Di động trực tuyến (950 tỷ đồng), thành viên HĐQT/Ban lãnh đạo (1,033 tỷ đồng). Các giao dịch này thuộc hoạt động kinh doanh thông thường nhưng quy mô lớn, cần được giám sát chặt chẽ. Đặc biệt khoản phải thu từ hợp đồng bán nợ 449,939 triệu đồng đã được trích lập dự phòng 100% vào nhóm nợ có khả năng mất vốn, cho thấy có rủi ro tín dụng nhất định với bên liên quan.', 'Nợ vay chủ yếu từ tiền gửi khách hàng (314,752 tỷ đồng) là nguồn vốn ổn định và chi phí thấp. Nợ vay từ TCTD khác (66,852 tỷ đồng) với lãi suất 0.70%-8.00%/năm. Phát hành giấy tờ có giá 33,679 tỷ đồng với lãi suất 3.50%-8.45%/năm. Nợ xấu nhóm 3-5 chỉ chiếm 0.66% tổng dư nợ cho vay - mức rất thấp so với trung bình ngành. Tỷ lệ nợ/VCSH ở mức 5.1 lần phù hợp với đặc thù ngân hàng thương mại. Dự phòng rủi ro cho vay đạt 3,735 tỷ đồng, tỷ lệ bao phủ nợ xấu nhóm 3-5 khoảng 49.5%. Áp lực thanh toán ngắn hạn được quản lý tốt với lượng tiền gửi không kỳ hạn lớn (147,861 tỷ đồng).', 'Ngân hàng không có hàng tồn kho truyền thống. Tài sản bất động sản đầu tư chủ yếu là Tòa nhà Techcombank với giá trị còn lại 1,088,924 triệu đồng, nguyên giá 1,435,699 triệu đồng, khấu hao đều đặn. Tài sản cố định hữu hình tăng mạnh từ 1,470,942 triệu lên 3,628,732 triệu đồng do đầu tư vào nhà cửa, vật kiến trúc và máy móc thiết bị. Không có dấu hiệu đọng vốn hay dự án dở dang kéo dài. Rủi ro tài sản cố định ở mức thấp.', 4, 'Techcombank đạt kết quả kinh doanh xuất sắc năm 2021 với lợi nhuận sau thuế 18,415 tỷ đồng, tăng 46.36% so với năm 2020. Tổng tài sản đạt 568,728 tỷ đồng, tăng 29.4%. Tỷ lệ nợ xấu nhóm 3-5 chỉ 0.66% - mức rất thấp trong ngành ngân hàng. Thu nhập lãi thuần đạt 26,698 tỷ đồng, tăng 42.4% nhờ NIM mở rộng. Tuy nhiên, cần lưu ý: (1) Mối quan hệ mật thiết với Masan Group tạo ra tập trung rủi ro tín dụng, (2) Khoản phải thu từ hợp đồng bán nợ 450 tỷ đồng đã mất vốn 100%, (3) Chi phí dự phòng rủi ro tín dụng tăng nhẹ 53 tỷ đồng so với năm trước, (4) Việc áp dụng Thông tư 03 về cơ cấu nợ COVID-19 có thể che giấu nợ xấu thực tế. Ý kiến kiểm toán là chấp nhận toàn phần, không có cảnh báo về khả năng hoạt động liên tục. Triển vọng kinh doanh tích cực nhờ nền tảng khách hàng đa dạng, CASA cao (47%) và chiến lược số hóa mạnh mẽ.'),
('TCB_2020_parent', 'TCB', 2020, 'parent', 'Ngân hàng có các giao dịch đáng kể với công ty con (Chứng khoán Kỹ thương, Quản lý nợ) và với Tập đoàn Masan (bên liên quan thông qua HĐQT). Các khoản cho vay và tiền gửi với các bên này nằm trong hoạt động kinh doanh thông thường, với lãi suất thị trường và không có dấu hiệu bất thường. Tuy nhiên, khoản cho vay lớn cho Masan (1.921 tỷ) và các giao dịch phái sinh với công ty con chứng khoán cần được theo dõi chặt chẽ.', 'Tổng nợ phải trả là 363.998 tỷ VND, vốn chủ sở hữu 68.721 tỷ, tỷ lệ nợ/vốn chủ sở hữu khoảng 5,3 lần, phù hợp với đặc thù ngân hàng. Chi phí lãi vay thấp nhờ huy động tiền gửi không kỳ hạn lớn (CASA 44,6%). Phát hành trái phiếu có lãi suất cạnh tranh. Áp lực thanh khoản thấp do kỳ hạn nợ dài và tài sản thanh khoản cao.', 'Ngân hàng không có hàng tồn kho hoặc dự án xây dựng dở dang đáng kể, rủi ro không đáng kể.', 4, 'Techcombank là ngân hàng thương mại cổ phần hàng đầu tại Việt Nam với quy mô tài sản lớn, tỷ lệ nợ xấu thấp (0,47%) và khả năng sinh lời tốt (ROE ước tính cao). Cấu trúc nguồn vốn ổn định với CASA cao. Các giao dịch với bên liên quan được công bố đầy đủ, không phát hiện dấu hiệu rủi ro trọng yếu. Ý kiến kiểm toán chấp nhận toàn phần. Triển vọng kinh doanh tích cực trong bối cảnh phục hồi kinh tế sau Covid-19.'),
('TCB_2023_parent', 'TCB', 2023, 'parent', '[Xiaomi]: Ngân hàng có giao dịch cho vay và tiền gửi đáng kể với các công ty trong Tập đoàn Masan (như Công ty TNHH Khai thác Chế biến Khoáng sản Núi Pháo, Công ty TNHH Vonfram Masan) và Tập đoàn One Mount. Tuy nhiên, các khoản vay này có lãi suất trong khoảng thị trường và được thực hiện theo đúng chính sách tín dụng chung. Cần giám sát rủi ro tập trung tín dụng vào một số nhóm doanh nghiệp liên quan lớn.
[DeepSeek]: Ngân hàng có giao dịch đáng kể với các bên liên quan như nhóm Masan, One Mount và các công ty con. Các khoản cho vay và tiền gửi có kỳ hạn với các bên liên quan chiếm tỷ trọng lớn, nhưng đều có tài sản đảm bảo và lãi suất thị trường. Tuy nhiên, cần theo dõi rủi ro tập trung tín dụng vào nhóm cổ đông lớn.', '[Xiaomi]: Nợ vay và tiền gửi của khách hàng chiếm tỷ trọng lớn (hơn 60% tổng tài sản), đặc biệt tiền gửi không kỳ hạn (CASA) chiếm tỷ trọng đáng kể. Ngân hàng phát hành trái phiếu và chứng chỉ tiền gửi với lãi suất từ 2% - 8,64%. Cơ cấu nợ chủ yếu dựa vào huy động từ dân cư và tổ chức, rủi ro thanh khoản được quản lý qua các tỷ lệ an toàn của NHNN.
[DeepSeek]: Ngân hàng có tỷ lệ nợ/vốn chủ sở hữu cao (khoảng 6 lần) nhưng phù hợp với đặc thù ngân hàng. Nợ vay tập trung vào tiền gửi khách hàng (457.722 tỷ) và vay liên ngân hàng (139.424 tỷ). Áp lực chi phí lãi vay tăng do lãi suất cao, nhưng ngân hàng duy trì thanh khoản tốt với CASA 38%.', '[Xiaomi]: Ngân hàng không có hàng tồn kho truyền thống. Khoản mục ''Chi phí xây dựng cơ bản dở dang'' ghi nhận các chi phí đầu tư vào tài sản cố định, không phải hàng hóa kinh doanh, nên rủi ro tồn kho không áp dụng.
[DeepSeek]: Ngân hàng không có hàng tồn kho lớn. Chi phí xây dựng cơ bản dở dang (3.965 tỷ) liên quan đến trụ sở, không phải dự án bất động sản, rủi ro thấp.', 4, '[Đánh giá từ Xiaomi]: Techcombank là một ngân hàng thương mại lớn và có uy tín tại Việt Nam. Báo cáo kiểm toán phát hành ý kiến chấp nhận toàn phần, không có vấn đề về hoạt động liên tục. Ngân hàng có mối quan hệ kinh doanh chặt chẽ với các tập đoàn lớn như Masan và One Mount, nhưng các giao dịch này được thực hiện trong khuôn khổ chính sách tín dụng và có giám sát. Cơ cấu tài sản và nợ phải trả có tính thanh khoản tốt, được quản lý rủi ro theo các chuẩn mực quốc tế. Tuy nhiên, cần lưu ý đến rủi ro tập trung tín dụng và biến động lãi suất.

[Đánh giá từ DeepSeek]: Techcombank là ngân hàng TMCP lớn hàng đầu Việt Nam, có nền tảng vốn mạnh (vốn điều lệ 35.225 tỷ), quản trị rủi ro tốt. Năm 2023 lợi nhuận sau thuế 14.994 tỷ, giảm 16% do chi phí dự phòng tăng. Chất lượng tài sản ổn định với tỷ lệ nợ xấu thấp (1.20%). Ngân hàng có lợi thế cạnh tranh trong ngân hàng số và mảng bán lẻ. Triển vọng trung hạn khả quan.'),
('TCB_2023_consolidated', 'TCB', 2023, 'consolidated', '[Xiaomi]: Các giao dịch với bên liên quan chủ yếu tập trung vào nhóm Masan và các công ty thành viên (như Núi Pháo, Masan High-Tech, WinEco, One Mount) với quy mô lớn, bao gồm cho vay, mua trái phiếu và tiền gửi có kỳ hạn. Các giao dịch này thuộc phạm vi hoạt động kinh doanh thông thường của ngân hàng và được thực hiện theo điều kiện thị trường, chưa phát hiện dấu hiệu bất thường về giá hay điều kiện ưu đãi vượt trội. Tuy nhiên, mức độ tập trung tín dụng vào một nhóm liên quan là đáng lưu ý.
[DeepSeek]: Các giao dịch bên liên quan có quy mô lớn, tập trung vào các khoản cho vay và đầu tư trái phiếu với các công ty trong hệ sinh thái Masan và One Mount. Mặc dù được công bố đầy đủ, nhưng mức độ tập trung tín dụng vào các bên liên quan có thể tiềm ẩn rủi ro nếu các công ty này gặp khó khăn. Cần theo dõi chặt chẽ.', '[Xiaomi]: Nợ phải trả chiếm tỷ trọng cao với tổng nợ/VCSH khoảng 5.45 lần, chủ yếu từ tiền gửi không kỳ hạn và phát hành giấy tờ có giá. Áp lực trả nợ ngắn hạn lớn khi tiền gửi không kỳ hạn chiếm 38% tổng tiền gửi khách hàng. Lãi suất huy động có xu hướng giảm so với năm trước, giúp giảm bớt chi phí vốn. Ngân hàng duy trì đa dạng hóa nguồn huy động từ khách hàng tổ chức và cá nhân.
[DeepSeek]: Tổng nợ phải trả ở mức cao (717.866 tỷ VND), chủ yếu là tiền gửi khách hàng và phát hành giấy tờ có giá. Tỷ lệ nợ/vốn chủ sở hữu xấp xỉ 5,45 lần, phù hợp với đặc thù ngân hàng. Cấu trúc nợ có kỳ hạn đa dạng, lãi suất thị trường. Rủi ro thanh khoản được quản lý tốt qua các chỉ số an toàn.', '[Xiaomi]: Ngân hàng không có hàng tồn kho vật lý. Rủi ro tập trung vào danh mục chứng khoán đầu tư, trong đó có 498.753 triệu đồng chứng khoán giảm giá tại thời điểm cuối năm, chủ yếu là trái phiếu doanh nghiệp chưa niêm yết. Dự phòng rủi ro tín dụng cho chứng khoán đầu tư ở mức hợp lý.
[DeepSeek]: Ngân hàng không có hàng tồn kho sản xuất. Chi phí xây dựng cơ bản dở dang chủ yếu liên quan đến đầu tư tài sản cố định. Rủi ro đọng vốn thấp do các dự án triển khai đúng kế hoạch.', 4, '[Đánh giá từ Xiaomi]: Techcombank là ngân hàng thương mại cổ phần lớn, có mạng lưới rộng và hệ sinh thái đa dạng. Kết quả kinh doanh năm 2023 giảm 10.99% so với năm trước do thu nhập lãi thuần giảm và chi phí dự phòng rủi ro tín dụng tăng mạnh. Tuy nhiên, tỷ lệ an toàn vốn (CAR) được duy trì tốt, nợ xấu kiểm soát ở mức thấp (0.27% trên dư nợ cho vay). Ngân hàng có mối quan hệ mật thiết với nhóm Masan, cần theo dõi rủi ro tập trung tín dụng. Triển vọng trung hạn phụ thuộc vào diễn biến lãi suất và chất lượng tài sản.

[Đánh giá từ DeepSeek]: Techcombank năm 2023 đạt lợi nhuận sau thuế 18.190 tỷ VND, giảm nhẹ so với năm trước do chi phí dự phòng tăng. Ngân hàng duy trì chất lượng tài sản tốt với tỷ lệ nợ xấu thấp (0,27% nợ có khả năng mất vốn). Kiểm toán độc lập đưa ra ý kiến chấp nhận toàn phần. Các giao dịch bên liên quan có quy mô đáng kể nhưng nằm trong quản lý rủi ro. Nhìn chung, tình hình tài chính ổn định, triển vọng khả quan.'),
('TCB_2019_consolidated', 'TCB', 2019, 'consolidated', 'Giao dịch với các bên liên quan bao gồm cho vay và nhận tiền gửi quy mô lớn (Công ty Cổ phần Cửa sổ nhựa Châu Âu, Công ty TNHH Khai thác Chế biến khoáng sản Núi Pháo, và Tập đoàn Masan) cùng với tiền gửi của thành viên HĐQT. Các giao dịch này nằm trong hoạt động ngân hàng thông thường nhưng quy mô đáng kể, tiềm ẩn rủi ro tập trung và xung đột lợi ích.', 'Tỷ lệ nợ/vốn chủ sở hữu cao (~5.2 lần) đặc thù ngành ngân hàng. Nợ vay chủ yếu từ các TCTD và phát hành trái phiếu với lãi suất cạnh tranh. Áp lực thanh khoản được quản lý thông qua danh mục cho vay và huy động đa dạng. Rủi ro lãi suất được kiểm soát qua chênh lệch lãi suất dương.', 'Ngân hàng không có hàng tồn kho. Rủi ro thấp.', 3, 'Ngân hàng TMCP Kỹ thương Việt Nam (Techcombank) có tình hình tài chính lành mạnh, ý kiến kiểm toán chấp nhận toàn phần từ Ernst & Young. Hoạt động kinh doanh tăng trưởng tốt với lợi nhuận trước thuế đạt 12.838 tỷ đồng (+20% so với năm trước). Chất lượng tài sản được kiểm soát với tỷ lệ nợ xấu thấp 1,33% và tỷ lệ bao phủ dự phòng 41,1%. Cơ cấu vốn ổn định, thanh khoản dồi dào. Quản trị doanh nghiệp tốt, rủi ro bên liên quan ở mức trung bình.'),
('TCB_2020_consolidated', 'TCB', 2020, 'consolidated', 'Giao dịch với bên liên quan tập trung vào Tập đoàn Masan (cho vay 1.921 tỷ VND, trái phiếu 738 tỷ VND, dịch vụ 445 tỷ VND) và các công ty liên quan đến cổ đông/ban lãnh đạo (One Mount, One Distribution, Cửa sổ nhựa Châu Âu). Các giao dịch này về cơ bản là nghiệp vụ ngân hàng thông thường (cho vay, nhận tiền gửi, phát hành bảo lãnh). Thành viên HĐQT, Ban Kiểm soát, Ban Lãnh đạo gửi tiền tại Techcombank với số dư 818 tỷ VND - đây là hoạt động bình thường. Thu nhập lãi cho vay từ Masan Group đạt 103 tỷ VND, phí dịch vụ 445 tỷ VND cho thấy quan hệ kinh doanh đa dạng. Chưa phát hiện dấu hiệu bất thường hay chuyển giá.', 'Techcombank có cơ cấu nguồn vốn lành mạnh với tiền gửi khách hàng 277.459 tỷ VND (tăng 20% so với năm trước), trong đó tiền gửi không kỳ hạn chiếm 44,4% (CASA cao). Nợ vay từ TCTD khác giảm từ 61.267 tỷ xuống 47.485 tỷ VND, phát hành giấy tờ có giá tăng từ 17.461 tỷ lên 27.900 tỷ VND. Nợ xấu (Nhóm 3-5) chiếm 0,47% dư nợ cho vay, cải thiện đáng kể so với mức 1,33% năm 2019. Dự phòng cụ thể chỉ còn 334.775 triệu VND (giảm mạnh từ 1.265.078 triệu VND) do xử lý nợ xấu hiệu quả. Tỷ lệ nợ/VCSH ở mức 4,89 lần đặc thù ngân hàng thương mại, phù hợp quy định NHNN.', 'Là ngân hàng thương mại, Techcombank không có hàng tồn kho truyền thống. Tuy nhiên, dư nợ cho vay bất động sản chiếm 32,92% tổng cho vay (91.361 tỷ VND), tăng mạnh từ 21,85% năm trước cho thấy mức độ tập trung cao vào ngành bất động sản. Bất động sản đầu tư cho thuê trị giá 1.125 tỷ VND, tạm ứng xây dựng 2.891 tỷ VND cho trụ sở văn phòng. Rủi ro chính là tập trung tín dụng vào bất động sản - ngành nhạy cảm với chu kỳ kinh tế và chính sách tín dụng.', 3, 'Techcombank đạt kết quả kinh doanh xuất sắc năm 2020 với lợi nhuận sau thuế 12.582 tỷ VND (tăng 23%), thu nhập lãi thuần 18.751 tỷ VND (tăng 31,4%). Kiểm toán viên KPMG đưa ra ý kiến chấp nhận toàn phần. Cơ cấu quản trị minh bạch với HĐQT đa quốc gia (Chủ tịch Hồ Hùng Anh, Tổng Giám đốc Jens Lottner người Đức). Tỷ lệ nợ xấu cải thiện mạnh từ 1,33% xuống 0,47%. NIM đạt 4,56%, CASA 44,4% - đều ở mức cao trong ngành. Giao dịch bên liên quan với Masan Group lớn nhưng minh bạch. Điểm rủi ro thấp do ý kiến kiểm toán sạch, quản trị tốt, nợ xấu thấp, lợi nhuận tăng trưởng mạnh.'),
('TCB_2019_parent', 'TCB', 2019, 'parent', 'Ngân hàng có giao dịch với nhiều bên liên quan phức tạp, bao gồm các công ty liên quan đến cổ đông lớn, thành viên HĐQT và công ty con. Các giao dịch chủ yếu là cho vay và tiền gửi với giá trị lớn, tập trung ở một số đối tác như Công ty TNHH Khai thác Chế biến khoáng sản Núi Pháo (hơn 1 nghìn tỷ) và Công ty Cổ phần Tập đoàn Masan (hơn 1.4 nghìn tỷ tiền gửi). Mặc dù các giao dịch được thuyết minh, nhưng mức độ tập trung cao và mối quan hệ phức tạp có thể tiềm ẩn rủi ro về xung đột lợi ích và chất lượng tín dụng nếu các bên liên quan gặp khó khăn tài chính.', 'Cơ cấu nợ của Ngân hàng chủ yếu dựa trên tiền gửi của khách hàng (233,054 tỷ đồng) và phát hành giấy tờ có giá (16,807 tỷ đồng). Nợ ngắn hạn chiếm tỷ trọng lớn, tạo áp lực thanh khoản liên tục. Ngân hàng phụ thuộc vào việc huy động vốn liên tục từ thị trường. Tuy nhiên, tỷ lệ nợ xấu (Nhóm 5) chỉ ở mức 1.11% và dự phòng cho vay đạt 113.77% nợ xấu, cho thấy khả năng quản trị rủi ro tín dụng tương đối tốt. Lãi suất huy động đầu vào dao động trong khoảng rộng, chịu ảnh hưởng bởi biến động thị trường.', 'Ngân hàng không có hàng tồn kho theo nghĩa truyền thống. Rủi ro tài sản chính đến từ danh mục cho vay và chứng khoán đầu tư. Ngân hàng đã trích lập dự phòng rủi ro tín dụng đầy đủ (2,906 tỷ đồng) và đánh giá giảm giá chứng khoán đầu tư. Tuy nhiên, bất động sản nhận thế chấp chiếm tỷ trọng lớn (305,845 tỷ đồng), có thể chịu rủi ro từ biến động thị trường bất động sản.', 5, 'Ngân hàng TMCP Kỹ thương Việt Nam (Techcombank) kết thúc năm 2019 với kết quả kinh doanh tích cực, lợi nhuận trước thuế tăng 10.41% so với năm trước. Tổng tài sản đạt gần 380 nghìn tỷ đồng, tăng trưởng mạnh. Tuy nhiên, ngân hàng đối mặt với một số rủi ro: (1) Cơ cấu tài sản - nợ phải trả có thể chịu áp lực thanh khoản do huy động ngắn hạn để tài trợ cho tài sản dài hạn; (2) Giao dịch với bên liên quan phức tạp và giá trị lớn, yêu cầu giám sát chặt chẽ; (3) Phụ thuộc lớn vào huy động vốn từ khách hàng và thị trường. Ban điều hành nhất quán và có kinh nghiệm, công tác quản trị rủi ro được đánh giá ở mức trung bình. Triển vọng phụ thuộc vào môi trường lãi suất và chất lượng tín dụng.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('TCB_2018_parent', 'TCB', 2018, 'parent', 'Ngân hàng có các công ty con chuyên ngành nhưng không phát hiện giao dịch bất thường trong năm. Rủi ro thấp.', 'Nợ phải trả ở mức cao so với vốn chủ sở hữu (tỷ lệ 5.46 lần) nhưng đặc thù ngân hàng. Các khoản vay chủ yếu từ các TCTD và phát hành giấy tờ có giá. Không có dấu hiệu áp lực thanh toán đáng kể.', 'Không có hàng tồn kho, không rủi ro.', 2, 'Ngân hàng có quy mô lớn, tăng trưởng tốt, được kiểm toán bởi EY với ý kiến chấp nhận toàn phần. Cơ cấu sở hữu rõ ràng, ban điều hành ổn định. Tình hình tài chính lành mạnh, triển vọng tích cực.'),
('TCB_2018_consolidated', 'TCB', 2018, 'consolidated', 'Không có thông tin chi tiết về giao dịch với bên liên quan trong báo cáo. Rủi ro được đánh giá là thấp do không có bằng chứng về giao dịch bất thường.', 'Nợ phải trả chiếm tỷ trọng cao (83.9% tổng tài sản), chủ yếu từ tiền gửi khách hàng và vay các tổ chức tín dụng. Áp lực thanh khoản và chi phí lãi vay lớn, tuy nhiên ngân hàng có cấu trúc vốn chủ sở hữu ổn định.', 'Ngân hàng không có hàng tồn kho vật chất truyền thống. Rủi ro liên quan đến tài sản tài chính và cho vay được quản lý thông qua dự phòng rủi ro tín dụng.', 2, 'Ngân hàng có cấu trúc tài chính lành mạnh với vốn chủ sở hữu tăng mạnh, lợi nhuận tăng trưởng tốt. Ý kiến kiểm toán là chấp nhận toàn phần, không có vấn đề về hoạt động liên tục. Tuy nhiên, nợ phải trả lớn đòi hỏi quản lý thanh khoản chặt chẽ.'),
('TCB_2017_parent', 'TCB', 2017, 'parent', 'Không có giao dịch trọng yếu với các bên liên quan được trình bày trong báo cáo. Rủi ro thấp.', 'Ngân hàng có tổng nợ phải trả lớn (243,384 tỷ đồng) chủ yếu từ tiền gửi khách hàng (171,511 tỷ đồng) và vay các TCTD khác (46,887 tỷ đồng). Tỷ lệ nợ/vốn chủ sở hữu ở mức cao (9.75 lần) nhưng phù hợp với đặc thù ngân hàng. Chi phí lãi vay và phát hành giấy tờ có giá ở mức quản lý được.', 'Ngân hàng thương mại không có hàng tồn kho sản xuất. Rủi ro hàng tồn kho không đáng kể.', 3, 'Ngân hàng TMCP Kỹ thương Việt Nam năm 2017 có báo cáo tài chính được kiểm toán bởi Ernst & Young với ý kiến chấp nhận toàn phần. Lợi nhuận sau thuế tăng mạnh lên 5,678 tỷ đồng. Chất lượng tín dụng duy trì tốt với tỷ lệ nợ xấu ở mức thấp (0.97% nợ có khả năng mất vốn). Ngân hàng có cơ cấu vốn ổn định, vốn điều lệ tăng lên nhờ phát hành cổ phiếu và chuyển đổi trái phiếu. Hoạt động kinh doanh cốt lõi hiệu quả. Quản trị rủi ro được chú trọng. Điểm yếu là tỷ lệ nợ/vốn chủ sở hữu cao nhưng phù hợp lĩnh vực ngân hàng. Nhìn chung, sức khỏe tài chính tốt, triển vọng khả quan.'),
('TCB_2017_consolidated', 'TCB', 2017, 'consolidated', 'Ngân hàng có nhiều giao dịch với các bên liên quan, đặc biệt là các công ty có thành viên Hội đồng Quản trị. Các giao dịch chủ yếu là cho vay và tiền gửi với quy mô đáng kể (lên đến hàng nghìn tỷ đồng). Tuy nhiên, các giao dịch này nằm trong hoạt động ngân hàng thông thường và được công khai minh bạch trong thuyết minh báo cáo tài chính.', 'Nợ phải trả của ngân hàng chiếm tỷ trọng lớn (hơn 90% tổng tài sản), chủ yếu là tiền gửi khách hàng và vay từ các TCTD khác. Áp lực thanh khoản được kiểm soát tốt với tỷ lệ dự trữ bắt buộc đạt yêu cầu. Tuy nhiên, ngân hàng cần theo dõi sát diễn biến lãi suất và khả năng huy động vốn trong bối cảnh cạnh tranh.', 'Ngân hàng không có hàng tồn kho vật chất. Bất động sản đầu tư (Tòa nhà Techcombank) có giá trị lớn nhưng được khấu hao đều đặn và không có dấu hiệu giảm giá trị. Rủi ro từ bất động sản đầu tư không đáng kể.', 5, 'Ngân hàng có kết quả kinh doanh tăng trưởng mạnh trong năm 2017 với lợi nhuận sau thuế đạt 6,445 tỷ đồng, tăng 104% so với năm trước. Cơ cấu tài sản và nguồn vốn ổn định, tỷ lệ an toàn vốn đạt chuẩn. Tuy nhiên, ngân hàng cần chú ý đến rủi ro từ các giao dịch bên liên quan và quản lý nợ xấu (tỷ lệ nợ xấu 0.97%). Triển vọng phát triển khả quan nhờ mạng lưới rộng và nền tảng công nghệ hiện đại.'),
('CTG_2025_consolidated', 'CTG', 2025, 'consolidated', 'Các giao dịch với bên liên quan chủ yếu mang tính chất nghiệp vụ ngân hàng thông thường: (1) Tiền gửi và vay NHNN là nghiệp vụ tái cấp vốn bắt buộc theo quy định; (2) Giao dịch với The Bank of Tokyo-Mitsubishi UFJ - cổ đông chiến lược - quy mô nhỏ (doanh thu lãi tiền gửi chỉ 23 triệu đồng, chi phí lãi vay 1.492 triệu đồng năm 2025); (3) Giao dịch với Indovina (liên doanh 50%) có số dư tiền gửi qua lại lớn (12.334 tỷ VNĐ) nhưng là hoạt động liên ngân hàng bình thường; (4) Các khoản vay của thành viên HĐQT, BKS, Ban Điều hành tại Ngân hàng đạt 249.504 triệu đồng, giảm so với năm trước (138.214 triệu đồng). Chưa phát hiện dấu hiệu chuyển giá, rút ruột hay giao dịch bất thường có lợi cho bên liên quan.', 'Cơ cấu nợ của VietinBank phụ thuộc lớn vào tiền gửi khách hàng (1.793.732 tỷ VNĐ, chiếm 69% tổng nợ) và phát hành giấy tờ có giá (174.030 tỷ VNĐ). Nợ vay NHNN và Kho bạc đạt 144.592 tỷ VNĐ. Tỷ lệ nợ/VCSH là 14.4 lần - đặc trưng cho ngành ngân hàng. Dư nợ cho vay khách hàng tăng 15.7% so với năm trước (1.992.272 tỷ VNĐ). Nợ quá hạn nhóm 5 tăng mạnh từ 13.711 tỷ lên 19.847 tỷ VNĐ, trong khi nợ nhóm 2 giảm từ 22.899 tỷ xuống 17.346 tỷ VNĐ cho thấy cải thiện chất lượng nợ trung hạn. Dự phòng rủi ro cho vay đạt 34.810 tỷ VNĐ với tỷ lệ dự phòng/nợ xấu (nhóm 3-5) đạt 159%, đảm bảo bù đắp rủi ro tín dụng. Lãi suất huy động chủ yếu biến động theo thị trường NHNN quy định.', 'Hàng tồn kho và tài sản dở dang của VietinBank không phải là hoạt động kinh doanh cốt lõi. Chi phí xây dựng cơ bản dở dang đạt 5.593 tỷ VNĐ (giảm nhẹ từ 5.678 tỷ VNĐ năm 2024), tập trung vào dự án Tòa nhà Trụ sở chính tại miền Bắc. Ngân hàng đang thực hiện thủ tục chuyển nhượng dự án này. Giá trị dự phòng giảm giá hàng tồn kho đạt 18.073 triệu đồng - mức không đáng kể so với tổng tài sản. Rủi ro đọng vốn từ xây dựng dở dang thấp do quy mô nhỏ.', 3, 'VietinBank (CTG) là một trong những ngân hàng thương mại lớn nhất Việt Nam với tổng tài sản đạt 2.767.699 tỷ VNĐ (tăng 16% so với năm trước). Lợi nhuận sau thuế đạt 34.871 tỷ VNĐ (tăng 36.8%), lãi cơ bản trên cổ phiếu đạt 4.455 đồng/cổ phiếu. Ngân hàng đã tăng vốn điều lệ lên 77.669 tỷ VNĐ thông qua phát hành cổ phiếu trả cổ tức. Tỷ lệ nợ xấu (nhóm 3-5) ở mức 1.1% trên tổng dư nợ cho vay - mức kiểm soát được. Tỷ lệ dự phòng/nợ xấu đạt 159% cho thấy bộ đệm rủi ro vững chắc. Ngân hàng đã đạt chuẩn Basel II và đang triển khai Basel III. Công tác quản trị minh bạch với ý kiến kiểm toán chấp nhận toàn phần từ PwC. Triển vọng kinh doanh tích cực nhờ tăng trưởng tín dụng mạnh, cải thiện biên lãi ròng và kiểm soát chất lượng tài sản tốt.'),
('CTG_2025_parent', 'CTG', 2025, 'parent', 'Giao dịch với các bên liên quan chủ yếu là nghiệp vụ ngân hàng thông thường (tiền gửi, cho vay, lãi vay) với Ngân hàng Nhà nước (NHNN - đại diện chủ sở hữu Nhà nước ~64.46% vốn), cổ đông chiến lược MUFG Bank (~19.7% vốn), 8 công ty con và 1 công ty liên doanh Indovina. Dư nợ cho vay HĐQT/BKS/Ban Điều hành và người liên quan chỉ 249,504 triệu đồng ở mức rất nhỏ so với tổng tài sản. Không phát hiện giao dịch bất thường, cho vay không lãi suất hay chuyển giá có dấu hiệu tuồn vốn ra sân sau. Tổng lợi nhuận nhận được từ các công ty con đạt 65,664 triệu đồng/năm phản ánh hiệu quả hoạt động đầu tư.', 'Cơ cấu nợ của Ngân hàng phụ thuộc lớn vào tiền gửi khách hàng (1,790,691,987 triệu đồng, chiếm ~69.9% tổng nợ phải trả), trong đó tiền gửi không kỳ hạn chiếm 24.8% tổng tiền gửi (CASA ratio). Phát hành giấy tờ có giá 174,030,352 triệu đồng với đa số chứng chỉ tiền gửi ngắn hạn dưới 12 tháng (111,067,832 triệu đồng). Nợ vay từ NHNN giảm từ 154,284,104 xuống 144,592,357 triệu đồng cho thấy Ngân hàng chủ động giảm phụ thuộc nguồn vốn tái cấp vốn. Tỷ lệ nợ xấu 1.10% giảm từ 1.24% cùng kỳ. Tỷ lệ bao phủ nợ xấu (specific provision/NPL) đạt ~159%. Tổng nợ/Vốn chủ sở hữu ~14.87 lần (đặc thù ngân hàng). Áp lực trả nợ ngắn hạn ở mức kiểm soát nhờ đa dạng hóa nguồn huy động và duy trì dự trữ thanh khoản cao.', 'Ngân hàng là tổ chức tín dụng, không có hàng tồn kho theo nghĩa truyền thống. Các khoản mục tương đương bao gồm: Chi phí xây dựng cơ bản dở dang 5,593,474 triệu đồng (chủ yếu dự án Tòa nhà Trụ sở chính đang trong thủ tục chuyển nhượng) và chứng khoán đầu tư 208,695,892 triệu đồng (bao gồm trái phiếu Chính phủ, trái phiếu doanh nghiệp niêm yết và chưa niêm yết). Dự phòng rủi ro chứng khoán đầu tư chỉ 391,863 triệu đồng cho thấy chất lượng danh mục đầu tư chứng khoán tốt. Dự phòng rủi ro cho vay khách hàng 34,603,225 triệu đồng (1.75% dư nợ cho vay). Rủi ro tín dụng tập trung ở nhóm 5 (19,759,966 triệu đồng) đã được trích lập đầy đủ theo tỷ lệ 100%.', 3, 'VietinBank (CTG) có năm tài chính 2025 tăng trưởng mạnh: lợi nhuận sau thuế riêng lẻ đạt 32,906,427 triệu đồng (tăng 35.65%), tổng tài sản đạt 2,735,388,878 triệu đồng (tăng 15.85%). Chất lượng tài sản cải thiện rõ rệt với tỷ lệ nợ xấu giảm từ 1.24% xuống 1.10%, chi phí dự phòng tín dụng giảm 32.91%. Vốn chủ sở hữu đạt 172,387,355 triệu đồng, vốn điều lệ tăng từ 53,699,917 lên 77,669,446 triệu đồng (tăng 44.63% qua phát hành cổ phiếu trả cổ tức). Kiểm toán viên PwC (Việt Nam) đưa ra ý kiến chấp nhận toàn phần, không có vấn đề về hoạt động liên tục. Ngân hàng tuân thủ Basel II và đang triển khai Basel III. Đội ngũ lãnh đạo ổn định, cơ cấu cổ đông minh bạch (NHNN ~64.46%, MUFG ~19.7%). Triển vọng trung hạn tích cực nhờ đà tăng trưởng tín dụng 15.7% và cải thiện hiệu quả hoạt động.'),
('CTG_2024_parent', 'CTG', 2024, 'parent', 'Giao dịch với các bên liên quan chủ yếu là với Ngân hàng Nhà nước (vay vốn), cổ đông chiến lược The Bank of Tokyo - Mitsubishi UFJ (giao dịch tiền gửi và lãi) và các công ty con. Các giao dịch này là hoạt động ngân hàng thông thường, quy mô lớn nhưng minh bạch, phục vụ mục đích huy động và đầu tư vốn. Chưa thấy dấu hiệu bất thường hay chiếm dụng vốn.', 'Cơ cấu nợ chủ yếu là tiền gửi của khách hàng (chiếm tỷ trọng lớn nhất) và phát hành giấy tờ có giá. Nợ vay NHNN tăng mạnh (từ 766 tỷ lên 9.512 tỷ). Ngân hàng có đa dạng nguồn huy động, áp dụng hệ thống điều chuyển vốn nội bộ (FTP) và quản lý rủi ro lãi suất theo thông lệ. Tuy nhiên, áp lực huy động vốn trong bối cảnh lãi suất biến động là đáng lưu ý.', 'Ngân hàng không có hàng tồn kho truyền thống. Khoản ''chi phí xây dựng cơ bản dở dang'' chiếm tỷ trọng nhỏ trên tổng tài sản và không có trích lập dự phòng, cho thấy dự án đang triển khai bình thường, rủi ro đọng vốn thấp.', 4, 'VietinBank là ngân hàng lớn, có vị thế vững chắc với sự tham gia của cổ đông chiến lược nước ngoài (BTMU). Hệ thống quản trị rủi ro được xây dựng bài bản theo Basel II. Tình hình tài chính ổn định, tăng trưởng tín dụng và huy động vốn đều đặn. Tuy nhiên, cần theo dõi chất lượng tài sản (dự phòng rủi ro tín dụng tăng), quản lý nợ xấu đã xử lý và biến động lãi suất. Triển vọng trung và dài hạn tích cực.'),
('CTG_2024_consolidated', 'CTG', 2024, 'consolidated', 'Các giao dịch với bên liên quan chủ yếu là nghiệp vụ ngân hàng thông thường. Giao dịch với NHNN bao gồm tiền gửi thanh toán dự trữ bắt buộc và vay tái cấp vốn nghiệp vụ tín dụng, phù hợp với vai trò cơ quan quản lý. Giao dịch với Indovina (liên doanh 50%) phát sinh lãi tiền gửi/tiền vay với giá trị nhỏ. Giao dịch với BTMU (cổ đông chiến lược 19,73%) chủ yếu là chi phí lãi vay và tiền gửi với quy mô nhỏ so với tổng hoạt động. Số dư lớn với BTMU bao gồm tiền gửi của Ngân hàng tại BTMU (37.680 tỷ VND) và tiền Ngân hàng vay trước đây (đã trả hết). Nhìn chung, chưa phát hiện dấu hiệu giao dịch bất thường hay rút vốn giữa các bên.', 'Cơ cấu nợ vay lớn với tổng nợ phải trả 2.236.883 tỷ VND (tỷ lệ nợ/VCSH ~15 lần), đặc trưng của hoạt động ngân hàng. Nợ ngắn hạn chiếm tỷ trọng lớn: tiền gửi không kỳ hạn TCTD (204.153 tỷ), phát hành giấy tờ có giá ngắn hạn (96.457 tỷ). Nợ vay NHNN tăng mạnh từ 767 tỷ lên 9.513 tỷ do mở rộng nghiệp vụ tái cấp vốn. Tiền gửi Kho bạc Nhà nước tăng vọt từ 21.047 tỷ lên 144.771 tỷ. Phát hành giấy tờ có giá tăng 31,5% (từ 115.376 tỷ lên 151.678 tỷ). Tuy nhiên, ngân hàng có mạng lưới huy động vốn rộng với tổng tiền gửi khách hàng 1.606.317 tỷ VND và duy trì danh mục chứng khoán đầu tư lớn (215.193 tỷ) làm tài sản dự trữ thanh khoản.', 'Ngân hàng TMCP Công Thương Việt Nam là tổ chức tín dụng, không có hàng tồn kho theo nghĩa truyền thống. Các khoản mục tương tự bao gồm chi phí xây dựng cơ bản dở dang (5.679 tỷ VND) cho việc xây dựng/trang bị trụ sở và chi nhánh ngân hàng, và vật liệu công cụ (316 tỷ VND). Dự phòng giảm giá hàng tồn kho chỉ 14 tỷ VND, quy mô không đáng kể. Rủi ro đọng vốn từ bất động sản dở dang thấp.', 4, 'VietinBank là một trong những ngân hàng thương mại lớn nhất Việt Nam với mạng lưới 157 chi nhánh và 953 phòng giao dịch, tổng tài sản 2.385.388 tỷ VND (tăng 17,4%). Lợi nhuận sau thuế đạt 25.483 tỷ VND (tăng 27,1%), lãi cơ bản cổ phiếu 4.720 VND. Tăng trưởng tín dụng 17,5% (cho vay khách hàng từ 1.445.572 tỷ lên 1.685.291 tỷ). Tỷ lệ nợ xấu nhóm 3-5 là 1,22% (tăng từ 1,12% năm trước), tỷ lệ dự phòng bao phủ nợ xấu ~175%. Ngân hàng được quản trị bởi Nhà nước (64,46% vốn) với cổ đông chiến lược BTMU (19,73%), cơ cấu quản trị rõ ràng. Ý kiến kiểm toán chấp nhận toàn phần. CASA ~23,9%, NIM ~2,86%. Áp lực thanh khoản ngắn hạn từ tỷ lệ nợ ngắn hạn lớn nhưng được hỗ trợ bởi tài sản dự trữ thanh khoản phong phú. Triển vọng kinh doanh ổn định, hưởng lợi từ vị thế ngân hàng quốc doanh lớn và mạng lưới rộng khắp.'),
('CTG_2023_consolidated', 'CTG', 2023, 'consolidated', 'Giao dịch với Ngân hàng Nhà nước Việt Nam (NHNN) với vai trò chủ sở hữu và cơ quan quản lý là nghiệp vụ thông thường. Giao dịch với Ngân hàng liên doanh Indovina và cổ đông chiến lược Tokyo-Mitsubishi UFJ chủ yếu là nghiệp vụ lãi tiền gửi và vay, không có dấu hiệu bất thường hay chuyển giá.', 'Nợ vay lớn, tập trung vào tiền gửi của khách hàng (1.410.899.038 triệu VND), phát hành giấy tờ có giá (115.375.727 triệu VND) và vay các TCTD khác. Cơ cấu nợ chủ yếu ngắn hạn, áp lực lãi suất biến động. Tỷ lệ nợ/VCSH ở mức cao, cần giám sát chặt.', 'Chi phí xây dựng cơ bản dở dang 5.570.225 triệu VND chủ yếu là các công trình xây dựng trụ sở, chi nhánh. Đây là tài sản cố định, không phải hàng tồn kho kinh doanh, rủi ro thấp nếu dự án đúng tiến độ.', 4, 'Ngân hàng TMCP Công thương Việt Nam (VietinBank) là ngân hàng lớn, có sự hiện diện của cổ đông chiến lược nước ngoài (Bank of Tokyo-Mitsubishi UFJ). Tình hình tài chính ổn định, lợi nhuận tăng trưởng 18% so với cùng kỳ. Ý kiến kiểm toán chấp nhận toàn phần. Công tác quản trị rủi ro tuân thủ quy định, tuy nhiên cần lưu ý cơ cấu nợ lớn và biến động lãi suất.'),
('CTG_2023_parent', 'CTG', 2023, 'parent', 'Ngân hàng có mối quan hệ kinh doanh đa dạng với các bên liên quan bao gồm NHNN (chủ sở hữu), cổ đông chiến lược (Ngân hàng Tokyo-Mitsubishi UFJ), ngân hàng liên doanh (Indovina) và các công ty con. Các giao dịch chủ yếu tập trung vào hoạt động huy động vốn, cho vay, thanh toán và đầu tư, phù hợp với hoạt động kinh doanh ngân hàng. Tuy nhiên, quy mô giao dịch với công ty con và liên doanh khá lớn, cần giám sát chặt chẽ để tránh xung đột lợi ích.', 'Nợ phải trả của Ngân hàng chủ yếu đến từ tiền gửi của khách hàng (1.4 triệu tỷ VNĐ) và phát hành giấy tờ có giá (115 nghìn tỷ VNĐ). Áp lực trả nợ ngắn hạn lớn do cơ cấu tiền gửi chủ yếu là có kỳ hạn. Tuy nhiên, Ngân hàng có tài sản thanh khoản cao (tiền mặt, tiền gửi tại NHNN) và quản lý rủi ro thanh khoản chủ động. Tỷ lệ nợ xấu (1.12%) ở mức kiểm soát được, tỷ lệ bao phủ dự phòng cao (167.7%) cho thấy Ngân hàng dự phòng đầy đủ cho rủi ro tín dụng.', 'Ngân hàng không có hàng tồn kho truyền thống. Chi phí xây dựng cơ bản dở dang (5.570 tỷ VNĐ) tập trung vào các công trình xây dựng trụ sở, văn phòng phục vụ hoạt động kinh doanh. Rủi ro đọng vốn thấp do tiến độ xây dựng vẫn được kiểm soát.', 4, 'VietinBank là ngân hàng thương mại lớn, có cấu trúc tài chính lành mạnh với tổng tài sản hơn 2 triệu tỷ VNĐ. Tăng trưởng lợi nhuận trước thuế năm 2023 đạt 17.8%, cho thấy hiệu quả hoạt động cải thiện. Ngân hàng tuân thủ tốt các quy định của NHNN về Basel II, quản trị rủi ro và thanh khoản. Ý kiến kiểm toán là chấp nhận toàn phần, không có vấn đề về hoạt động liên tục. Tuy nhiên, cần lưu ý áp lực cạnh tranh trong ngành ngân hàng và biến động lãi suất thị trường.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('CTG_2022_consolidated', 'CTG', 2022, 'consolidated', 'Các giao dịch với bên liên quan chủ yếu phát sinh từ hoạt động ngân hàng thông thường: tiền gửi và vay NHNN (chủ sở hữu Nhà nước chiếm khoảng 64.5% vốn), giao dịch với ngân hàng liên doanh Indovina (50% sở hữu) và cổ đông chiến lược Tokyo-Mitsubishi UFJ. Các giao dịch này phục vụ mục đích thanh toán, dự trữ bắt buộc và quan hệ liên ngân hàng, không có dấu hiệu bất thường hay chuyển giá. Dư tiền gửi tại Indovina tăng mạnh từ 36,483 lên 1,025,483 triệu VNĐ cần được theo dõi thêm.', 'Tổng nợ phải trả đạt 1,700,262,107 triệu VNĐ, tập trung chủ yếu vào tiền gửi khách hàng (73.5% tổng nợ) với tính ổn định cao. Nợ vay NHNN ở mức khiêm tốn 1,736,629 triệu VNĐ. Vay các TCTD khác giảm mạnh từ 105,163,042 xuống 69,497,315 triệu VNĐ cho thấy ngân hàng chủ động giảm phụ thuộc vốn liên ngân hàng. Phát hành giấy tờ có giá tăng 41.7% lên 91,370,419 triệu VNĐ, trong đó 53% là dài hạn (trên 5 năm), giúp đa dạng hóa cơ cấu kỳ hạn vốn. Tỷ lệ nợ/vốn chủ sở hữu ở mức 15.7 lần đặc thù cho ngành ngân hàng. Áp lực lãi suất phát hành giấy tờ có giá tăng do chi phí lãi tăng 6.2% so với cùng kỳ.', 'Dành cho ngân hàng thương mại, rủi ro ''hàng tồn kho'' thể hiện qua chất lượng danh mục tín dụng. Tỷ lệ nợ xấu (nhóm 3-5) ở mức 1.24% trên tổng dư nợ cho vay, cải thiện so với mặt bằng chung ngành. Dự phòng rủi ro tín dụng tăng mạnh 31.4% lên 24,163,177 triệu VNĐ thể hiện sự chủ động trích lập. Tỷ lệ bao phủ dự phòng đạt 188.3% trên nợ xấu. Chi phí xây dựng cơ bản dở dang 5,633,260 triệu VNĐ chủ yếu là đầu tư hạ tầng chi nhánh và công nghệ, không có dấu hiệu đọng vốn kéo dài.', 4, 'VietinBank là ngân hàng thương mại nhà nước lớn thứ 2 tại Việt Nam với tổng tài sản 1,808,429,764 triệu VNĐ (tăng 18.1%). Ngân hàng có cấu trúc cổ đông rõ ràng với Nhà nước nắm giữ đa số, có cổ đông chiến lược quốc tế (Bank of Tokyo-Mitsubishi UFJ). Lợi nhuận sau thuế hợp nhất đạt 16,834,994 triệu VNĐ (tăng 18.4%), thu nhập lãi thuần tăng trưởng 14.4% nhờ mở rộng quy mô tín dụng. Tỷ lệ nợ xấu 1.24% và dự phòng bao phủ 188.3% cho thấy chất lượng tài sản được kiểm soát tốt. CASA ratio 19.5% còn thấp so với một số ngân hàng tư nhân, là điểm cần cải thiện. Ý kiến kiểm toán chấp nhận toàn phần từ Deloitte Việt Nam. Nhìn chung, ngân hàng có nền tảng tài chính vững mạnh, triển vọng tăng trưởng ổn định trong trung hạn.'),
('CTG_2021_consolidated', 'CTG', 2021, 'consolidated', 'Các giao dịch với bên liên quan chủ yếu là với Ngân hàng Nhà nước Việt Nam (chủ sở hữu và cơ quan quản lý trực tiếp) và ngân hàng liên doanh Indovina. Các giao dịch này chủ yếu là tiền gửi, vay và lãi suất tiền gửi, mang tính chất nghiệp vụ ngân hàng thông thường và không có dấu hiệu bất thường hay xung đột lợi ích lớn.', 'Tổng nợ phải trả của Ngân hàng lớn (hơn 1.437 nghìn tỷ VNĐ), tập trung vào tiền gửi của khách hàng (chiếm tỷ trọng lớn) và phát hành giấy tờ có giá. Ngân hàng có cơ cấu tài sản đa dạng và nguồn vốn ổn định, tỷ lệ nợ/VCSH ở mức cao (khoảng 15.3 lần) đặc thù của ngành ngân hàng. Áp lực trả nợ ngắn hạn được kiểm soát tốt nhờ quản lý thanh khoản chặt chẽ và đa dạng hóa nguồn vốn.', 'Ngân hàng không có hàng tồn kho vật chất lớn như doanh nghiệp sản xuất. Khoản mục ''Chi phí xây dựng cơ bản dở dang'' chủ yếu liên quan đến đầu tư xây dựng cơ sở hạ tầng của Ngân hàng, không phải hàng hóa kinh doanh nên rủi ro thấp.', 2, 'Ngân hàng TMCP Công thương Việt Nam (VietinBank) là một trong những ngân hàng thương mại lớn tại Việt Nam với mạng lưới rộng khắp. Báo cáo tài chính hợp nhất năm 2021 được kiểm toán bởi Ernst & Young Việt Nam với ý kiến chấp nhận toàn phần. Tình hình tài chính ổn định, tăng trưởng lợi nhuận, quản trị rủi ro tốt. Các chỉ tiêu an toàn hoạt động đáp ứng yêu cầu của Ngân hàng Nhà nước. Triển vọng kinh doanh tích cực trong trung hạn.'),
('CTG_2022_parent', 'CTG', 2022, 'parent', 'Giao dịch với các bên liên quan có quy mô lớn nhưng mang tính chất hoạt động ngân hàng cốt lõi: (1) Giao dịch lớn nhất là với Kho bạc Nhà nước (tiền gửi 103 tỷ VND) và NHNN (vay 1.7 tỷ VND), phản ánh vai trò chủ sở hữu nhà nước và mối quan hệ ngân hàng thương mại - ngân hàng trung ương là hoàn toàn bình thường; (2) BTMU là cổ đông chiến lược nước ngoài với tỷ lệ sở hữu đáng kể, giao dịch bao gồm tiền gửi, vay và chi phí lãi - quy mô giảm mạnh so với đầu năm (tiền vay giảm từ 7.5 tỷ xuống 8 triệu VND), cho thấy xu hướng giảm phụ thuộc vào vốn ngoại; (3) Đầu tư vào 7 công ty con và 1 ngân hàng liên doanh với tổng giá trị 5.6 tỷ VND, hoạt động đa dạng hóa dịch vụ tài chính (cho thuê tài chính, chứng khoán, bảo hiểm, quản lý quỹ, vàng bạc). Chưa phát hiện dấu hiệu chuyển giá, rút vốn hay giao dịch bất thường với bên liên quan.', 'Nợ phải trả chủ yếu từ tiền gửi khách hàng (1.247 tỷ VND, chiếm 73.9% tổng nợ) - nguồn vốn ổn định và chi phí thấp cho ngân hàng. Tỷ lệ tiền gửi không kỳ hạn/tổng tiền gửi khách hàng đạt 19.5% (CASA thấp hơn trung bình ngành). Nợ vay các TCTD khác giảm mạnh từ 100.5 tỷ xuống 64.9 tỷ VND, cho thấy chủ động giảm phụ vốn vay liên ngân hàng. Phát hành giấy tờ có giá tăng mạnh từ 64.5 tỷ lên 91.4 tỷ VND, tập trung vào chứng chỉ tiền gửi ngắn hạn (43 tỷ VND dưới 12 tháng) và trái phiếu trung-dài hạn (36.3 tỷ VND trên 5 năm). Tổng nợ/VCSH ở mức 16.1 lần - đặc thù của hoạt động ngân hàng thương mại. Áp lực thanh toán nợ ngắn hạn lớn (796.6 tỷ VND đáo hạn trong vòng 1 tháng) nhưng được bù đắp bởi lượng tài sản ngắn hạn tương ứng.', 'Là ngân hàng thương mại, VietinBank không có hàng tồn kho truyền thống. Chi phí xây dựng cơ bản dở dang (CIP) đạt 5.633 tỷ VND, tăng nhẹ so với đầu năm (5.567 tỷ VND), chủ yếu là đầu tư hạ tầng trụ sở và chi nhánh tại 3 miền. Giá trị CIP chiếm tỷ trọng nhỏ trong tổng tài sản (0.31%), rủi ro đọng vốn thấp. Tuy nhiên, danh mục cho vay bất động sản tiềm ẩn rủi ro khi tổng tài sản thế chấp bất động sản đạt 1.705 tỷ VND (tăng từ 1.485 tỷ VND), chiếm tỷ trọng lớn trong tài sản bảo đảm. Nợ xấu tập trung ở nhóm 3-5 đạt 15.709 tỷ VND (tỷ lệ NPL 1.24%), tỷ lệ dự phòng/NPL đạt 1.89 lần cho thấy mức trích lập dự phòng tương đối đầy đủ.', 4, 'VietinBank là ngân hàng thương mại lớn thứ 3 Việt Nam với vốn điều lệ 48.057 tỷ VND, được kiểm toán bởi Deloitte với ý kiến chấp nhận toàn phần. Cơ cấu cổ đông minh bạch với Nhà nước nắm giữ ~64.5% vốn và BTMU là cổ đông chiến lược nước ngoài. Tình hình tài chính năm 2022 cải thiện tích cực: lợi nhuận sau thuế đạt 16.379 tỷ VND (tăng 20.2% YoY), thu nhập lãi thuần tăng 5.830 tỷ VND (+14.2%), nợ xấu kiểm soát ở mức 1.24%. Dự phòng rủi ro tín dụng tăng chủ động (24.096 tỷ VND) thể hiện thận trọng trong quản trị. Đáng chú ý là chi phí dự phòng tăng 5.759 tỷ VND (+31.4%), cho thấy ngân hàng đẩy mạnh xử lý nợ xấu. Hệ số an toàn vốn và các tỷ lệ đảm bảo an toàn tuân thủ quy định NHNN. Triển vọng phát triển ổn định nhờ vị thế thị trường mạnh, mạng lưới rộng (157 chi nhánh, 957 phòng giao dịch) và tiến trình áp dụng Basel II.'),
('CTG_2020_parent', 'CTG', 2020, 'parent', 'Ngân hàng có mạng lưới công ty con rộng lớn (7 công ty con và 1 ngân hàng con 100% vốn tại Lào) cùng liên doanh Ngân hàng TNHH Indovina. Các giao dịch với bên liên quan chủ yếu xoay quanh hoạt động kinh doanh ngân hàng cốt lõi: tiền gửi, cho vay và lãi suất trong hệ thống. Tổng dư nợ cho vay và tiền gửi với công ty con/liên doanh khoảng 5,174 tỷ VNĐ. Giao dịch với NHNN là giao dịch bắt buộc theo quy định (dự trữ bắt buộc, vay tái cấp vốn). Thu nhập từ góp vốn, mua cổ phần đạt 531.947 triệu đồng chủ yếu từ lợi nhuận được chia từ các khoản đầu tư dài hạn. Chưa thấy dấu hiệu rút ruột hoặc chuyển giá bất thường qua các giao dịch liên quan, nhưng quy mô hệ sinh thái công ty con phức tạp đòi hỏi giám sát chặt chẽ.', 'Tổng nợ phải trả lên tới 1,245,808,062 triệu đồng, gấp khoảng 15.17 lần vốn chủ sở hữu (82,112,946 triệu đồng). Đây là đặc trưng của hoạt động ngân hàng với đòn bẩy tài chính cao. Nợ phải trả tập trung chủ yếu vào tiền gửi khách hàng (988,070,156 triệu đồng, chiếm 79.3% tổng nợ) - nguồn vốn tương đối ổn định. Tuy nhiên, tỷ lệ tiền gửi có kỳ hạn cao (794,345,685 triệu đồng) cho thấy chi phí vốn cố định lớn. Nợ vay NHNN giảm mạnh từ 70,602,893 triệu đồng xuống 44,597,188 triệu đồng. Phát hành giấy tờ có giá tăng từ 56,966,353 lên 59,875,570 triệu đồng, trong đó trái phiếu ghi số dài hạn (trên 5 năm) chiếm 34,874,320 triệu đồng. Áp lực trả nợ ngắn hạn tập trung vào tiền gửi không kỳ hạn và nợ liên ngân hàng.', 'Ngân hàng không có hàng tồn kho truyền thống. Chi phí xây dựng cơ bản dở dang (XDCB) trị giá 5,628,132 triệu đồng chủ yếu là chi phí xây dựng trụ sở/chi nhánh tại 3 khu vực (Bắc: 5,210,728, Trung: 330,482, Nam: 86,922 triệu đồng), chiếm tỷ trọng rất nhỏ (<0.5%) trong tổng tài sản. Không có dự phòng giảm giá cho XDCB, cho thấy các dự án xây dựng cơ bản được đánh giá tiến độ tốt. Rủi ro đọng vốn từ hoạt động xây dựng là thấp.', 4, 'VietinBank là một trong những ngân hàng thương mại nhà nước lớn nhất Việt Nam với tổng tài sản 1,327,921,008 triệu đồng. Lợi nhuận trước thuế đạt 16,448,581 triệu đồng (tăng 43.5% so với năm 2019), lợi nhuận sau thuế đạt 13,255,847 triệu đồng. Tỷ lệ nợ xấu (Nhóm 3+4+5) là 9,317,285 triệu đồng, chiếm 0.93% trên tổng dư nợ cho vay. Dự phòng rủi ro tín dụng đạt 12,345,700 triệu đồng, tỷ lệ bao phủ nợ xấu đạt 132.5%. Kiểm toán viên Ernst & Young Việt Nam đưa ra ý kiến chấp nhận toàn phần. Ngân hàng có 22,564 nhân viên với mạng lưới 155 chi nhánh và 7 công ty con. Cổ đông lớn nhất là Nhà nước với vốn đầu tư 24,001,066 triệu đồng (64.5% vốn điều lệ). Ngân hàng đã chi trả cổ tức 5% mệnh giá năm 2019 (1,861,702 triệu đồng). Cơ chế quản trị rủi ro được xây dựng theo tiêu chuẩn Basel II, hệ thống kiểm soát nội bộ tuân thủ Thông tư 13/2018/TT-NHNN. Nhìn chung, ngân hàng có nền tảng tài chính vững chắc, hoạt động ổn định với sự hỗ trợ mạnh mẽ từ cổ đông Nhà nước.'),
('CTG_2020_consolidated', 'CTG', 2020, 'consolidated', 'Các giao dịch với bên liên quan chủ yếu mang tính quy định và hoạt động kinh doanh thông thường. Giao dịch với NHNN (chủ sở hữu nhà nước 64,46% vốn) bao gồm tiền gửi thanh toán và vay tái cấp vốn, là nghiệp vụ chuẩn của ngân hàng thương mại. Giao dịch với Ngân hàng TNHH Indovina (liên doanh 50% với Cathay United, Đài Loan) gồm tiền gửi qua lại và chênh lệch lãi, quy mô giao dịch giảm mạnh trong năm 2020 (-3.919 tỷ đồng tiền gửi tại Indovina). Thu nhập ban lãnh đạo HĐQT, Ban Điều hành và Ban Kiểm soát ở mức hợp lý 30,5 tỷ đồng. Không phát hiện dấu hiệu giao dịch bất thường, cho vay không lãi suất hay chuyển giá với bên liên quan.', 'Tổng nợ phải trả 1.256.025 tỷ đồng, chiếm 93,6% tổng tài sản. Nguồn vốn phụ thuộc lớn vào tiền gửi khách hàng (990.331 tỷ đồng, chiếm 79% tổng nợ). CASA ratio chỉ đạt 18,8% - mức khá thấp, cho thấy chi phí vốn huy động có thể cao. Nợ phát hành giấy tờ có giá 59.876 tỷ đồng, trong đó trái phiếu hữu danh dài hạn 34.874 tỷ đồng cho thấy ngân hàng đã đa dạng hóa nguồn vốn. Nợ vay các TCTD khác 128.519 tỷ đồng phản ánh hoạt động liên ngân hàng lớn. Tỷ lệ nợ xấu (nhóm 3-5) đạt 0,94% - mức chấp nhận được so với mặt bằng ngành. Tuy nhiên, nợ cần chú ý (nhóm 2) còn 2.799 tỷ đồng và nợ quá hạn tổng 1.866 tỷ đồng cần được theo dõi sát.', 'Ngân hàng hoạt động trong lĩnh vực tài chính, không có hàng tồn kho truyền thống. Các khoản xây dựng cơ bản dở dang trị giá 6.628 tỷ đồng tập trung tại hệ thống 155 chi nhánh và 7 công ty con trên toàn quốc, quy mô hợp lý so với tổng tài sản. Dự phòng giảm giá hàng tồn kho chỉ 21,7 tỷ đồng, quy mô nhỏ. Rủi ro đọng vốn vào tài sản cố định không đáng kể.', 4, 'VietinBank là ngân hàng thương mại cổ phần lớn thứ 4 tại Việt Nam với vốn điều lệ 37.234 tỷ đồng, tổng tài sản 1.341.436 tỷ đồng, mạng lưới 155 chi nhánh và 7 công ty con. Kiểm toán viên Ernst & Young Việt Nam đưa ra ý kiến chấp nhận toàn phần, không có vấn đề về khả năng hoạt động liên tục. Ngân hàng có kết quả kinh doanh tích cực năm 2020 với lợi nhuận sau thuế 13.757 tỷ đồng (tăng 45% so với 2019), NIM đạt 2,76%. Tỷ lệ nợ xấu 0,94% ở mức kiểm soát được. Dự phòng bao phủ nợ xấu đạt 54,6% - mức trung bình. CASA 18,8% là điểm yếu so với một số ngân hàng cùng quy mô. Ngân hàng đang trong quá trình thoái vốn 50% tại VietinBank Leasing cho Mitsubishi UFJ Lease & Finance. Ban lãnh đạo có sự thay đổi đáng kể năm 2020 với nhiều thành viên HĐQT mới được bổ nhiệm. Tổng thể, ngân hàng có nền tảng tài chính vững chắc, hoạt động kinh doanh ổn định, triển vọng phát triển trung hạn tích cực.'),
('CTG_2019_consolidated', 'CTG', 2019, 'consolidated', 'Giao dịch với Ngân hàng Nhà nước Việt Nam là hoạt động bình thường của ngân hàng thương mại (tiền gửi dự trữ bắt buộc, vay tái cấp vốn). Giao dịch với Ngân hàng TNHH Indovina là liên doanh hợp pháp (50% vốn góp), số dư tiền gửi qua lại cân đối (4,015,808 vs 4,044,912 triệu đồng). Không phát hiện dấu hiệu giao dịch bất thường, cho vay không lãi suất hay chuyển giá với bên liên quan.', 'Tổng nợ phải trả 1,163,356,657 triệu đồng chiếm 93.8% tổng tài sản, đặc thù của hoạt động ngân hàng. Cơ cấu nguồn vốn chủ yếu từ tiền gửi khách hàng (892,785,228 triệu đồng - 76.7% tổng nợ), trong đó tiền gửi có kỳ hạn chiếm 83% tạo nguồn vốn ổn định. Tỷ lệ nợ/vốn chủ sở hữu ở mức 15.0 lần, áp dụng chuẩn Basel II. Nợ vay từ các TCTD khác giảm từ 37,457,688 xuống 26,945,019 triệu đồng cho thấy cải thiện cơ cấu vốn. Phát hành giấy tờ có giá tăng mạnh 23.5% phản ánh đa dạng hóa nguồn huy động.', 'Là ngân hàng thương mại, VietinBank không có hàng tồn kho theo nghĩa truyền thống. Tuy nhiên, rủi ro tín dụng (cho vay khách hàng 935,270,945 triệu đồng) là trọng yếu. Nợ xấu (nhóm 3-5) ở mức 10,813,411 triệu đồng (1.16% dư nợ), giảm so với năm trước (13,709,348 triệu đồng - 1.58%). Trái phiếu VAMC trị giá 12,781,245 triệu đồng đã trích lập dự phòng 6,589,018 triệu đồng (51.6%). Công trình xây dựng dở dang 5,730,014 triệu đồng chủ yếu là đầu tư hạ tầng trụ sở, chi nhánh.', 3, 'VietinBank là một trong những ngân hàng thương mại nhà nước lớn nhất Việt Nam với tổng tài sản hơn 1.24 triệu tỷ đồng. Kết quả kinh doanh năm 2019 cải thiện mạnh với lợi nhuận sau thuế 9,476,989 triệu đồng (tăng 79.6% so với năm trước). Thu nhập lãi thuần đạt 33,199,037 triệu đồng (tăng 49.5%), NIM cải thiện lên 2.68%. Tỷ lệ nợ xấu giảm xuống 1.16% cho thấy chất lượng tín dụng cải thiện. Ngân hàng được kiểm toán bởi Ernst & Young với ý kiến chấp nhận toàn phần, không có vấn đề going concern. Cơ cấu quản trị minh bạch với đại diện từ NHNN và đối tác chiến lược Nhật Bản (Mizuho). Triển vọng đầu tư trung hạn tích cực nhờ lợi thế mạng lưới rộng lớn (155 chi nhánh) và vị thế thị trường vững chắc.'),
('CTG_2019_parent', 'CTG', 2019, 'parent', 'Ngân hàng có giao dịch lớn và thường xuyên với chủ sở hữu (NHNN) và các công ty con/liên doanh, đặc biệt là tiền gửi và cho vay nội bộ. Các giao dịch này là đặc thù hoạt động của ngân hàng, tuy nhiên cần giám sát quy mô và điều khoản lãi suất để đảm bảo không có ưu đãi bất thường hoặc rủi ro tập trung.', 'Cấu trúc nợ chủ yếu là tiền gửi không kỳ hạn và có kỳ hạn ngắn hạn của khách hàng (chiếm tỷ trọng lớn). Ngân hàng phát hành giấy tờ có giá với kỳ hạn dài hơn để cân đối. Áp lực lãi suất là đáng kể do chi phí vốn đầu vào biến động. Ngân hàng quản lý rủi ro lãi suất thông qua hệ thống ALM và FTP. Tỷ lệ nợ/vốn chủ sở hữu (Leverage) rất cao là đặc trưng của ngành ngân hàng.', 'Hàng tồn kho không phải là tài sản trọng yếu. Tuy nhiên, ''Chi phí xây dựng cơ bản dở dang'' có giá trị lớn (hơn 5.700 tỷ đồng), phản ánh các dự án đầu tư xây dựng cơ sở hạ tầng, trụ sở. Cần đánh giá tiến độ và khả năng hoàn thành đúng kế hoạch của các dự án này để tránh đọng vốn quá lâu.', 4, 'Ngân hàng TMCP Công thương Việt Nam (VietinBank) là một trong những ngân hàng thương mại Nhà nước lớn, có mạng lưới rộng. Tình hình tài chính năm 2019 cho thấy tăng trưởng lợi nhuận ấn tượng (83,7%). Tuy nhiên, áp lực từ chi phí dự phòng rủi ro tín dụng và quản lý nợ xấu vẫn là trọng tâm. Hệ thống quản trị rủi ro theo Basel II đang được triển khai. Cổ đông Nhà nước chi phối, giao dịch với bên liên quan là nội bộ tập đoàn ngân hàng. Triển vọng phụ thuộc vào môi trường kinh tế vĩ mô, chính sách tiền tệ và năng lực xử lý nợ xấu.'),
('CTG_2018_consolidated', 'CTG', 2018, 'consolidated', 'Giao dịch với các bên liên quan (Ngân hàng Nhà nước, Ngân hàng TNHH Indovina) là giao dịch kinh doanh thông thường trong ngành ngân hàng (tiền gửi, cho vay). Quy mô lớn do bản chất hoạt động của ngân hàng nhưng không thấy dấu hiệu bất thường hay chuyển giá.', 'Cơ cấu nợ chủ yếu là tiền gửi của khách hàng (nguồn vốn ổn định), vay từ Chính phủ và NHNN, và phát hành giấy tờ có giá. Áp lực nợ ngắn hạn lớn nhưng được bù đắp bởi tài sản ngắn hạn. Tỷ lệ nợ/VCSH ở mức cao (~16.3 lần) là đặc trưng của ngành ngân hàng.', 'Ngân hàng không có hàng tồn kho truyền thống. Các khoản phải thu và cho vay là tài sản chính, đã được trích lập dự phòng rủi ro tín dụng đầy đủ theo quy định. Rủi ro tập trung vào chất lượng tín dụng hơn là hàng tồn kho.', 2, 'Ngân hàng có quy mô lớn, vị thế thị trường vững chắc. Cơ cấu tài sản và nguồn vốn phản ánh đặc thù ngành ngân hàng. Kiểm toán viên đưa ra ý kiến chấp nhận toàn phần. Ban lãnh đạo có sự thay đổi trong năm nhưng hoạt động vẫn liên tục. Công tác quản trị rủi ro được xây dựng bài bản theo chuẩn Basel II.'),
('CTG_2018_parent', 'CTG', 2018, 'parent', 'Giao dịch với Ngân hàng Nhà nước chủ yếu là tiền gửi dự trữ bắt buộc và thanh toán, không có rủi ro lớn. Giao dịch với các công ty con bao gồm tiền gửi, cho vay và lãi phát sinh với quy mô tương đối nhỏ so với tổng tài sản (khoảng 1,5 tỷ VND tiền gửi và 772 tỷ VND cho vay), không thấy dấu hiệu bất thường hay chuyển giá.', 'Nợ vay của ngân hàng rất lớn, chủ yếu là tiền gửi khách hàng (824.345 tỷ VND) và phát hành giấy tờ có giá (46.016 tỷ VND). Tỷ lệ nợ/Vốn chủ sở hữu lên tới khoảng 16,7 lần, đặc trưng của ngân hàng. Áp lực trả nợ cao nhưng được kiểm soát bởi hệ thống quản lý rủi ro thanh khoản. Nợ xấu tăng nhẹ từ 1,24% năm 2017 lên 1,59% năm 2018, tập trung ở nhóm nợ có khả năng mất vốn (9.454 tỷ VND). Tài sản thế chấp chủ yếu là bất động sản (hơn 1.080.000 tỷ VND) và động sản.', 'Ngân hàng không có hàng tồn kho vật lý. Khoản mục ''Chi phí xây dựng cơ bản dở dang'' (5.865 tỷ VND) đại diện cho các dự án đầu tư xây dựng, chưa trích lập dự phòng. Rủi ro đọng vốn thấp nếu dự án đúng tiến độ, nhưng cần theo dõi tiến độ triển khai để tránh tích tụ chi phí quá lâu.', 4, 'Ngân hàng VietinBank có quy mô lớn, mạng lưới hoạt động rộng. Tình hình tài chính lành mạnh với tổng tài sản hơn 1,15 triệu tỷ VND. Hoạt động kinh doanh cốt lõi (tín dụng, dịch vụ) tăng trưởng tốt. Tuy nhiên, nợ xấu có xu hướng tăng nhẹ, cần được giám sát. Ban lãnh đạo có một số thay đổi nhân sự trong năm nhưng không ảnh hưởng nghiêm trọng đến hoạt động. Công tác quản trị rủi ro được đánh giá tốt, tuân thủ các chuẩn mực Basel II. Triển vọng trung hạn ổn định.'),
('CTG_2017_consolidated', 'CTG', 2017, 'consolidated', 'Giao dịch với các bên liên quan chủ yếu là hoạt động ngân hàng truyền thống với NHNN (cơ quan quản lý) và công ty liên doanh Indovina. Tiền gửi qua lại với Indovina là nghiệp vụ liên ngân hàng thông thường. Không phát hiện giao dịch bất thường hay chuyển giá. Các giao dịch với công ty con phục vụ mục đích mở rộng dịch vụ tài chính đa ngành.', 'Tổng nợ phải trả chiếm 94.2% tổng tài sản - tỷ lệ đặc thù của ngành ngân hàng. Tiền gửi khách hàng chiếm 73% tổng nợ, là nguồn vốn ổn định. Nợ vay từ các TCTD khác chiếm 11.2%, bao gồm 46.6 nghìn tỷ vay từ các tổ chức tín dụng. Ngân hàng phát hành trái phiếu 22.5 nghìn tỷ. Áp lực thanh toán nợ ngắn hạn lớn nhưng được bù đắp bởi mạng lưới tiền gửi rộng khắp. Tỷ lệ nợ xấu 1.14% với dự phòng bao phủ 92.37% cho thấy chất lượng tín dụng được kiểm soát tốt.', 'Là ngân hàng thương mại, VietinBank không có hàng tồn kho truyền thống hay dự án xây dựng dở dang. Chỉ có vật liệu và công cụ trị giá 193 tỷ VNĐ và chi phí trả trước 2,990 tỷ VNĐ - mức không đáng kể so với tổng tài sản. Rủi ro hàng tồn kho không phải là mối lo ngại.', 4, 'VietinBank là ngân hàng lớn thứ 4 tại Việt Nam với tổng tài sản hơn 1.095 triệu tỷ VNĐ, mạng lưới 157 chi nhánh, 7 công ty con và 1 ngân hàng con tại Lào. Kiểm toán Ernst & Young Việt Nam cấp ý kiến chấp nhận toàn phần. Lợi nhuận sau thuế tăng 10% đạt 7,459 tỷ VNĐ, EPS đạt 1,546 VNĐ/cổ phiếu. Tỷ lệ nợ xấu 1.14% ở mức kiểm soát tốt. Tuy nhiên, ngân hàng đang liên quan đến vụ án Huỳnh Thị Huyền Like với nghĩa vụ nợ tiềm ẩn lớn (bản án sơ thẩm 1,085 tỷ VNĐ bồi thường), tạo rủi ro pháp lý bất định. Triển vọng đầu tư trung hạn tích cực với điều kiện theo dõi tiến triển vụ kiện.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('CTG_2017_parent', 'CTG', 2017, 'parent', 'Giao dịch với bên liên quan chủ yếu là hoạt động kinh doanh thông thường với công ty con và cơ quan quản lý (NHNN). Giá trị giao dịch tiền gửi và cho vay với công ty con chiếm tỷ trọng nhỏ trong tổng tài sản, không có dấu hiệu bất thường hay chiếm dụng vốn lớn.', 'Nợ vay lớn, chủ yếu từ tiền gửi khách hàng và phát hành giấy tờ có giá. Tỷ lệ nợ trên vốn chủ sở hữu cao (khoảng 16.6 lần), đặc thù của ngành ngân hàng. Ngân hàng đa dạng hóa nguồn vốn và quản lý thanh khoản chặt chẽ theo quy định. Áp lực trả nợ ngắn hạn đáng kể do cơ cấu nợ chủ yếu ngắn hạn.', 'Ngân hàng không có hàng tồn kho vật chất. Dự án xây dựng dở dang (chi phí xây dựng cơ bản dở dang) có giá trị lớn, tập trung vào xây dựng trụ sở và chi nhánh. Rủi ro chậm tiến độ hoặc chi phí vượt dự toán có thể xảy ra nhưng không được đề cập cụ thể trong báo cáo.', 4, 'Ngân hàng có cấu trúc tài chính ổn định với tổng tài sản lớn, tăng trưởng mạnh về cho vay và huy động vốn. Ý kiến kiểm toán chấp nhận toàn phần và không có nghi ngờ về khả năng hoạt động liên tục. Tuy nhiên, nợ xấu có xu hướng tăng nhẹ, tỷ lệ nợ/VCSH cao đặc thù ngành ngân hàng. Công tác quản trị rủi ro được cải thiện theo chuẩn Basel II. Triển vọng kinh doanh phụ thuộc vào môi trường lãi suất và tăng trưởng kinh tế.'),
('CTG_2016_consolidated', 'CTG', 2016, 'consolidated', 'Các giao dịch với Ngân hàng Nhà nước và công ty liên doanh (Indovina, Vietinbank Aviva) có giá trị lớn nhưng chủ yếu là nghiệp vụ tiền gửi/cho vay thông thường. Không có dấu hiệu bất thường rõ ràng, nhưng cần giám sát quy mô giao dịch nội bộ.', 'Nợ vay chiếm tỷ trọng lớn với tổng nợ phải trả 888,300 tỷ VNĐ, trong đó tiền gửi khách hàng chiếm 655,060 tỷ. Tỷ lệ nợ/Vốn chủ sở hữu cao (~14.7 lần) đặc thù ngân hàng, nhưng ngân hàng có dự phòng rủi ro tín dụng 6,862 tỷ và trái phiếu VAMC. Áp lực thanh khoản ngắn hạn cần quản lý do cơ cấu nợ ngắn hạn lớn.', 'Hàng tồn kho không phải tài sản chính của ngân hàng. Tuy nhiên, chi phí xây dựng dở dang 5,258 tỷ VNĐ (chủ yếu là công trình xây dựng) tồn tại và cần theo dõi tiến độ dự án.', 6, 'Ngân hàng có mô hình kinh doanh lớn, tăng trưởng lợi nhuận 20% năm 2016. Tuy nhiên, áp lực nợ vay cao, cơ cấu nguồn vốn tập trung vào tiền gửi ngắn hạn, và sự cố liên quan đến vụ Huỳnh Thị Huyền Như tạo rủi ro pháp lý. Ban lãnh đạo cam kết không chịu tổn thất, nhưng cần theo dõi phán quyết cuối cùng. Hệ thống quản trị rủi ro đang được nâng cấp theo Basel II.'),
('CTG_2016_parent', 'CTG', 2016, 'parent', 'Các giao dịch với bên liên quan chủ yếu là tiền gửi và vay với Ngân hàng Nhà nước, các liên doanh (Indovina, Aviva). Giá trị giao dịch lớn nhưng là nghiệp vụ ngân hàng thông thường, không có dấu hiệu bất thường về chuyển giá hay chiếm dụng vốn.', 'Ngân hàng huy động vốn lớn từ tiền gửi khách hàng và phát hành giấy tờ có giá. Tỷ lệ nợ trên vốn chủ sở hữu cao (khoảng 15 lần) nhưng là đặc thù ngành ngân hàng. Áp lực thanh khoản được quản lý chặt chẽ theo quy định của NHNN.', 'Không có hàng tồn kho. Có chi phí xây dựng cơ bản dở dang 5,255,232 triệu VND (khoảng 0.56% tổng tài sản) liên quan đến đầu tư hạ tầng, rủi ro thấp.', 3, 'Ngân hàng có kết quả kinh doanh tăng trưởng tốt năm 2016 với lợi nhuận sau thuế tăng 17%. Chất lượng tín dụng được kiểm soát với tỷ lệ nợ xấu 1.02% và tỷ lệ bao phủ dự phòng hơn 100%. Hệ thống quản trị rủi ro theo chuẩn Basel II đang được triển khai. Triển vọng tích cực.'),
('CTG_2015_consolidated', 'CTG', 2015, 'consolidated', 'Ngân hàng có quan hệ giao dịch với Ngân hàng Nhà nước Việt Nam (NHNN) với vai trò vừa là cơ quan quản lý vừa là chủ nợ lớn (vay NHNN 13.227.115 triệu VND) và là nơi gửi dự trữ bắt buộc. Các giao dịch với công ty liên doanh (Ngân hàng TNHH Indovina và Công ty TNHH Bảo hiểm Nhân thọ VietinBank Aviva) chủ yếu phát sinh từ tiền gửi thanh khoản dư thừa, quy mô không lớn so với tổng tài sản. Tuy nhiên, cơ cấu sở hữu phức tạp với 7 công ty con và 2 liên doanh đòi hỏi giám sát chặt chẽ. Vụ án Huỳnh Thị Huyền Như liên quan đến cá nhân nguyên là nhân viên chi nhánh TP.HCM và Nhà Bè, tuy Tòa phúc thẩm tuyên Ngân hàng không có trách nhiệm bồi thường nhưng vẫn là rủi ro pháp lý tiềm ẩn.', 'Tổng nợ phải trả 723.373.341 triệu VND so với vốn chủ sở hữu 56.110.146 triệu VND, tỷ lệ đòn bẩy khoảng 12,9 lần - đặc trưng cho ngân hàng thương mại lớn. Tiền gửi khách hàng chiếm 68% tổng nợ phải trả với cơ cấu chủ yếu ngắn hạn (huy động lãi suất thả nổi), tạo áp lực quản lý rủi ro lãi suất. Vay NHNN tăng mạnh 180% trong năm (từ 4.731.118 lên 13.205.353 triệu VND) cho thấy ngân hàng tích cực sử dụng kênh tái cấp vốn. Phát hành giấy tờ có giá tăng gần 4 lần (từ 5.294.073 lên 20.860.497 triệu VND). Tỷ lệ nợ ngắn hạn cho vay trung dài hạn cần được giám sát theo quy định NHNN. Ngân hàng không phát sinh khoản vay mất khả năng thanh toán hay vi phạm hợp đồng trong năm 2015.', 'Do là ngân hàng thương mại, VietinBank không có hàng tồn kho theo nghĩa truyền thống. Chi phí xây dựng cơ bản dở dang trị giá 5.218.948 triệu VND trải đều trên 3 miền, chủ yếu phục vụ xây dựng văn phòng và chi nhánh mới, không có dấu hiệu đình trệ hay chậm tiến độ. Dự phòng rủi ro cho vay khách hàng đạt 4.549.711 triệu VND (0,85% dư nợ cho vay), trong đó nợ xấu phân loại nhóm 3-5 (Nợ dưới tiêu chuẩn, Nợ nghi ngờ, Nợ có khả năng mất vốn) chiếm 1,52% tổng dư nợ cho vay.', 6, 'VietinBank là ngân hàng thương mại cổ phần lớn thứ hai tại Việt Nam (theo vốn điều lệ 37.234 tỷ VND) với Nhà nước sở hữu 64,5% vốn. Năm 2015, tổng tài sản đạt 779.483 tỷ VND (tăng 17,9%), lợi nhuận trước thuế đạt 7.345 tỷ VND (tương đương năm trước). Dư nợ cho vay tăng trưởng mạnh 22,3%, thu nhập lãi thuần tăng 5,5%. Tuy nhiên, tỷ lệ nợ xấu nội bảng tăng lên 1,52% (từ 1,33% năm trước), tỷ lệ dự phòng cụ thể/Nợ xấu còn thấp cho thấy rủi ro tiềm ẩn. Hệ số an toàn vốn đạt 9,1% - gần mức tối thiểu theo quy định. Vụ án Huỳnh Thị Huyền Như vẫn là rủi ro pháp lý chưa được giải quyết dứt điểm dù Ngân hàng không phải chịu trách nhiệm tài chính theo phán quyết phúc thẩm. Ngân hàng đang trong quá trình sáp nhập PG Bank và triển khai Basel II, thể hiện nỗ lực cải thiện quản trị. Triển vọng trung hạn phụ thuộc vào khả năng xử lý nợ xấu, nâng cao hệ số an toàn vốn và hoàn tất sáp nhập PG Bank.'),
('CTG_2015_parent', 'CTG', 2015, 'parent', 'Các giao dịch với Ngân hàng Nhà nước và các công ty con/liên doanh là hoạt động kinh doanh thông thường. Không có dấu hiệu bất thường lớn, nhưng cần giám sát do quy mô giao dịch.', 'Nợ vay chủ yếu từ tiền gửi khách hàng và trái phiếu phát hành, với tỷ lệ nợ trên vốn chủ sở hữu cao. Áp lực trả nợ ngắn hạn lớn, nhưng được hỗ trợ bởi nguồn vốn ổn định từ tiền gửi.', 'Ngân hàng không có hàng tồn kho truyền thống, nên rủi ro này không áp dụng.', 4, 'Ngân hàng có tình hình tài chính ổn định với lợi nhuận tăng trưởng. Tuy nhiên, cần lưu ý rủi ro từ vụ kiện pháp lý và cơ cấu nợ ngắn hạn.'),
('BID_2025_consolidated', 'BID', 2025, 'consolidated', 'Giao dịch với bên liên quan chủ yếu là tiền gửi và vay với Ngân hàng Nhà nước, Bộ Tài chính, Kho bạc Nhà nước và các công ty con/liên doanh/liên kết. Các giao dịch này mang tính chất nghiệp vụ ngân hàng thông thường, không có dấu hiệu bất thường hay chiếm dụng vốn. Tuy nhiên, quy mô giao dịch lớn với tổ chức nhà nước cho thấy sự phụ thuộc vào chính sách tiền tệ.', 'Nợ vay tập trung vào tiền gửi khách hàng (chiếm phần lớn) và phát hành giấy tờ có giá. Cơ cấu nợ chủ yếu là ngắn hạn, áp lực thanh toán lớn nhưng được bù đắp bởi tài sản có tính thanh khoản cao. Tỷ lệ nợ/Vốn chủ sở hữu ở mức cao (khoảng 18.2 lần) đặc trưng cho ngành ngân hàng. Lãi suất vay không được công bố chi tiết nhưng ngân hàng duy trì chính sách quản lý rủi ro lãi suất chặt chẽ.', 'Không có hàng tồn kho vật lý. Chi phí xây dựng dở dang chiếm tỷ trọng nhỏ trong tổng tài sản, tập trung vào đầu tư hạ tầng. Các khoản đầu tư vào công ty liên doanh/liên kết có giá trị đáng kể nhưng được quản lý theo phương pháp vốn chủ sở hữu, rủi ro được kiểm soát.', 3, 'BIDV là ngân hàng thương mại lớn với tổng tài sản hơn 3.3 triệu tỷ VND, có sự hậu thuẫn mạnh mẽ từ Nhà nước (chiếm 79.56% vốn điều lệ). Kết quả kinh doanh tăng trưởng tốt (LNST tăng 18.51%) nhờ thu nhập lãi thuần tăng và hoạt động thu nợ xấu hiệu quả. Cơ cấu tài sản lành mạnh, thanh khoản đảm bảo. Quản trị rủi ro tuân thủ Basel II. Triển vọng tích cực nhờ vị thế thị trường và tiềm năng tăng trưởng.'),
('BID_2025_parent', 'BID', 2025, 'parent', 'Các giao dịch với bên liên quan chủ yếu là tiền gửi và vay với quy mô lớn, nằm trong hoạt động bình thường của ngân hàng. Không phát hiện giao dịch bất thường đáng kể.', 'Tổng nợ phải trả lớn, tỷ lệ đòn bẩy cao đặc thù ngành ngân hàng. Nợ ngắn hạn chiếm tỷ trọng lớn, tập trung vào tiền gửi không kỳ hạn và có kỳ hạn ngắn. Lãi suất vay biến động theo thị trường. Ngân hàng duy trì dự phòng rủi ro tín dụng đầy đủ.', 'Ngân hàng không có hàng tồn kho theo nghĩa thông thường. Chi phí xây dựng dở dang với giá trị nhỏ, rủi ro thấp.', 3, 'Ngân hàng có tình hình tài chính ổn định, tăng trưởng lợi nhuận cao. Tuy nhiên, đòn bẩy tài chính cao đặc thù ngành. Ban lãnh đạo nhất quán, công tác quản trị rủi ro được thực hiện tốt.'),
('BID_2024_consolidated', 'BID', 2024, 'consolidated', 'Các giao dịch với bên liên quan chủ yếu là giao dịch tiền gửi và vay vốn với đại diện chủ sở hữu (NHNN), Bộ Tài chính, Kho bạc Nhà nước, cổ đông chiến lược và các công ty liên doanh/liên kết. Quy mô giao dịch lớn nhưng thuộc hoạt động kinh doanh thông thường của ngân hàng, chưa thấy dấu hiệu bất thường hay chuyển giá. Rủi ro liên quan ở mức thấp do tính minh bạch và đối tác là các tổ chức nhà nước, chiến lược.', 'Nợ vay chủ yếu đến từ tiền gửi khách hàng (chiếm phần lớn) và phát hành giấy tờ có giá. Tỷ lệ nợ trên vốn chủ sở hữu cao (khoảng 18 lần) đặc trưng cho mô hình kinh doanh ngân hàng. Áp lực thanh toán ngắn hạn lớn do phần lớn tiền gửi không kỳ hạn và có kỳ hạn ngắn. Ngân hàng có cơ cấu vốn đa dạng, phụ thuộc vào huy động từ dân cư và tổ chức tín dụng.', 'Ngân hàng không có hàng tồn kho vật lý. Các tài sản rủi ro chính là danh mục cho vay khách hàng và chứng khoán đầu tư. Tỷ lệ nợ xấu (nhóm 3-5) trên tổng dư nợ cho vay là 1.41%, ở mức chấp nhận được. Dự phòng rủi ro cho vay bao phủ nợ xấu 131%, cho thấy khả năng hấp thụ tổn thất. Rủi ro tín dụng là trọng yếu và được quản lý chặt chẽ.', 2, 'BIDV là ngân hàng thương mại nhà nước lớn với mạng lưới rộng, cơ cấu cổ đông rõ ràng (Nhà nước sở hữu 80.99%). Tình hình tài chính ổn định với tăng trưởng lợi nhuận sau thuế hợp nhất 16.5% năm 2024. Tỷ lệ nợ xấu được kiểm soát tốt, dự phòng đầy đủ. Ban lãnh đạo nhất quán và công tác quản trị rủi ro tuân thủ quy định. Ngân hàng có triển vọng phát triển bền vững gắn liền với sự phát triển kinh tế quốc gia.'),
('BID_2024_parent', 'BID', 2024, 'parent', 'Giao dịch với bên liên quan chủ yếu là tiền gửi và vay vốn với quy mô lớn, phản ánh vai trò ngân hàng quốc doanh chủ đạo. Các giao dịch với công ty con, liên doanh và liên kết là cần thiết cho hoạt động kinh doanh ngân hàng và tài chính đa ngành. Không phát hiện dấu hiệu chuyển giá hay rút vốn bất thường, tuy nhiên quy mô lớn đòi hỏi giám sát chặt chẽ.', 'Ngân hàng có cấu trúc nợ tập trung vào tiền gửi khách hàng và phát hành giấy tờ có giá. Tỷ lệ nợ trên vốn chủ sở hữu (~18.88 lần) là đặc trưng của mô hình ngân hàng thương mại. Lãi suất vay không được công bố chi tiết trong báo cáo riêng. Áp lực trả nợ ngắn hạn cao do bản chất kinh doanh, nhưng được hỗ trợ bởi cơ sở tiền gửi ổn định và vai trò là ngân hàng hệ thống.', 'Không có hàng tồn kho vật chất. Rủi ro tập trung vào các khoản đầu tư dài hạn vào công ty con, liên doanh và liên kết, cũng như bất động sản nhận nợ. Dự phòng giảm giá đầu tư đã được trích lập hợp lý (201.6 tỷ VNĐ). Dự án xây dựng dở dang có quy mô nhỏ và đang trong quá trình hoàn thiện.', 4, 'BIDV là ngân hàng thương mại lớn với mạng lưới rộng, chịu sự giám sát chặt chẽ của NHNN. Tăng trưởng lợi nhuận sau thuế riêng lẻ 14.66% năm 2024 cho thấy hiệu quả hoạt động cải thiện. Chất lượng tín dụng được kiểm soát với tỷ lệ nợ xấu khoảng 1.37%, thấp hơn mức trung bình ngành. Cơ cấu vốn chủ sở hữu mạnh với vốn Nhà nước chi phối. Triển vọng ổn định nhờ vị thế dẫn đầu và sự hỗ trợ từ Chính phủ.'),
('BID_2023_consolidated', 'BID', 2023, 'consolidated', 'Giao dịch với các bên liên quan chủ yếu mang tính chất nghiệp vụ ngân hàng thông thường với các cơ quan Nhà nước (NHNN, Bộ Tài chính, Kho bạc Nhà nước), cổ đông chiến lược KEB Hana và các công ty liên doanh/liên kết. Tiền gửi của Bộ Tài chính và Kho bạc Nhà nước tại BIDV giảm mạnh 115.663 triệu do luân chuyển nguồn vốn ngân sách. Tiền gửi của các công ty liên doanh giảm 915 triệu và tiền gửi của công ty liên kết giảm 141 triệu, phản ánh hoạt động kinh doanh bình thường. Không phát hiện giao dịch bất thường, cho vay không lãi suất hay chuyển giá có dấu hiệu tuồn vốn ra sân sau. Tuy nhiên, mức độ tập trung giao dịch với các chủ thể Nhà nước là lớn do BIDV là ngân hàng thương mại Nhà nước.', 'Tổng nợ phải trả đạt 2.178.002 tỷ VNĐ, tỷ lệ nợ/VCSH ở mức 17,7 lần - đặc trưng của hoạt động ngân hàng thương mại lớn. Cơ cấu nợ chủ yếu dựa vào tiền gửi khách hàng (78% tổng nợ, tăng 15,7% YoY lên 1.704.690 tỷ), phản ánh nền huy động vững chắc từ thị trường bán lẻ. Phát hành giấy tờ có giá tăng 20,6% lên 189.487 tỷ, trong đó chứng chỉ tiền gửi tăng mạnh 36,8% cho thấy ngân hàng đẩy mạnh huy động trung-dài hạn. Nợ Chính phủ và NHNN giảm mạnh 76,5% do đáo hạn tiền gửi Kho bạc có kỳ hạn lớn (từ 139.586 tỷ xuống 17.981 tỷ). Tài sản thế chấp lớn (2.845.342 tỷ) chủ yếu là bất động sản (72%), cung cấp bộ đệm an toàn cho hoạt động tín dụng.', 'BIDV là ngân hàng thương mại nên không có rủi ro hàng tồn kho theo nghĩa truyền thống. Tuy nhiên, chi phí xây dựng cơ bản dở dang (2.078.021 triệu) phản ánh đầu tư nâng cấp hệ thống mạng lưới 189 chi nhánh và 895 phòng giao dịch. Các dự án xây dựng phân bổ đều theo vùng miền (Bắc, Trung, Nam, nước ngoài), tiến độ triển khai ổn định, không có dấu hiệu đình trệ hay tích tụ vốn kéo dài. Dự phòng giảm giá đầu tư dài hạn ở mức 114.097 triệu giảm nhẹ so với đầu năm, cho thấy danh mục đầu tư dài hạn cơ bản lành mạnh.', 3, 'BIDV là ngân hàng thương mại Nhà nước lớn nhất Việt Nam với tổng tài sản 2,3 triệu tỷ VNĐ, mạng lưới rộng khắp 63 tỉnh thành và hiện diện tại Campuchia, Lào, Myanmar. Kết quả kinh doanh năm 2023 tăng trưởng mạnh: LNST hợp nhất tăng 19,78% đạt 21.977 tỷ VNĐ, chủ yếu nhờ thu nhập lãi thuần ổn định (56.136 tỷ), thu nhập dịch vụ tăng 16,3%, thu nhập ngoại hối tăng 50% và giảm chi phí dự phòng tín dụng (-14,7%). Tỷ lệ nợ xấu giảm xuống 1,26% với tỷ lệ dự phòng bao phủ nợ xấu đạt 181% - mức an toàn cao. Ý kiến kiểm toán chấp nhận toàn phần từ Deloitte Việt Nam. CASA ở mức 19,6% - còn dư địa cải thiện để giảm chi phí vốn. Ban lãnh đạo ổn định với Tổng Giám đốc Lê Ngọc Lâm, thù lao minh bạch và cơ chế quản trị rủi ro ba tuyến phòng vệ được thiết lập bài bản theo Basel. Triển vọng đầu tư tích cực nhờ quy mô lớn, chất lượng tín dụng cải thiện, thu nhập ngoài lãi tăng trưởng mạnh và vị thế dẫn đầu thị trường.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('BID_2023_parent', 'BID', 2023, 'parent', 'Giao dịch với các bên liên quan chủ yếu là hoạt động tiền gửi, vay mượn và đầu tư giữa BIDV và các công ty con, liên doanh, liên kết, cũng như với đại diện chủ sở hữu Nhà nước. Các giao dịch này là nghiệp vụ ngân hàng thông thường, tuy nhiên quy mô lớn và tập trung vào nguồn vốn Nhà nước cho thấy mức độ phụ thuộc nhất định.', 'Nợ vay của BIDV tập trung vào tiền gửi khách hàng (chiếm tỷ trọng lớn), phát hành giấy tờ có giá và vay từ NHNN. Cơ cấu nợ ngắn hạn cao tạo áp lực thanh khoản. Lãi suất chi tiết không được công bố. Dự phòng rủi ro tín dụng được trích lập đầy đủ theo quy định.', 'Ngân hàng không có hàng tồn kho vật chất. Chỉ có chi phí xây dựng cơ bản dở dang (dự án xây dựng) với giá trị tăng so với đầu năm, phản ánh hoạt động đầu tư vào cơ sở vật chất. Không có thông tin về tiến độ dự án hay trích lập dự phòng.', 4, 'BIDV là ngân hàng thương mại nhà nước lớn với mạng lưới rộng, tăng trưởng lợi nhuận tốt (18,82% năm 2023). Tỷ lệ nợ xấu được kiểm soát ở mức 1,15%, dự phòng bao phủ nợ xấu đạt 197%. Cơ cấu tài sản nợ ổn định nhưng phụ thuộc vào nguồn vốn ngắn hạn. Ban lãnh đạo có nhiều biến động nhân sự. Triển vọng trung hạn tích cực nhờ vị thế thị trường và sự hỗ trợ từ Nhà nước.'),
('BID_2022_consolidated', 'BID', 2022, 'consolidated', 'BIDV là ngân hàng thương mại Nhà nước với đại diện chủ sở hữu là NHNN. Các giao dịch với bên liên quan chủ yếu là hoạt động huy động vốn và thanh toán truyền thống giữa ngân hàng thương mại Nhà nước và các cơ quan quản lý (tiền gửi Kho bạc Nhà nước tăng mạnh từ 11.787 tỷ lên 141.012 tỷ VNĐ do huy động tiền gửi có kỳ hạn của Kho bạc Nhà nước). Tiền gửi của cổ đông chiến lược KEB Hana và các công ty liên doanh (VRB, BIDV Tower, BIDV Metlife) chiếm tỷ trọng nhỏ trong tổng nguồn vốn. Các giao dịch này phản ánh cơ chế hoạt động bình thường của ngân hàng Nhà nước, chưa phát hiện dấu hiệu bất thường hay chuyển giá.', 'Tổng nợ phải trả đạt 2.016.419 tỷ VNĐ, trong đó tiền gửi của khách hàng chiếm 73,1% (1.473.598 tỷ) - nguồn vốn cốt lõi ổn định. Phát hành giấy tờ có giá đạt 157.052 tỷ VNĐ, bao gồm 45.092 tỷ trái phiếu tăng vốn BIDV và 101.023 tỷ chứng chỉ tiền gửi. Nợ vay từ Chính phủ và NHNN tăng mạnh từ 25.340 tỷ lên 152.753 tỷ chủ yếu do Kho bạc Nhà nước gửi tiền có kỳ hạn lớn. Tỷ lệ nợ/vốn chủ sở hữu là 19,4 lần - mức cao đặc thù cho ngành ngân hàng. Áp lực trả nợ ngắn hạn tập trung vào tiền gửi không kỳ hạn của khách hàng (270.547 tỷ) và tiền gửi không kỳ hạn của TCTD khác (77.546 tỷ).', 'Là ngân hàng thương mại, BIDV không có hàng tồn kho truyền thống. Chi phí xây dựng cơ bản dở dang chiếm tỷ trọng rất nhỏ (1.937 tỷ VNĐ, tương đương 0,09% tổng tài sản), chủ yếu là chi phí sửa chữa, cải tạo trụ sở và chi nhánh. Dự án bất động sản đáng chú ý là Công ty Liên doanh Tháp BIDV (giá trị ghi sổ 266 tỷ). Cho vay bất động sản là tài sản thế chấp lớn nhất (1.777.464 tỷ VNĐ tài sản thế chấp bất động sản) phản ánh rủi ro tập trung vào lĩnh vực bất động sản trong danh mục cho vay.', 3, 'BIDV là một trong bốn ngân hàng thương mại Nhà nước lớn nhất Việt Nam với mạng lưới 189 chi nhánh và 895 phòng giao dịch. Năm 2022, lợi nhuận sau thuế hợp nhất đạt 18.420 tỷ VNĐ, tăng 69,9% so với năm 2021, nhờ thu nhập lãi thuần tăng 19,7%, chi phí dự phòng rủi ro tín dụng giảm 18,5%. Tổng tài sản đạt 2,12 triệu tỷ VNĐ, tăng 20,4%. Vốn chủ sở hữu đạt 104.190 tỷ VNĐ. Tỷ lệ nợ xấu (nhóm 3-5) ở mức 1,16% - mức chấp nhận được. Kiểm toán viên Deloitte Việt Nam đưa ra ý kiến chấp nhận toàn phần (unqualified), không có vấn đề về hoạt động liên tục. Cơ cấu cổ đông rõ ràng với Nhà nước sở hữu 81%, cổ đông chiến lược KEB Hana 15%. Công tác quản trị rủi ro được triển khai bài bản theo Basel II. Triển vọng đầu tư trung-dài hạn tích cực nhờ vị thế thị trường vững chắc và đà tăng trưởng lợi nhuận mạnh.'),
('BID_2021_consolidated', 'BID', 2021, 'consolidated', 'Các giao dịch với bên liên quan chủ yếu là với các cơ quan quản lý Nhà nước (NHNN, Bộ Tài chính), công ty con và liên doanh, phục vụ cho hoạt động kinh doanh chính của ngân hàng (huy động, cho vay, thanh toán). Giá trị giao dịch lớn nhưng nằm trong khuôn khổ pháp lý và phục vụ mục đích vận hành. Rủi ro xung đột lợi ích được kiểm soát thông qua chính sách nội bộ và giám sát của Ban Kiểm soát.', 'Nợ vay đa dạng từ nhiều nguồn (NHNN, phát hành giấy tờ có giá, tiền gửi khách hàng). Tỷ lệ nợ/VCSH khoảng 19.4 lần (1,675,366,766 / 86,329,026), phản ánh đặc thù kinh doanh ngân hàng. Áp lực lãi vay được quản lý qua chiến lược cân đối kỳ hạn và lãi suất. Tuy nhiên, biến động lãi suất thị trường vẫn là rủi ro chính.', 'Không có hàng tồn kho truyền thống. Chi phí xây dựng dở dang là đầu tư tài sản cố định cho mạng lưới, tiến độ thực hiện theo kế hoạch, không có dấu hiệu đọng vốn hay chậm tiến độ lớn.', 4, 'BIDV là ngân hàng thương mại Nhà nước lớn, có vị thế thống trị trên thị trường. Báo cáo tài chính năm 2021 cho thấy hoạt động kinh doanh tăng trưởng mạnh (lợi nhuận sau thuế hợp nhất tăng 50%), chất lượng tài sản cải thiện (tỷ lệ nợ xấu giảm). Ban Điều hành và Kiểm soát có thay đổi nhân sự nhưng vẫn đảm bảo tính liên tục. Ý kiến kiểm toán là chấp nhận toàn phần, không có vấn đề về khả năng hoạt động liên tục. Rủi ro quản trị ở mức thấp đến trung bình do quy mô lớn và vai trò chủ đạo của Nhà nước.'),
('BID_2022_parent', 'BID', 2022, 'parent', 'BIDV có mạng lưới giao dịch bên liên quan rộng lớn với đại diện chủ sở hữu (NHNN), Bộ Tài chính, Kho bạc Nhà nước và cổ đông chiến lược KEB Hana. Tiền gửi của KBNN tại BIDV tăng mạnh từ 10.000 tỷ lên 139.586 tỷ đồng, tiền gửi của BTC và KBNN tại BIDV đạt 145.504 tỷ đồng. Các công ty con, liên doanh, liên kết có hoạt động gửi tiền và vay qua lại lớn (tiền gửi của công ty con tại BIDV: 4.794 tỷ, tiền BIDV gửi tại công ty con: 6.986 tỷ, tiền vay từ BIDV của công ty con: 765 tỷ). Các giao dịch này mang tính chất nội bộ hệ sinh thái ngân hàng - tài chính, chưa phát hiện dấu hiệu bất thường về chuyển giá hay rút vốn.', 'Tổng nợ phải trả đạt 1.983.399 tỷ đồng. Nợ vay chủ yếu từ tiền gửi khách hàng (1.456.810 tỷ, chiếm 73,5%), phát hành giấy tờ có giá (157.182 tỷ, trong đó trái phiếu tăng vốn BIDV 45.108 tỷ) và nợ Chính phủ/NHNN (151.710 tỷ). Dư nợ cho vay ngắn hạn chiếm 65,6% tổng dư nợ cho vay. Chi phí lãi và thu nhập lãi cho thấy NIM khoảng 2,86% với tổng thu nhập lãi 118.621 tỷ và chi phí lãi 64.064 tỷ. Tỷ lệ nợ xấu toàn hệ thống ở mức 1,12% (Nợ dưới tiêu chuẩn + Nghi ngờ + Có khả năng mất vốn = 16.681 tỷ / 1.488.151 tỷ). Dự phòng cụ thể cho vay khách hàng đạt 26.159 tỷ, tỷ lệ bao phủ nợ xấu khoảng 156,8%. Áp lực thanh toán nợ ngắn hạn đáng kể nhưng được hỗ trợ bởi mạng lưới huy động rộng lớn.', 'Doanh nghiệp là ngân hàng thương mại, không có hoạt động sản xuất kinh doanh hàng hóa vật lý truyền thống. Chi phí xây dựng cơ bản dở dang đạt 1.852 tỷ (tăng từ 1.801 tỷ năm trước) bao gồm các công trình văn phòng, chi nhánh tại ba miền Bắc - Trung - Nam. Quy mô XDCB dở dang chiếm tỷ trọng rất nhỏ trong tổng tài sản (0,09%), rủi ro đọng vốn thấp. BIDV cũng có tài sản gán nợ chờ xử lý trị giá 55 tỷ đồng (bất động sản).', 4, 'BIDV là ngân hàng thương mại nhà nước lớn nhất Việt Nam với tổng tài sản hơn 2,08 triệu tỷ đồng và mạng lưới trải rộng 63 tỉnh thành. Năm 2022, lợi nhuận sau thuế đạt 18.064 tỷ đồng, tăng 79,3% so với năm trước nhờ thu nhập tín dụng tăng và chi phí dự phòng giảm. Chất lượng tín dụng được cải thiện với tỷ lệ nợ xấu 1,12%. Tuy nhiên, quy mô giao dịch với bên liên quan (chính phủ, KBNN) rất lớn, tỷ lệ tiền gửi không kỳ hạn (CASA) chỉ 18,3% cho thấy chi phí huy động còn áp lực. Kiểm toán Deloitte đưa ra ý kiến chấp nhận toàn phần, không có vấn đề về hoạt động liên tục. Ban lãnh đạo ổn định với cơ cấu cổ đông Nhà nước 81%, cổ đông chiến lược KEB Hana 15%. Triển vọng trung hạn tích cực nhờ vị thế thị trường vững chắc và chất lượng tài sản cải thiện.'),
('BID_2020_parent', 'BID', 2020, 'parent', 'Giao dịch với các bên liên quan bao gồm đại diện chủ sở hữu (NHNN), Bộ Tài chính, Kho bạc Nhà nước, cổ đông chiến lược KEB Hana, và 11 công ty con, 3 công ty liên doanh, 1 công ty liên kết. Các giao dịch chủ yếu là tiền gửi, cho vay và phải thu/phải trả thuộc hoạt động kinh doanh ngân hàng thông thường. Không phát hiện dấu hiệu chuyển giá, cho vay không lãi suất hoặc chiếm dụng vốn bất thường. Tuy nhiên, quy mô giao dịch lớn với số lượng bên liên quan đa dạng đòi hỏi giám sát chặt chẽ.', 'Nợ vay của ngân hàng chủ yếu từ tiền gửi khách hàng (hơn 1,200 nghìn tỷ đồng) và phát hành giấy tờ có giá (63 nghìn tỷ đồng). Nợ ngắn hạn chiếm tỷ trọng lớn, tạo áp lực thanh khoản. Tỷ lệ nợ/VCSH khoảng 18.9 lần, đặc thù của ngành ngân hàng. Lãi suất chi tiết không được thuyết minh cụ thể cho từng khoản nợ, nhưng ngân hàng có tài sản thế chấp lớn (bất động sản trị giá hơn 1,247 nghìn tỷ đồng) để đảm bảo cho vay.', 'Là ngân hàng thương mại, không có hàng tồn kho truyền thống. Tuy nhiên, có chi phí xây dựng cơ bản dở dang trị giá khoảng 585 tỷ VNĐ (211+86+288) tại các khu vực. Rủi ro đọng vốn thấp vì đây là dự án xây dựng cơ sở hạ tầng phục vụ hoạt động ngân hàng, không phải bất động sản kinh doanh.', 3, 'BIDV là ngân hàng thương mại nhà nước lớn với mạng lưới rộng, vốn điều lệ 40,220 tỷ đồng. Kiểm toán viên Deloitte đưa ra ý kiến chấp nhận toàn phần, không có vấn đề về hoạt động liên tục. Tuy nhiên, lợi nhuận sau thuế giảm 19.3% từ 8,290 tỷ xuống 6,690 tỷ đồng, chủ yếu do chi phí dự phòng rủi ro tín dụng tăng 16%. Ngân hàng có cấu trúc quản trị rõ ràng với cổ đông Nhà nước chiếm 81%. Tỷ lệ nợ xấu (nhóm 3-5) tăng từ 1.66% lên 1.67%, vẫn trong kiểm soát. Dòng tiền hoạt động kinh doanh âm 68,916 tỷ do tăng trưởng cho vay mạnh. Triển vọng trung hạn phụ thuộc vào kiểm soát nợ xấu và kinh tế vĩ mô.'),
('BID_2020_consolidated', 'BID', 2020, 'consolidated', 'Các giao dịch với bên liên quan chủ yếu là với các cơ quan nhà nước và công ty liên doanh, liên kết. Giá trị lớn nhưng thuộc hoạt động bình thường của ngân hàng thương mại nhà nước. Chưa thấy dấu hiệu bất thường như cho vay không lãi suất hay chuyển giá.', 'Nợ vay tập trung từ tiền gửi khách hàng và phát hành giấy tờ có giá. Áp lực thanh khoản ngắn hạn tồn tại nhưng ngân hàng quản lý tốt với tài sản thanh khoản cao. Lãi suất và đáo hạn được quản lý theo quy định, tài sản thế chấp đa dạng.', 'Chi phí xây dựng dở dang có giá trị nhỏ so với tổng tài sản, không phải hoạt động kinh doanh chính của ngân hàng. Rủi ro đọng vốn thấp.', 3, 'Ngân hàng BIDV là ngân hàng thương mại nhà nước lớn tại Việt Nam với mạng lưới rộng lớn. Tình hình tài chính ổn định, ý kiến kiểm toán chấp nhận toàn phần. Dịch Covid-19 ảnh hưởng nhưng ngân hàng duy trì được hoạt động liên tục. Triển vọng trung hạn phụ thuộc vào phục hồi kinh tế và quản trị rủi ro.'),
('BID_2019_consolidated', 'BID', 2019, 'consolidated', 'BIDV có mối quan hệ phức tạp với nhiều bên liên quan do là ngân hàng quốc doanh lớn. Giao dịch chủ yếu với Cơ quan quản lý Nhà nước (NHNN, Bộ Tài chính, Kho bạc Nhà nước) là hoạt động kinh doanh bình thường của ngân hàng thương mại Nhà nước - tiền gửi của Kho bạc Nhà nước đạt 87.865 tỷ VND, tiền gửi của Bộ Tài chính đạt 10.158 tỷ VND. Giao dịch với cổ đông chiến lược KEB Hana Bank (15% vốn) chủ yếu qua khoản đầu tư 20.295 tỷ VND phát hành cổ phiếu riêng lẻ. Các công ty liên doanh (VRB, BIDV Tower, BIDV Metlife) và liên kết (VALC, Cavifood) có tiền gửi và vay qua lại với BIDV nhưng quy mô không lớn so với tổng tài sản. Báo cáo không cung cấp chi tiết lãi suất hay tài sản đảm bảo cho từng giao dịch cụ thể, tuy nhiên không phát hiện dấu hiệu bất thường.', 'Tổng nợ phải trả đạt 1.412.304 tỷ VND, tỷ lệ nợ/VCSH là 18,19 lần - mức cao đặc thù ngân hàng thương mại. Cơ cấu nợ chủ yếu từ tiền gửi khách hàng (1.114.162 tỷ VND, chiếm 78,9% tổng nợ), trong đó tiền gửi có kỳ hạn chiếm tỷ trọng lớn (923.233 tỷ VND). Phát hành giấy tờ có giá đạt 62.772 tỷ VND bao gồm trái phiếu tăng vốn BIDV 33.064 tỷ VND. Vay từ NHNN 9.761 tỷ VND và tiền gửi Bộ Tài chính/Kho bạc 101.588 tỷ VND phản ánh vị thế quan trọng của BIDV trong hệ thống ngân hàng quốc doanh. Nợ vay từ TCTD khác bằng ngoại tệ khá lớn (46.750 tỷ VND) tạo rủi ro tỷ giá. Áp lực thanh toán ngắn hạn đáng kể với tiền gửi không kỳ hạn đạt 178.383 tỷ VND. Tuy nhiên, BIDV có hệ thống quản trị rủi ro thanh khoản tốt với tỷ lệ dự trữ bắt buộc và tài sản thanh khoản cao.', 'Chi phí xây dựng cơ bản dở dang đạt 2.557.665 triệu VND (2,56 tỷ VND), giảm so với đầu năm (2.955.414 triệu VND) cho thấy tiến độ triển khai các công trình. Các công trình được phân bổ theo 4 khu vực: miền Bắc (355.698 triệu), miền Trung (39.687 triệu), miền Nam (503.421 triệu), nước ngoài (385.999 triệu). Ngân hàng có 189 chi nhánh và 871 phòng giao dịch trên toàn quốc, chi phí xây dựng dở dang chủ yếu cho việc mở rộng/mới mạng lưới. Tài sản gán nợ chờ xử lý 464.449 triệu VND (chủ yếu bất động sản) không thay đổi so với đầu năm cho thấy việc xử lý tài sản thế chấp thu hồi nợ còn chậm. Tuy nhiên, tổng giá trị này không đáng kể so với quy mô tài sản 1,49 triệu tỷ VND của ngân hàng.', 4, 'BIDV là ngân hàng thương mại lớn nhất Việt Nam về tổng tài sản (1,49 triệu tỷ VND), thuộc sở hữu Nhà nước (80,99%) với sự tham gia của KEB Hana Bank (15%) là cổ đông chiến lược nước ngoài. Năm 2019, ngân hàng đạt kết quả kinh doanh tích cực: lợi nhuận sau thuế đạt 8.547 tỷ VND (tăng 14% so với năm trước), tăng trưởng tín dụng 14% (từ 976.334 tỷ lên 1.102.365 tỷ VND), thu nhập lãi thuần đạt 35.977 tỷ VND. Nợ xấu toàn hệ thống ở mức 1,75% (từ 1,91% năm trước), trong đó nợ có khả năng mất vốn chiếm 1,02% tăng đáng lo ngại từ 0,73%. Dự phòng rủi ro tín dụng đạt 14.632 tỷ VND với tỷ lệ bao phủ nợ xấu 75,05%. Ngân hàng đã huy động thành công 20.295 tỷ VND từ KEB Hana Bank qua phát hành cổ phiếu riêng lẻ, tăng cường năng lực vốn. Hệ thống quản trị rủi ro được xây dựng theo Basel II, có mô hình 3 tuyến bảo vệ. Tuy nhiên, cần theo dõi sát xu hướng nợ xấu tăng, đặc biệt nợ có khả năng mất vốn, và áp lực thanh khoản từ tiền gửi không kỳ hạn lớn. Triển vọng đầu tư trung hạn khả quan nhờ vị thế dẫn đầu và sự hỗ trợ từ Nhà nước.'),
('BID_2018_consolidated', 'BID', 2018, 'consolidated', 'Giao dịch với các bên liên quan chủ yếu là với cơ quan quản lý nhà nước, công ty liên doanh và công ty liên kết, thuộc hoạt động kinh doanh thông thường của ngân hàng. Các giao dịch này có giá trị lớn nhưng được thực hiện trong khuôn khổ quy định, chưa thấy dấu hiệu bất thường hay rút vốn.', 'Nợ vay của ngân hàng chủ yếu từ khách hàng và các tổ chức tín dụng, với tỷ lệ nợ/VCSH khoảng 23 lần, phản ánh đặc thù kinh doanh ngân hàng. Áp lực thanh khoản ngắn hạn cao nhưng được quản lý thông qua hệ thống hạn mức và tài sản thanh khoản. Lãi suất vay đa dạng, không có rủi ro tập trung.', 'Hàng tồn kho chủ yếu là chi phí xây dựng cơ bản dở dang, không có dự phòng giảm giá. Rủi ro đọng vốn thấp do tiến độ xây dựng được kiểm soát, nhưng cần theo dõi tình hình thực hiện dự án.', 3, 'BIDV là ngân hàng thương mại lớn, có mạng lưới rộng, kết quả kinh doanh tăng trưởng ổn định với lợi nhuận sau thuế đạt 7.541 tỷ đồng năm 2018. Cơ cấu tài sản lành mạnh, nợ xấu được kiểm soát ở mức 1.9%. Ban điều hành nhất quán, ý kiến kiểm toán chấp nhận toàn phần. Triển vọng trung hạn tích cực nhưng cần lưu ý rủi ro từ biến động tỷ giá và nợ xấu tiềm ẩn.'),
('BID_2018_parent', 'BID', 2018, 'parent', 'BIDV là ngân hàng thương mại có vốn Nhà nước chi phối (95,28%) nên giao dịch với cơ quan quản lý Nhà nước (NHNN, Bộ Tài chính, KBNN) có giá trị rất lớn, chiếm tỷ trọng cao trong cơ cấu nguồn vốn. Các khoản tiền gửi của Bộ Tài chính và KBNN tăng mạnh từ 63.693 tỷ lên 94.060 tỷ đồng trong năm 2018. Giao dịch với 13 công ty con và 3 công ty liên doanh là hoạt động nội bộ thông thường trong mô hình ngân hàng mẹ-con, quy mô nợ phải thu/phải trả với bên liên quan khoảng 19.000 tỷ đồng, trong bối cảnh tổng tài sản hơn 1,27 triệu tỷ đồng thì tỷ trọng không lớn. Ý kiến kiểm toán là chấp nhận toàn phần, không có giao dịch bất thường hay dấu hiệu rút ruột.', 'Tổng nợ phải trả 1.228.617 tỷ đồng trên vốn chủ sở hữu 49.668 tỷ đồng, tỷ lệ nợ/VCSH đạt 24,7 lần - đặc trưng của hoạt động ngân hàng thương mại. Cơ cấu huy động phụ thuộc lớn vào tiền gửi khách hàng (972.358 tỷ đồng, chiếm 79,1% tổng nợ). Phát hành giấy tờ có giá giảm mạnh từ 83.738 tỷ xuống 39.791 tỷ đồng do đáo hạn chứng chỉ tiền gửi, bù đắp bằng tăng tiền gửi KBNN có kỳ hạn (51.000 tỷ). Tỷ lệ nợ ngắn hạn chiếm ưu thế trong cho vay khách hàng (590.556 tỷ/955.456 tỷ). Nợ xấu (nhóm 3-5) đạt 17.201 tỷ đồng (1,80% dư nợ cho vay), ở mức kiểm soát được cho ngân hàng lớn.', 'Chi phí xây dựng cơ bản dở dang tổng cộng 2.606 tỷ đồng (giảm từ 2.734 tỷ năm trước) tập trung vào xây dựng/cải tạo trụ sở chi nhánh tại 3 khu vực. Đây là tài sản cố định hình thành trong tương lai, không phải hàng tồn kho kinh doanh, rủi ro đọng vốn thấp. Ngoài ra, có 524 tỷ đồng bất động sản gán nợ chờ xử lý, tăng nhẹ so với năm trước, phản ánh hoạt động thu hồi nợ.', 3, 'BIDV là ngân hàng thương mại Nhà nước lớn thứ 3 tại Việt Nam với tổng tài sản 1.278.285 tỷ đồng, mạng lưới rộng khắp 63 tỉnh thành (190 chi nhánh, 871 phòng giao dịch). Kết quả kinh doanh tăng trưởng tốt: lợi nhuận sau thuế 7.175 tỷ đồng (tăng 8,8%), thu nhập lãi thuần 33.396 tỷ đồng (tăng 12,7%). Tỷ lệ nợ xấu 1,80% ở mức kiểm soát được, tỷ lệ dự phòng/nợ xấu đạt 67,0%. NIM đạt 2,79%. CASA chỉ 16,21% - thấp hơn đáng kể so với một số ngân hàng tư nhân, cho thấy cơ cấu huy động chi phí cao. Ngân hàng đang triển khai Basel II, có hệ thống quản trị rủi ro theo mô hình 3 tuyến bảo vệ. Cấu trúc cổ đông rõ ràng với Nhà nước chi phối, ban lãnh đạo có sự thay đổi (Chủ tịch HĐQT mới bổ nhiệm tháng 11/2018). Triển vọng đầu tư trung hạn ổn định, phù hợp với nhà đầu tư tìm kiếm cổ phiếu ngân hàng có quy mô lớn và ổn định.'),
('BID_2017_consolidated', 'BID', 2017, 'consolidated', 'Các giao dịch với bên liên quan chủ yếu là giao dịch với các cơ quan quản lý Nhà nước (NHNN, Bộ Tài chính, Kho bạc Nhà nước) và các công ty liên doanh, liên kết, đây là hoạt động bình thường và đặc thù của ngân hàng thương mại nhà nước. Giá trị tiền gửi và vay qua lại lớn nhưng không có dấu hiệu bất thường hay rút vốn. Tuy nhiên, cần theo dõi quy mô lớn của các cam kết tín dụng với các đơn vị liên quan.', 'Ngân hàng có cấu trúc nợ đa dạng và lớn, bao gồm nợ Chính phủ và NHNN (77.535 tỷ), tiền gửi và vay từ TCTD khác (91.978 tỷ), tiền gửi khách hàng (859.985 tỷ), phát hành giấy tờ có giá (83.738 tỷ). Áp lực trả nợ tập trung vào nợ ngắn hạn với lãi suất biến động. Tuy nhiên, với vai trò là ngân hàng lớn có mạng lưới rộng, khả năng huy động vốn và quản lý thanh khoản được đánh giá là tốt. Tỷ lệ nợ/Vốn chủ sở hữu ở mức cao (~23.6 lần) là đặc thù ngành nhưng cần được giám sát.', 'Là ngân hàng, BIDV không có hàng tồn kho truyền thống. Rủi ro tập trung vào tài sản thế chấp là bất động sản (giá trị 720.647 tỷ) và các khoản phải thu xây dựng cơ bản dở dang (3.150 tỷ). Các dự án xây dựng dở dang tập trung tại các chi nhánh lớn, tiến độ được theo dõi và chưa có dấu hiệu đọng vốn lớn. Dự phòng rủi ro tín dụng được trích lập đầy đủ theo quy định.', 3, 'BIDV là ngân hàng thương mại nhà nước lớn, có mạng lưới hoạt động rộng khắp, tình hình tài chính ổn định với tổng tài sản hơn 1.202 nghìn tỷ đồng, lợi nhuận sau thuế tăng trưởng 12% so với năm trước. Ý kiến kiểm toán là chấp nhận toàn phần. Các chỉ tiêu an toàn vốn và thanh khoản được đảm bảo theo quy định. Tuy nhiên, nợ xấu và chi phí dự phòng rủi ro tín dụng vẫn ở mức đáng kể (tỷ lệ nợ xấu 1.62%). Triển vọng trung hạn ổn định nhờ vị thế thị trường và sự hỗ trợ từ nhà nước.');
PRAGMA foreign_keys = ON;
